INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('6f86fdbf-9213-56bf-b9b9-f64baacf4184', 'arabic', 'النواسخ: كان وأخواتها وإنّ وأخواتها', 'الأفعال الناسخة وتأثيرها في المبتدأ والخبر، والحروف الناسخة ومعانيها وإعرابها', '# ⚔️ النواسخ: كان وأخواتها وإنّ وأخواتها

> 💡 «النواسخ تنسخ حكم المبتدأ والخبر: تغيّر الحركات وتضيف المعاني — أتقنها تفتحْ أبواب الإعراب كلّها.»

## 🏰 مفهوم النسخ

النواسخ هي أفعال أو حروف **تدخل على الجملة الاسمية** فتغيّر إعراب المبتدأ والخبر:

- **كان وأخواتها** (أفعال ناسخة): ترفع المبتدأ فيُسمّى **اسمها**، وتنصب الخبر فيُسمّى **خبرها**.
- **إنّ وأخواتها** (حروف ناسخة): تنصب المبتدأ فيُسمّى **اسمها**، وترفع الخبر فيُسمّى **خبرها**.

> 🗡️ القاعدة الذهبية: كان ترفع اسمها وتنصب خبرها — إنّ تنصب اسمها وترفع خبرها. الفعل والحرف يعملان عكس بعضهما!

## ⚡ كان وأخواتها — التعريف والعمل

«كان» فعل ماضٍ ناسخ (وتتصرّف في المضارع والأمر):

| الفعل                                   | المعنى المضاف                                  |
| --------------------------------------- | ---------------------------------------------- |
| كانَ                                    | الدلالة على الزمن الماضي المطلق                |
| أصبحَ                                   | الدلالة على وقت الصباح أو التحوّل              |
| أمسى                                    | الدلالة على وقت المساء                         |
| أضحى                                    | الدلالة على وقت الضحى                          |
| ظلَّ                                    | الدلالة على الاستمرار نهارًا                   |
| باتَ                                    | الدلالة على الاستمرار ليلًا                    |
| صارَ                                    | الدلالة على التحوّل والانتقال                  |
| ليسَ                                    | نفي الخبر عن الاسم في الحاضر                   |
| ما زالَ / ما انفكَّ / ما فتئَ / ما برحَ | الدلالة على الاستمرار والدوام                  |
| ما دامَ                                 | الدلالة على الاستمرار مدّة بقاء الاسم على حاله |

> 🛡️ «ليس» فعل جامد لا يتصرّف — يأتي فقط على صيغة الماضي. وأفعال «ما زال وما انفكّ وما فتئ وما برح» لا تعمل إلا مسبوقةً بنفي أو نهي.

## 🛡️ أمثلة إعرابية على كان وأخواتها

**المثال الأوّل**: «كانَ الجوُّ صافيًا»

- **كانَ**: فعل ماضٍ ناسخ مبنيّ على الفتح.
- **الجوُّ**: اسم «كان» مرفوع وعلامة رفعه الضمّة.
- **صافيًا**: خبر «كان» منصوب وعلامة نصبه الفتحة.

**المثال الثاني**: «أصبحَ الطلابُ متحمّسينَ»

- **أصبحَ**: فعل ماضٍ ناسخ مبنيّ على الفتح.
- **الطلابُ**: اسم «أصبح» مرفوع وعلامة رفعه الضمّة.
- **متحمّسينَ**: خبر «أصبح» منصوب وعلامة نصبه الياء لأنّه جمع مذكّر سالم.

**المثال الثالث**: «ليسَ الكذبُ خُلُقًا كريمًا»

- **ليسَ**: فعل ماضٍ ناسخ جامد مبنيّ على الفتح.
- **الكذبُ**: اسم «ليس» مرفوع وعلامة رفعه الضمّة.
- **خُلُقًا**: خبر «ليس» منصوب وعلامة نصبه الفتحة.

## 🔮 إنّ وأخواتها — التعريف والعمل

هي حروف مشبّهة بالفعل، تدخل على الجملة الاسمية فتنصب المبتدأ وترفع الخبر:

| الحرف | المعنى                                       |
| ----- | -------------------------------------------- |
| إنَّ  | التوكيد (تأتي في ابتداء الكلام أو بعد القول) |
| أنَّ  | التوكيد (تقع في محلّ مصدر مؤوَّل)            |
| كأنَّ | التشبيه                                      |
| لكنَّ | الاستدراك                                    |
| ليتَ  | التمنّي                                      |
| لعلَّ | الترجّي والتوقّع                             |

> 🔮 الفرق بين «إنّ» و«أنّ»: «إنّ» تقع في ابتداء الكلام وبعد «قال»، و«أنّ» تقع بعد العلم والظنّ وسائر الأفعال التي تستلزم مصدرًا مؤوَّلًا.

## 🧮 أمثلة إعرابية على إنّ وأخواتها

**المثال الأوّل**: «إنَّ العلمَ نورٌ»

- **إنَّ**: حرف توكيد ونصب مبنيّ على الفتح.
- **العلمَ**: اسم «إنّ» منصوب وعلامة نصبه الفتحة.
- **نورٌ**: خبر «إنّ» مرفوع وعلامة رفعه الضمّة.

**المثال الثاني**: «كأنَّ البحرَ مرآةٌ»

- **كأنَّ**: حرف تشبيه ونصب مبنيّ على الفتح.
- **البحرَ**: اسم «كأنّ» منصوب وعلامة نصبه الفتحة.
- **مرآةٌ**: خبر «كأنّ» مرفوع وعلامة رفعه الضمّة.

**المثال الثالث**: «لعلَّ الفرجَ قريبٌ»

- **لعلَّ**: حرف ترجٍّ وتوقّع ونصب مبنيّ على الفتح.
- **الفرجَ**: اسم «لعلّ» منصوب وعلامة نصبه الفتحة.
- **قريبٌ**: خبر «لعلّ» مرفوع وعلامة رفعه الضمّة.

## 🧪 منهجيّة إعراب جملة النواسخ

1. **تعرَّف على الناسخ**: هل هو فعل (كان وأخواتها) أم حرف (إنّ وأخواتها)؟
2. **حدِّد الاسم**: إن كان فعلًا ناسخًا → الاسم **مرفوع**؛ وإن كان حرفًا ناسخًا → الاسم **منصوب**.
3. **حدِّد الخبر**: إن كان فعلًا ناسخًا → الخبر **منصوب**؛ وإن كان حرفًا ناسخًا → الخبر **مرفوع**.
4. **حدِّد العلامة الإعرابية** بحسب نوع الاسم (مفرد، مثنّى، جمع مذكّر سالم، ممنوع من الصرف...).

> 🏆 تلخيص سريع: فعل ناسخ = اسم مرفوع + خبر منصوب؛ حرف ناسخ = اسم منصوب + خبر مرفوع.

## ⚙️ تمييز الناسخ عن غيره

- «كان» قد تأتي زائدة (بين المبتدأ والخبر أو في صلة الموصول) فلا تعمل: «جاءَ الذي كانَ مجتهدًا» — هنا كان زائدة.
- «إنّ» المكسورة الهمزة توكيديّة في ابتداء الكلام. «أنّ» المفتوحة الهمزة تقع في محلّ مصدر مؤوَّل: «علمتُ أنَّ الحقَّ منتصرٌ» = علمتُ انتصارَ الحقِّ.
- «ليت» لا تُستخدم إلا في التمنّي غير الواقع أو ما يُشكّ في وقوعه: «ليتَ الشبابَ يعودُ يومًا».', '# 📜 ملخّص: النواسخ — كان وأخواتها وإنّ وأخواتها

- **النواسخ** تدخل على الجملة الاسمية فتغيّر إعراب المبتدأ والخبر.
- **كان وأخواتها** (أفعال ناسخة): **ترفع المبتدأ** (اسمها) و**تنصب الخبر** (خبرها).
- أخوات «كان»: أصبحَ، أمسى، أضحى، ظلَّ، باتَ، صارَ، ليسَ، ما زالَ، ما انفكَّ، ما فتئَ، ما برحَ، ما دامَ.
- «ليس» فعل جامد لا يتصرّف. «ما زال» وأخواتها لا تعمل إلا بعد نفي أو نهي.
- **إنّ وأخواتها** (حروف ناسخة): **تنصب المبتدأ** (اسمها) و**ترفع الخبر** (خبرها).
- أخوات «إنّ» وأغراضها: إنَّ وأنَّ (توكيد)، كأنَّ (تشبيه)، لكنَّ (استدراك)، ليتَ (تمنٍّ)، لعلَّ (ترجٍّ).
- **الفرق الجوهري**: فعل ناسخ → اسم مرفوع + خبر منصوب؛ حرف ناسخ → اسم منصوب + خبر مرفوع.
- **المنهجيّة**: حدِّد الناسخ نوعه ← ثم الاسم وحركته ← ثم الخبر وحركته ← ثم العلامة الإعرابية بحسب نوع الكلمة.', 2, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('7ffcf241-6fe1-5136-87ff-53ecbdbbdaeb', 'arabic', 'المنصوبات', 'المفعول به والمفعول المطلق وأنواعه والمفعول لأجله والمفعول فيه والحال والتمييز والمستثنى بإلّا — مع الإعراب التفصيلي لكلّ نوع', '# ⚔️ المنصوبات — أسلحة المعنى في الجملة

> 💡 «المنصوبات تُثري الجملة وتُكمل المعنى: فلا فعلَ بلا مفعول، ولا صورةَ بلا حال، ولا دقّةَ بلا تمييز.»

## 🏰 المفعول به

**المفعول به** اسم منصوب يقع عليه فعل الفاعل، ويصحّ أن تسأل عنه بـ«مَن؟» أو «ماذا؟» بعد الفعل والفاعل.

- مثال: «قرأَ الطالبُ **الكتابَ**» — الكتابَ: مفعول به منصوب وعلامة نصبه الفتحة.
- مثال: «زرتُ **المدرستَينِ**» — المدرستَين: مفعول به منصوب وعلامة نصبه الياء لأنّه مثنّى.
- مثال: «كرَّمَ المديرُ **المجتهدينَ**» — المجتهدين: مفعول به منصوب وعلامة نصبه الياء لأنّه جمع مذكّر سالم.

> 🗡️ يُحذف المفعول به إذا كان الفعل لازمًا (غير متعدٍّ)، مثل: «جلسَ الولدُ». ولا يصحّ إضافة مفعول به هنا.

## ⚡ المفعول المطلق وأنواعه

**المفعول المطلق** مصدر منصوب يؤتى به بعد فعله من لفظه، وله ثلاثة أنواع:

| النوع        | الغرض                      | المثال                            |
| ------------ | -------------------------- | --------------------------------- |
| مؤكِّد للفعل | تأكيد الحدث ورفع الشكّ عنه | «ضربتُه **ضربًا**»                |
| مبيِّن للنوع | بيان نوع الحدث أو صفته     | «سارَ الجنديُّ **سيرَ الأبطالِ**» |
| مبيِّن للعدد | بيان عدد مرّات الحدث       | «قرعتُ الجرسَ **قرعتَينِ**»       |

- «ضربًا»: مفعول مطلق مؤكِّد للفعل منصوب بالفتحة.
- «سيرَ الأبطالِ»: مفعول مطلق مبيِّن للنوع منصوب بالفتحة (مضاف و«الأبطالِ» مضاف إليه مجرور).
- «قرعتَينِ»: مفعول مطلق مبيِّن للعدد منصوب وعلامة نصبه الياء لأنّه مثنّى.

> 🛡️ قد يُنيب عن المفعول المطلق صفتُه أو عدده أو ضميره: «سرتُ سريعًا» (الصفة نابت عنه)، «ضربتُه ثلاثَ ضرباتٍ» (العدد).

## 🛡️ المفعول لأجله

**المفعول لأجله** (أو المفعول له) مصدر قلبيّ منصوب يُذكر سببًا وعلّةً لوقوع الفعل، ويُجاب عن «لماذا؟».

- مثال: «قمتُ **احترامًا** للضيفِ» — احترامًا: مفعول لأجله منصوب بالفتحة.
- مثال: «جئتُ **طلبًا** للعلمِ» — طلبًا: مفعول لأجله منصوب بالفتحة.

شروط نصبه مفعولًا لأجله:

- أن يكون مصدرًا.
- أن يكون قلبيًّا (يدلّ على معنى نفسيّ: حبّ، خوف، احترام…).
- أن يتّحد مع عامله في الزمن والفاعل.

> 🔮 إذا اقترن بـ«اللام» أو «الباء» أُعرب مجرورًا لا منصوبًا: «جئتُ لطلبِ العلمِ» — طلبِ: اسم مجرور باللام.

## 🔮 المفعول فيه (ظرف الزمان والمكان)

**المفعول فيه** اسم منصوب يدلّ على زمن الحدث أو مكانه، ويُقدَّر معه حرف الجرّ «في»:

**ظرف الزمان**: يدلّ على وقت وقوع الفعل.

- مثال: «جئتُ **يومَ** الجمعةِ» — يومَ: ظرف زمان منصوب وعلامة نصبه الفتحة.
- مثال: «نمتُ **ليلةً** كاملةً» — ليلةً: ظرف زمان منصوب بالفتحة.

**ظرف المكان**: يدلّ على مكان وقوع الفعل.

- مثال: «جلستُ **أمامَ** الأستاذِ» — أمامَ: ظرف مكان منصوب وعلامة نصبه الفتحة.
- مثال: «وقفتُ **خلفَ** البابِ» — خلفَ: ظرف مكان منصوب بالفتحة.

> 🗡️ الظروف المبهمة (قبلَ، بعدَ، فوقَ، تحتَ، أمامَ، خلفَ، يمينَ، يسارَ، وسطَ…) دائمًا منصوبة على الظرفيّة. الظروف المختصّة (يومٌ، ليلةٌ…) قد تنصب على الظرفيّة أو تُجرّ.

## 🧮 الحال

**الحال** اسم نكرة منصوب يُبيّن هيئة صاحبه وقت وقوع الفعل، ويُجاب به عن «كيف؟»:

- مثال: «عادَ الجنديُّ **منتصرًا**» — منتصرًا: حال منصوب بالفتحة، وصاحب الحال «الجنديُّ».
- مثال: «وصلَ الفريقُ **مبتهجًا**» — مبتهجًا: حال منصوب بالفتحة.
- مثال: «قرأَ الطلابُ **صامتينَ**» — صامتين: حال منصوب وعلامة نصبه الياء (جمع مذكّر سالم).

شروط الحال:

- نكرة في الغالب (ولا يجوز تعريفها).
- مشتقّة في الأصل (اسم فاعل أو مفعول أو صفة مشبّهة).
- لها صاحب معرفة في الغالب.

> 🛡️ الحال قد تكون جملة: «جاءَ الطالبُ وهو فرحٌ» — جملة «وهو فرحٌ» في محلّ نصب حال.

## 🧪 التمييز — تمييز الذات وتمييز النسبة

**التمييز** اسم نكرة منصوب يُزيل الإبهام عن اسم أو نسبة:

**تمييز الذات** (تمييز المفرد): يُزيل إبهام مفرد (عدد، مقدار، مساحة، وزن):

- مثال: «اشتريتُ عشرينَ **كتابًا**» — كتابًا: تمييز منصوب بالفتحة.
- مثال: «عندي لتران **ماءً**» — ماءً: تمييز منصوب بالفتحة.

**تمييز النسبة** (تمييز الجملة): يُزيل إبهام جملة كاملة:

- مثال: «ازدادَ المحبُّ **شوقًا**» — شوقًا: تمييز منصوب بالفتحة يُزيل إبهام ما ازداد.
- مثال: «امتلأَ القلبُ **سعادةً**» — سعادةً: تمييز منصوب بالفتحة.

> 🔮 تمييز العدد: من 3 إلى 10 جمع مجرور؛ من 11 إلى 99 مفرد منصوب (تمييز مجرور لـ3-10، منصوب لـ11-99).

## ⚙️ المستثنى بإلّا

**المستثنى** اسم يقع بعد «إلّا» ويُخرج من حكم ما قبلها. وحكمه:

| نوع الجملة   | حكم المستثنى           | المثال                                      |
| ------------ | ---------------------- | ------------------------------------------- |
| تامّة مثبتة  | منصوب وجوبًا           | «حضرَ الطلابُ **إلّا زيدًا**»               |
| تامّة منفيّة | منصوب أو بدل           | «ما حضرَ الطلابُ **إلّا زيدًا** / **زيدٌ**» |
| ناقصة منفيّة | إعراب ما يقتضيه المقام | «ما حضرَ **إلّا زيدٌ**» (فاعل)              |

- «زيدًا» في الجملة التامّة المثبتة: مستثنى منصوب وعلامة نصبه الفتحة.
- «زيدٌ» في الجملة الناقصة المنفيّة: فاعل مرفوع بالضمّة (وليس مستثنى منصوبًا).', '# 📜 ملخّص: المنصوبات

- **المفعول به**: اسم منصوب وقع عليه فعل الفاعل — يُسأل عنه بـ«مَن؟» أو «ماذا؟» بعد الفعل والفاعل.
- **المفعول المطلق**: مصدر منصوب من لفظ فعله؛ ثلاثة أنواع: مؤكِّد للفعل («ضربًا»)، مبيِّن للنوع («سيرَ الأبطال»)، مبيِّن للعدد («قرعتَينِ»).
- **المفعول لأجله**: مصدر قلبيّ منصوب يُذكر سببًا لوقوع الفعل — يُجاب به عن «لماذا؟» (شرطه: مصدر قلبيّ متّحد مع عامله في الزمن والفاعل).
- **المفعول فيه**: اسم منصوب يدلّ على ظرف الزمان («يومَ الجمعة») أو المكان («أمامَ الأستاذ»)، يُقدَّر معه حرف الجرّ «في».
- **الحال**: نكرة منصوبة تُبيّن هيئة صاحبها وقت وقوع الفعل — يُجاب به عن «كيف؟»؛ صاحبه معرفة في الغالب.
- **التمييز**: نكرة منصوبة تُزيل الإبهام؛ نوعان: تمييز الذات (يُزيل إبهام مفرد: عدد أو مقدار) وتمييز النسبة (يُزيل إبهام جملة).
- **المستثنى بإلّا**: في الجملة التامّة المثبتة → منصوب وجوبًا؛ في التامّة المنفيّة → منصوب أو بدل؛ في الناقصة المنفيّة → يُعرب حسب موقعه.
- **المنهجيّة**: حدِّد نوع المنصوب ← ثم علامة النصب (فتحة / ياء / كسرة للممنوع من الصرف) ← ثم سبب النيابة إن وُجدت.', 3, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('ccaffc76-5b0e-539a-b938-127edf17aa08', 'arabic', 'الأساليب النحوية', 'أسلوب الإغراء والتحذير والاختصاص والنداء والاستفهام والتعجّب مع الإعراب التفصيلي', '# ⚔️ الأساليب النحوية — سلاحك في التعبير والإقناع

> 💡 «الأسلوب روح الجملة: فبه تُغري وتُحذِّر وتُنادي وتستفهم وتتعجّب. أتقنه تملك ناصية البيان.»

## 🏰 أسلوب الإغراء

**الإغراء** هو أسلوب يُحثُّ فيه المخاطَب على فعل أمر محمود.

- **الصيغة**: ذِكر الاسم المُغرى به منصوبًا مع حذف الفعل وجوبًا.
- **العامل المقدَّر**: فعل محذوف وجوبًا، تقديره «الزَم» أو «عليك».
- **الإعراب**: المُغرى به **منصوب** وعلامة نصبه الفتحة (أو ما ينوب عنها).

**أمثلة محلولة**:

| الجملة                  | الإعراب                                       |
| ----------------------- | --------------------------------------------- |
| الصِّدقَ الصِّدقَ!      | الصِّدقَ: مُغرى به منصوب، والتكرار للتوكيد    |
| النظافةَ أيّها الطلابُ! | النظافةَ: مُغرى به منصوب بالفتحة              |
| الجِدَّ والمثابرةَ!     | الجِدَّ والمثابرةَ: مُغرى بهما منصوبان بالعطف |

> 🗡️ يُكرَّر المُغرى به أو يُعطف عليه للتوكيد، وفعله محذوف دائمًا.

## ⚡ أسلوب التحذير

**التحذير** هو أسلوب يُنبَّه فيه المخاطَب إلى أمر مكروه ليتجنّبه.

- **الصيغة**: ذِكر الاسم المحذَّر منه منصوبًا مع حذف الفعل وجوبًا.
- **العامل المقدَّر**: فعل محذوف وجوبًا، تقديره «احذَر» أو «اتَّقِ».
- **الإعراب**: المحذَّر منه **منصوب** وعلامة نصبه الفتحة أو ما ينوب عنها.
- **أداة الربط «إيّا»**: تُستخدم مع ضمير المخاطب: إيّاكَ، إيّاكِ، إيّاكما، إيّاكم.

**أمثلة محلولة**:

| الجملة          | الإعراب                                                     |
| --------------- | ----------------------------------------------------------- |
| الكسلَ الكسلَ!  | الكسلَ: محذَّر منه منصوب، التكرار للتوكيد                   |
| إيّاكَ والغشَّ! | إيّاكَ: ضمير منفصل مفعول به لفعل محذوف؛ الغشَّ: معطوف منصوب |
| إيّاكَ الكذبَ!  | إيّاكَ: مفعول به، الكذبَ: بدل أو مفعول ثانٍ منصوب           |

> 🛡️ الفرق: الإغراء يدعو إلى فعل الخير، والتحذير يُبعد عن الشرّ.

## 🔮 أسلوب الاختصاص

**الاختصاص** هو أسلوب يُخصَّص فيه الحكم بضمير المتكلّم أو المخاطَب بعد ذكره.

- **الصيغة**: ضمير + اسم منصوب بين شبه معترضتين (أو بعد الضمير مباشرة).
- **أداة الاختصاص**: كثيرًا ما تسبقه «أيّ» أو «أيّتها».
- **الإعراب**: اسم الاختصاص **منصوب** على الاختصاص بفعل محذوف تقديره «أخصّ».

**أمثلة محلولة**:

| الجملة                          | الإعراب                      |
| ------------------------------- | ---------------------------- |
| نحنُ — العربَ — نُكرم الضيفَ    | العربَ: منصوب على الاختصاص   |
| أنا — المعلّمَ — أُقدِّر العلمَ | المعلّمَ: منصوب على الاختصاص |

## 🧮 أسلوب النداء

**النداء** أسلوب لاستدعاء المخاطَب وتنبيهه.

**أدوات النداء**:

- **يا**: للقريب والبعيد (الأكثر استعمالًا).
- **أيا / هيا**: للبعيد.
- **أيْ / آ**: للقريب.

**إعراب المنادى**:

| نوع المنادى     | الإعراب         | مثال             |
| --------------- | --------------- | ---------------- |
| علم مفرد        | مبنيّ على الضمّ | يا محمّدُ        |
| نكرة مقصودة     | مبنيّ على الضمّ | يا رجلُ          |
| نكرة غير مقصودة | منصوب           | يا رجلًا أعنِّي  |
| مضاف            | منصوب           | يا طالبَ العلمِ  |
| شبيه بالمضاف    | منصوب           | يا طالبًا للمجدِ |

> 🏆 المنادى المفرد العلم والنكرة المقصودة: مبنيّان على الضمّ في محلّ نصب دائمًا.

**مثال محلول**:

- «يا عليُّ أجِبْ»: يا حرف نداء، عليُّ منادى مبنيّ على الضمّ في محلّ نصب.
- «يا طالبَ العلمِ اجتهدْ»: طالبَ منادى منصوب بالفتحة، وهو مضاف.

## 🧪 أسلوب الاستفهام

**الاستفهام** هو أسلوب للسؤال عن شيء مجهول.

**أدوات الاستفهام**:

| الأداة       | الاستخدام                      | مثال             |
| ------------ | ------------------------------ | ---------------- |
| هل           | سؤال عن الجملة (جواب نعم/لا)   | هل درستَ؟        |
| الهمزة       | سؤال عن الجملة أو التعيين      | أحاضرٌ أنتَ؟     |
| من           | عن العاقل                      | من جاءَ؟         |
| ما           | عن غير العاقل                  | ما الواجبُ؟      |
| ماذا         | عن غير العاقل (يدخل على الفعل) | ماذا فعلتَ؟      |
| متى          | عن الزمن                       | متى سافرتَ؟      |
| أين          | عن المكان                      | أين البيتُ؟      |
| كيف          | عن الحال                       | كيف صحّتُك؟      |
| كم           | عن العدد                       | كم كتابًا قرأتَ؟ |
| لماذا / لِمَ | عن السبب                       | لماذا تأخّرتَ؟   |

> 💡 «هل» لا تدخل على الاسم المفرد ولا تُعلَّق بما بعدها إضافةً، بخلاف الهمزة.

## ✨ أسلوب التعجّب

**التعجّب** هو أسلوب للتعبير عن الدهشة والإعجاب.

**صيغتاه القياسيّتان**:

### الصيغة الأولى: ما أفعلَه!

- **البناء**: ما + فعل التعجّب (ماضٍ على وزن أفعَلَ) + اسم منصوب (المتعجَّب منه).
- **إعراب «ما»**: اسم نكرة مبنيّ في محلّ رفع مبتدأ، أو تعجّبيّة.
- **المتعجَّب منه**: منصوب على أنّه مفعول به.
- مثال: **ما أجملَ السماءَ!** → ما: مبتدأ؛ أجملَ: فعل ماضٍ؛ السماءَ: مفعول به منصوب.

### الصيغة الثانية: أفعِلْ به!

- **البناء**: فعل أمر جامد على وزن أفعِلْ + «بـ» الزائدة + الفاعل مجرور لفظًا مرفوع محلًّا.
- مثال: **أجمِلْ بالسماءِ!** → أجمِلْ: فعل أمر جامد؛ بالسماءِ: الباء زائدة، السماء فاعل مرفوع محلًّا مجرور لفظًا.

**شروط التعجّب القياسي**: الفعل الثلاثيّ التامّ المتصرّف غير الدالّ على لون أو عيب، قابل للتفاضل.

> ⚔️ للتعجّب من فعل لا يستوفي الشروط نستعين بـ «ما أشدَّ» أو «ما أكثرَ»: **ما أشدَّ احمرارَ الوردةِ!**', '# 📜 ملخّص: الأساليب النحوية

- **أسلوب الإغراء**: حثّ المخاطَب على فعل محمود؛ المُغرى به **منصوب** بفعل محذوف وجوبًا (الزَم). مثال: _الصِّدقَ الصِّدقَ!_
- **أسلوب التحذير**: تنبيه المخاطَب من أمر مكروه؛ المحذَّر منه **منصوب** بفعل محذوف (احذَر). يُصاغ بـ«إيّاكَ» أيضًا. مثال: _إيّاكَ والكسلَ!_
- **الفرق**: الإغراء = دعوة للخير؛ التحذير = نهي عن الشرّ. كلاهما: الفعل محذوف وجوبًا والاسم منصوب.
- **أسلوب الاختصاص**: اسم منصوب بعد ضمير متكلّم/مخاطَب لتخصيص الحكم. العامل: فعل محذوف تقديره «أخصّ». مثال: _نحنُ — العربَ — نُكرم الضيفَ_.
- **أسلوب النداء**: أدواته (يا، أيا، هيا، أيْ، آ). إعراب المنادى: مبنيّ على الضمّ إن كان مفردًا علمًا أو نكرة مقصودة؛ منصوب إن كان مضافًا أو شبيهًا به أو نكرة غير مقصودة.
- **أسلوب الاستفهام**: أدواته (هل، الهمزة، من، ما، ماذا، متى، أين، كيف، كم، لماذا). «هل» للتصديق فقط؛ الهمزة للتصديق والتعيين.
- **أسلوب التعجّب** — صيغتان قياسيّتان:
  - **ما أفعلَه!**: ما (مبتدأ تعجّبيّة) + فعل ماضٍ وزن أفعَلَ + مفعول به منصوب.
  - **أفعِلْ به!**: فعل أمر جامد وزن أفعِلْ + باء زائدة + فاعل مرفوع محلًّا مجرور لفظًا.
  - الشرط: ثلاثيّ تامّ متصرّف لا يدلّ على لون أو عيب.', 4, NULL)
ON CONFLICT (id) DO UPDATE SET
