INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b8b9fa61-a238-5076-93f5-f91d5c0ba8da', 'df137ab2-b7c2-518b-8af5-dac47ffe3890', 'في «مررتُ بمساجدَ»، لماذا جُرّ «مساجدَ» بالفتحة؟', '[{"id":"a","text":"لأنّه جمع مذكّر سالم"},{"id":"b","text":"لأنّه ممنوع من الصرف"},{"id":"c","text":"لأنّه مثنّى"},{"id":"d","text":"لأنّه من الأسماء الخمسة"}]'::jsonb, 'b', '«مساجد» على صيغة منتهى الجموع، فهو ممنوع من الصرف يُجرّ بالفتحة نيابة عن الكسرة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5fd6d30b-9ffe-5b58-91fa-7af341455373', 'df137ab2-b7c2-518b-8af5-dac47ffe3890', 'أيّ حالة إعراب تخصّ الأفعال دون الأسماء؟', '[{"id":"a","text":"الجرّ"},{"id":"b","text":"الجزم"},{"id":"c","text":"النصب"},{"id":"d","text":"الرفع"}]'::jsonb, 'b', 'الجزم خاصّ بالأفعال المضارعة، في حين أنّ الجرّ خاصّ بالأسماء، والرفع والنصب مشتركان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('de698859-c461-58c5-9dda-ca90d16dc9e6', 'e1499e39-9a76-5e0c-b297-921b08b69cf4', 'arabic', '👑 تحدّي النخبة: دقائق الإعراب والبناء', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
