  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a483811-cc0a-5d76-a7cf-955674b98ddb', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'ما الفرق بين الكلمة المعربة والكلمة المبنيّة؟', '[{"id":"a","text":"المعربة يتغيّر آخرها بتغيّر موقعها، والمبنيّة يلزم آخرها حالة واحدة"},{"id":"b","text":"المعربة اسم دائمًا والمبنيّة فعل دائمًا"},{"id":"c","text":"المعربة تُنصب فقط والمبنيّة تُرفع فقط"},{"id":"d","text":"لا فرق بينهما في الاستعمال"}]'::jsonb, 'a', 'المعرب تتغيّر علامة آخره (رفع/نصب/جرّ/جزم) بحسب موقعه في الجملة، أمّا المبنيّ فيلزم آخره حركة واحدة لا تتغيّر مهما تغيّر موقعه. والقول إنّ المعرب اسم والمبنيّ فعل خطأ، فالماضي مبنيّ وهو فعل والمضارع معرب وهو فعل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dc240339-7154-5598-8bfc-8ad5062c796e', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'أيّ الكلمات التالية مبنيّ من الأسماء؟', '[{"id":"a","text":"الكتابُ"},{"id":"b","text":"هذا"},{"id":"c","text":"مدرسةٌ"},{"id":"d","text":"تلميذٌ"}]'::jsonb, 'b', '«هذا» اسم إشارة مبنيّ لا تتغيّر حركته بتغيّر موقعه، وكذلك الضمائر وأسماء الاستفهام والشرط من الأسماء المبنيّة. أمّا «الكتاب» و«مدرسة» و«تلميذ» فأسماء معربة تتغيّر علامتها بحسب الموقع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eaed1ca1-fb64-5d3c-860a-0f7145007bc3', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'في «سلّمتُ على المعلّمينَ»، ما علامة جرّ «المعلّمينَ»؟', '[{"id":"a","text":"الكسرة لأنّه اسم مفرد"},{"id":"b","text":"الياء لأنّه جمع مذكّر سالم"},{"id":"c","text":"الفتحة لأنّه ممنوع من الصرف"},{"id":"d","text":"الألف لأنّه مثنّى"}]'::jsonb, 'b', '«المعلّمين» جمع مذكّر سالم مجرور بحرف الجرّ «على»، وعلامة جرّه الياء نيابة عن الكسرة. والكسرة علامة جرّ الاسم المفرد لا الجمع السالم.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f21d5168-79c5-5a2c-856f-9f018163d4dd', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'في «لن أتأخّرَ عن الموعدِ»، ما إعراب «أتأخّرَ»؟', '[{"id":"a","text":"فعل مضارع مرفوع بالضمّة"},{"id":"b","text":"فعل مضارع مجزوم بالسكون"},{"id":"c","text":"فعل مضارع منصوب بالفتحة لأنّ «لن» أداة نصب"},{"id":"d","text":"فعل ماضٍ مبنيّ على الفتح"}]'::jsonb, 'c', '«لن» حرف نصب ونفي واستقبال ينصب المضارع، فـ«أتأخّرَ» منصوب وعلامة نصبه الفتحة. ولا يُجزم لأنّ الجزم يكون بأدوات الجزم كـ«لم» لا بـ«لن».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('755ca542-4943-570f-9d6a-ff928c134626', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'في «جاء القاضي»، لماذا قُدّرت الضمّة على «القاضي» ولم تظهر؟', '[{"id":"a","text":"لأنّه مبنيّ لا يُعرب"},{"id":"b","text":"لأنّه اسم منقوص آخره ياء فتُقدَّر عليه الضمّة للثقل"},{"id":"c","text":"لأنّه ممنوع من الصرف"},{"id":"d","text":"لأنّه جمع تكسير"}]'::jsonb, 'b', '«القاضي» اسم منقوص (معرب آخره ياء لازمة قبلها كسر)، تُقدَّر عليه الضمّة والكسرة للثقل، وتظهر الفتحة لخفّتها. فهو فاعل مرفوع بضمّة مقدّرة على الياء منع من ظهورها الثقل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('abb9556b-1be3-51c2-a675-f96041ced204', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'في «المجتهدونَ ينجحونَ»، بِمَ رُفع «المجتهدونَ» وبِمَ رُفع «ينجحونَ»؟', '[{"id":"a","text":"كلاهما بالضمّة"},{"id":"b","text":"الأوّل بالواو (جمع مذكّر سالم) والثاني بثبوت النون (من الأفعال الخمسة)"},{"id":"c","text":"الأوّل بالألف والثاني بالواو"},{"id":"d","text":"الأوّل بثبوت النون والثاني بالواو"}]'::jsonb, 'b', '«المجتهدون» جمع مذكّر سالم مرفوع بالواو نيابة عن الضمّة. و«ينجحون» فعل مضارع من الأفعال الخمسة (يتّصل به واو الجماعة) مرفوع بثبوت النون نيابة عن الضمّة. فعلامتا الرفع مختلفتان لاختلاف نوع الكلمتين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('f863d070-30b2-5bb6-b9d1-096ab319e8f8', 'e1499e39-9a76-5e0c-b297-921b08b69cf4', 'arabic', '👑 تحدّي المناظرة ⭐⭐⭐⭐: دقائق الإعراب والبناء — علامات فرعية ومقدّرة', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('26f6f856-b6e9-5d2b-9c08-02856f751581', 'f863d070-30b2-5bb6-b9d1-096ab319e8f8', 'في الجملة: «الطلّابُ يجتهدونَ في دروسِهم»، ما علامة رفع الفعل «يجتهدونَ»؟', '[{"id":"a","text":"ثبوت النون؛ لأنّه من الأفعال الخمسة"},{"id":"b","text":"الضمّة الظاهرة على آخره"},{"id":"c","text":"الضمّة المقدّرة"},{"id":"d","text":"الواو؛ لأنّه جمع مذكّر سالم"}]'::jsonb, 'a', '«يجتهدونَ» فعل مضارع اتّصلت به واو الجماعة، فهو من الأفعال الخمسة (يفعلون، تفعلون، يفعلان، تفعلان، تفعلين)، وعلامة رفعه ثبوت النون. ✓ الخطأ الشائع: معاملته كفعل صحيح الآخر فيُرفع بالضمّة؛ أو الخلط بينه وبين جمع المذكّر السالم (الواو علامة رفعٍ في الأسماء لا الأفعال).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('534d9a77-3d9d-582a-9769-7f0ca5f05df9', 'f863d070-30b2-5bb6-b9d1-096ab319e8f8', 'قال تلميذ: «الفعل الماضي معرَب؛ لأنّ آخره يتغيّر في مثل: كَتَبَ، كَتَبْتُ، كَتَبُوا». ما الخطأ في استدلاله؟', '[{"id":"a","text":"الماضي مبنيّ دائمًا؛ وتغيّر آخره مع الضمائر بناءٌ (على الفتح أو السكون أو الضمّ) لا إعراب"},{"id":"b","text":"لا خطأ، الماضي معرب فعلًا"},{"id":"c","text":"الماضي مبنيّ على الكسر دائمًا"},{"id":"d","text":"الماضي معرب بعلامات مقدّرة"}]'::jsonb, 'a', 'الفعل الماضي مبنيّ دائمًا: يُبنى على الفتح (كَتَبَ)، وعلى السكون إذا اتّصل بضمير رفع متحرّك (كَتَبْتُ)، وعلى الضمّ إذا اتّصلت به واو الجماعة (كَتَبُوا). فتغيّر آخره تغيّرُ بناءٍ بسبب المتّصل به، لا إعرابٌ بسبب العامل. (تمرين «صيد الخطأ».) الخطأ الشائع: عدّ كلّ تغيّرٍ في الآخر إعرابًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7afe2f4-44a5-5e41-8fea-67de7a98f9c0', 'f863d070-30b2-5bb6-b9d1-096ab319e8f8', 'في الجملة: «مَن يسعَ إلى الخيرِ يجدْ ثمرتَه»، ما علامة جزم الفعل «يسعَ»؟', '[{"id":"a","text":"حذف حرف العلّة (الألف)؛ لأنّه فعل معتلّ الآخر"},{"id":"b","text":"السكون الظاهر"},{"id":"c","text":"الفتحة"},{"id":"d","text":"حذف النون"}]'::jsonb, 'a', '«يسعَ» فعل مضارع معتلّ الآخر (أصله يسعى)، جاء مجزومًا لأنّه فعل الشرط بعد «مَن»، وعلامة جزم المعتلّ الآخر حذفُ حرف العلّة. ✓ الخطأ الشائع: جزمه بالسكون كالصحيح الآخر؛ أو حذف النون (وهي علامة جزم الأفعال الخمسة لا المعتلّ).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('93a91ba2-ce88-51ed-b929-fdb40416a26f', 'f863d070-30b2-5bb6-b9d1-096ab319e8f8', 'في الجملة: «كُوفِئَ المجتهدونَ»، ما إعراب «المجتهدونَ»؟', '[{"id":"a","text":"نائب فاعل مرفوع بالواو؛ لأنّه جمع مذكّر سالم"},{"id":"b","text":"فاعل مرفوع بالواو"},{"id":"c","text":"نائب فاعل مرفوع بالضمّة"},{"id":"d","text":"مفعول به منصوب بالياء"}]'::jsonb, 'a', 'الفعل «كُوفِئَ» مبنيّ للمجهول، فما بعده نائب فاعل. و«المجتهدونَ» جمع مذكّر سالم، فيُرفع بالواو نيابةً عن الضمّة. ✓ الخطأ الشائع: تسميته فاعلًا (مع أنّ الفعل مبنيّ للمجهول)؛ أو رفعه بالضمّة ونسيان أنّه جمع مذكّر سالم يُرفع بالواو.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21547f47-3a56-525d-8d0f-d16bca36e9fb', 'f863d070-30b2-5bb6-b9d1-096ab319e8f8', 'أيّ الكلمات التالية اسمٌ مبنيّ (لا يتغيّر آخره بتغيّر موقعه الإعرابيّ)؟', '[{"id":"a","text":"هؤلاء (اسم إشارة مبنيّ على الكسر)"},{"id":"b","text":"القاضي (اسم منقوص)"},{"id":"c","text":"المعلّمونَ (جمع مذكّر سالم)"},{"id":"d","text":"فتًى (اسم مقصور)"}]'::jsonb, 'a', '«هؤلاء» اسم إشارة، وأسماء الإشارة مبنيّة لا يتغيّر آخرها بتغيّر الموقع (تكون في محلّ رفع أو نصب أو جرّ). أمّا «القاضي» و«فتًى» فمُعربان بعلامات مقدّرة (منعها الثقل أو التعذّر)، و«المعلّمونَ» معرب بالحروف. ✓ الخطأ الشائع: ظنّ أنّ ثبات آخر المنقوص والمقصور ظاهريًّا يعني البناء، والصواب أنّها معربة بعلامات مقدّرة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b653bd8b-7af6-5a45-84a3-644309739be8', 'f863d070-30b2-5bb6-b9d1-096ab319e8f8', 'في الجملة: «سلّمتُ على القاضي العادلِ»، ما علامة جرّ «القاضي»؟', '[{"id":"a","text":"كسرة مقدّرة على الياء منع من ظهورها الثقل"},{"id":"b","text":"كسرة ظاهرة على الياء"},{"id":"c","text":"فتحة نيابةً عن الكسرة"},{"id":"d","text":"الياء؛ لأنّه من الأسماء الخمسة"}]'::jsonb, 'a', '«القاضي» اسم منقوص (منتهٍ بياء لازمة قبلها كسرة)، فتُقدَّر عليه علامات الرفع والجرّ للثقل: هنا هو مجرور بحرف الجرّ «على» بكسرة مقدّرة على الياء منع من ظهورها الثقل. ✓ الخطأ الشائع: إثبات كسرة ظاهرة على المنقوص؛ أو الخلط بينه وبين الأسماء الخمسة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

