INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8868e0d8-2c30-51f3-a641-9268c38dffbd', 'e484384e-e3e2-590c-8af1-36d54d28d850', 'في جملة «كانَ الجوُّ صافيًا»، ما إعراب «الجوُّ»؟', '[{"id":"a","text":"اسم «كان» مرفوع بالضمّة"},{"id":"b","text":"خبر «كان» منصوب بالفتحة"},{"id":"c","text":"فاعل مرفوع بالضمّة"},{"id":"d","text":"مبتدأ مرفوع بالضمّة"}]'::jsonb, 'a', '«كان» فعل ناسخ يرفع المبتدأ فيُسمّى اسمها، فـ«الجوُّ» اسم كان مرفوع وعلامة رفعه الضمّة.', 1)
