INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('13ab600c-3f76-5d89-8f22-4abcadc859ac', 'e484384e-e3e2-590c-8af1-36d54d28d850', 'أيٌّ من الجمل التالية يحتوي على فعل ناسخ؟', '[{"id":"a","text":"إنَّ الصديقَ أمينٌ"},{"id":"b","text":"صارَ الصديقُ قائدًا"},{"id":"c","text":"ليتَ الشبابَ يعودُ"},{"id":"d","text":"لعلَّ الفرجَ قريبٌ"}]'::jsonb, 'b', '«صار» فعل ناسخ من أخوات كان، أمّا «إنّ» و«ليت» و«لعلّ» فهي حروف ناسخة.', 3)
