  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e1816a2-33b0-5688-acd6-236456dc4c61', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'ما عمل «كان» وأخواتها في الجملة الاسمية؟', '[{"id":"a","text":"ترفع المبتدأ (اسمها) وتنصب الخبر (خبرها)"},{"id":"b","text":"تنصب المبتدأ وترفع الخبر"},{"id":"c","text":"ترفع المبتدأ والخبر معًا"},{"id":"d","text":"تجرّ المبتدأ والخبر"}]'::jsonb, 'a', 'الأفعال الناسخة (كان وأخواتها) ترفع المبتدأ ويُسمّى اسمها، وتنصب الخبر ويُسمّى خبرها. أمّا الحروف الناسخة (إنّ وأخواتها) فهي التي تنصب الاسم وترفع الخبر، فلا يُخلط بينهما.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7fe86a42-2eaf-5259-b771-24c8ff86cb8e', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'أيّ الجمل التالية تحتوي على فعل ناسخ؟', '[{"id":"a","text":"إنّ السماءَ صافيةٌ"},{"id":"b","text":"صار الجوُّ باردًا"},{"id":"c","text":"لعلّ الغائبَ حاضرٌ"},{"id":"d","text":"السماءُ صافيةٌ"}]'::jsonb, 'b', '«صار» فعل ناسخ من أخوات «كان» يدلّ على التحوّل، رفع «الجوُّ» اسمًا له ونصب «باردًا» خبرًا له. أمّا «إنّ» و«لعلّ» فحرفان ناسخان لا فعلان، والجملة الأخيرة جملة اسمية بلا ناسخ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f5c592a-efb1-59d8-b290-39d81bbb50ec', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'في «إنّ المعلّمينَ مخلصونَ»، ما إعراب «المعلّمينَ»؟', '[{"id":"a","text":"اسم إنّ منصوب وعلامة نصبه الياء (جمع مذكّر سالم)"},{"id":"b","text":"خبر إنّ مرفوع بالواو"},{"id":"c","text":"مبتدأ مرفوع بالضمّة"},{"id":"d","text":"اسم إنّ منصوب وعلامة نصبه الفتحة"}]'::jsonb, 'a', '«إنّ» حرف ناسخ ينصب اسمه، و«المعلّمين» اسمها منصوب، وهو جمع مذكّر سالم فعلامة نصبه الياء نيابة عن الفتحة لا الفتحة الظاهرة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d1d2571-8452-5bdf-817d-310cca9dcf83', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'أيٌّ من الحروف الناسخة يفيد التشبيه؟', '[{"id":"a","text":"ليت"},{"id":"b","text":"لعلّ"},{"id":"c","text":"كأنّ"},{"id":"d","text":"لكنّ"}]'::jsonb, 'c', '«كأنّ» تفيد التشبيه (كأنّ العلمَ نورٌ). أمّا «ليت» فللتمنّي، و«لعلّ» للترجّي، و«لكنّ» للاستدراك. فلكلّ حرف ناسخ معناه الخاصّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('efb5ba4b-c0cf-5bef-bf94-abe3bca30512', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'في «كان الجوُّ معتدلًا»، إذا حذفنا «كان» فما إعراب «الجوُّ» و«معتدل»؟', '[{"id":"a","text":"الجوُّ مبتدأ مرفوع و«معتدلٌ» خبر مرفوع"},{"id":"b","text":"الجوُّ اسم كان و«معتدلًا» خبرها منصوب"},{"id":"c","text":"الجوُّ فاعل و«معتدلًا» مفعول به"},{"id":"d","text":"الجوُّ خبر مقدّم و«معتدلًا» مبتدأ مؤخّر"}]'::jsonb, 'a', 'بحذف الناسخ تعود الجملة إلى أصلها الاسمي: «الجوُّ معتدلٌ»، فـ«الجوُّ» مبتدأ مرفوع و«معتدلٌ» خبر مرفوع. وهذا يُبرز أنّ عمل «كان» هو نصب الخبر فقط مع إبقاء رفع المبتدأ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a330277-b986-55a7-834f-8b23af6c0f1e', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'في «إنّ في الحديقةِ أزهارًا»، أين خبر «إنّ» وأين اسمها؟', '[{"id":"a","text":"«أزهارًا» اسمها مؤخّر منصوب، والخبر شبه الجملة «في الحديقة» مقدّم"},{"id":"b","text":"«الحديقة» اسمها و«أزهارًا» خبرها"},{"id":"c","text":"«أزهارًا» خبرها و«الحديقة» اسمها"},{"id":"d","text":"لا اسم لها ولا خبر"}]'::jsonb, 'a', 'تقدّم خبر «إنّ» (شبه الجملة «في الحديقة») على اسمها لأنّ الاسم نكرة «أزهارًا». فالخبر شبه جملة مقدّم في محلّ رفع، و«أزهارًا» اسم إنّ مؤخّر منصوب بالفتحة. ويجب التقديم هنا لئلّا يبدأ الكلام باسم نكرة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('6d835c50-a70c-5b48-9937-247d7b4ec039', '6f86fdbf-9213-56bf-b9b9-f64baacf4184', 'arabic', '👑 تحدّي المناظرة ⭐⭐⭐⭐: النواسخ — كان وإنّ وظنّ ولا النافية للجنس', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d8ac21d-d155-5e85-b527-d51e1608243f', '6d835c50-a70c-5b48-9937-247d7b4ec039', 'في الجملة: «كانَ الجوُّ صحوًا»، ما إعراب «صحوًا»؟', '[{"id":"a","text":"خبر «كان» منصوب بالفتحة"},{"id":"b","text":"اسم «كان» مرفوع"},{"id":"c","text":"مفعول به منصوب"},{"id":"d","text":"حال منصوبة"}]'::jsonb, 'a', '«كان» فعل ناسخ يرفع الاسم وينصب الخبر: «الجوُّ» اسمها مرفوع، و«صحوًا» خبرها منصوب بالفتحة. ✓ الخطأ الشائع: عدّ «صحوًا» مفعولًا به (كان لا تأخذ مفعولًا) أو حالًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6505a403-7af1-5911-a41c-55e1f21162ea', '6d835c50-a70c-5b48-9937-247d7b4ec039', 'قال تلميذ: «في جملة (صارَ الجوُّ باردًا) كلمة (الجوُّ) مبتدأ مرفوع». ما الخطأ؟', '[{"id":"a","text":"«صارَ» من أخوات «كان»، فـ«الجوُّ» اسمها مرفوع (لا مبتدأ) و«باردًا» خبرها منصوب"},{"id":"b","text":"لا خطأ، «الجوُّ» مبتدأ فعلًا"},{"id":"c","text":"«الجوُّ» فاعل لـ«صارَ»"},{"id":"d","text":"«باردًا» مبتدأ ثانٍ"}]'::jsonb, 'a', '«صارَ» فعل ناسخ من أخوات «كان»، يرفع الاسم وينصب الخبر؛ فـ«الجوُّ» اسم «صار» مرفوع (وليس مبتدأ لأنّ الناسخ دخل عليه)، و«باردًا» خبرها منصوب. (تمرين «صيد الخطأ».) الخطأ الشائع: تسمية اسم الناسخ مبتدأ بحكم أنّه مرفوع في أوّل الجملة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f0691fdf-c709-54b8-8f7c-0184032cf60a', '6d835c50-a70c-5b48-9937-247d7b4ec039', 'في الجملة: «إنَّ في التأنّي السلامةَ»، ما إعراب «السلامةَ» و«في التأنّي»؟', '[{"id":"a","text":"«السلامةَ» اسم «إنّ» مؤخّر منصوب ; «في التأنّي» جارّ ومجرور خبر «إنّ» مقدّم"},{"id":"b","text":"«السلامةَ» خبر «إنّ» منصوب ; «في التأنّي» متعلّق بالخبر"},{"id":"c","text":"«السلامةَ» مفعول به ; «في التأنّي» حال"},{"id":"d","text":"«السلامةَ» اسم «إنّ» مرفوع ; «في التأنّي» خبر"}]'::jsonb, 'a', 'تقدّم خبر «إنّ» شبه الجملة «في التأنّي» على اسمها، فهو خبر مقدّم، و«السلامةَ» اسم «إنّ» مؤخّر منصوب بالفتحة. وتقديم الخبر شبه الجملة على الاسم النكرة جائزٌ بل قد يكون واجبًا. ✓ الخطأ الشائع: عدّ «السلامةَ» خبرًا لأنّها متأخّرة، وإهمال أنّ «إنّ» تنصب الاسم لا الخبر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6a18a894-49f4-58c3-b9b3-850f73e9544a', '6d835c50-a70c-5b48-9937-247d7b4ec039', 'في الجملة: «حسِبتُ الامتحانَ سهلًا»، كم مفعولًا للفعل «حسِبَ» وما إعرابهما؟', '[{"id":"a","text":"مفعولان: «الامتحانَ» أوّل و«سهلًا» ثانٍ، منصوبان (أصلهما مبتدأ وخبر)"},{"id":"b","text":"مفعول واحد «الامتحانَ»، و«سهلًا» حال"},{"id":"c","text":"مفعول واحد «سهلًا»، و«الامتحانَ» فاعل"},{"id":"d","text":"لا مفعول له؛ لأنّه فعل ناقص"}]'::jsonb, 'a', '«حسِبَ» من أفعال الظنّ (ظنّ وأخواتها) التي تنصب مفعولَين أصلهما مبتدأ وخبر: «الامتحانَ» مفعول أوّل منصوب، و«سهلًا» مفعول ثانٍ منصوب. ✓ الخطأ الشائع: عدّ «سهلًا» حالًا؛ وهي في الأصل خبرٌ عن «الامتحان» فصارت مفعولًا ثانيًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ddc76b15-7cda-5072-a67a-7fc46ab98062', '6d835c50-a70c-5b48-9937-247d7b4ec039', 'في الجملة: «لا طالبَ غائبٌ»، ما إعراب «طالبَ»؟', '[{"id":"a","text":"اسم «لا» النافية للجنس مبنيّ على الفتح في محلّ نصب"},{"id":"b","text":"مبتدأ مرفوع بالضمّة"},{"id":"c","text":"اسم «لا» منصوب بالفتحة الظاهرة"},{"id":"d","text":"مفعول به منصوب"}]'::jsonb, 'a', '«لا» هنا نافية للجنس تعمل عمل «إنّ»، واسمها إذا كان مفردًا (غير مضاف ولا شبيه به) يُبنى على ما يُنصب به: «طالبَ» مبنيّ على الفتح في محلّ نصب اسم «لا»، و«غائبٌ» خبرها مرفوع. ✓ الخطأ الشائع: إعرابه مبتدأ، أو نصبه بالفتحة الظاهرة مع أنّه مبنيّ لا معرب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e976a1f-5b7d-5c38-a816-0910ca5b8e6f', '6d835c50-a70c-5b48-9937-247d7b4ec039', 'في الجملة: «إنَّ الطلّابَ يجتهدونَ»، ما خبر «إنّ» وما محلّه من الإعراب؟', '[{"id":"a","text":"جملة «يجتهدونَ» الفعلية في محلّ رفع خبر «إنّ»"},{"id":"b","text":"«يجتهدونَ» خبر «إنّ» منصوب"},{"id":"c","text":"لا خبر لها في الجملة"},{"id":"d","text":"«الطلّابَ» خبر «إنّ»"}]'::jsonb, 'a', '«الطلّابَ» اسم «إنّ» منصوب، وخبرها جملة «يجتهدونَ» الفعلية الواقعة في محلّ رفع خبر «إنّ». فالجملة بعد اسم «إنّ» المنصوب تقع خبرًا في محلّ رفع. ✓ الخطأ الشائع: نصب الخبر لفظًا مع أنّه جملة لها محلّ من الإعراب (رفع)، لا إعراب ظاهر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('e8522c3d-f6bd-5416-819b-2a8b84c36952', '7ffcf241-6fe1-5136-87ff-53ecbdbbdaeb', 'arabic', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
