INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('96271970-854d-52ac-88cd-09b36519110c', '98751e6e-34dd-547a-bc9e-6548f561bba7', 'في جملة «قرأَ الطالبُ الكتابَ»، ما إعراب «الكتابَ»؟', '[{"id":"a","text":"فاعل مرفوع وعلامة رفعه الضمّة"},{"id":"b","text":"مفعول به منصوب وعلامة نصبه الفتحة"},{"id":"c","text":"مبتدأ مرفوع وعلامة رفعه الضمّة"},{"id":"d","text":"حال منصوب وعلامة نصبه الفتحة"}]'::jsonb, 'b', '«الكتابَ» وقع عليه فعل القراءة، فهو مفعول به منصوب وعلامة نصبه الفتحة الظاهرة على آخره.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
