INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d5894891-78f6-523e-ae76-e2e552c508d3', '98751e6e-34dd-547a-bc9e-6548f561bba7', 'في «ضربَ المعلّمُ ضربًا»، ما نوع «ضربًا»؟', '[{"id":"a","text":"مفعول به"},{"id":"b","text":"مفعول لأجله"},{"id":"c","text":"تمييز"},{"id":"d","text":"مفعول مطلق مؤكِّد للفعل"}]'::jsonb, 'd', '«ضربًا» مصدر من لفظ الفعل «ضربَ» جاء لتأكيد الحدث ورفع الشكّ عنه، فهو مفعول مطلق مؤكِّد للفعل، منصوب بالفتحة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7c45664c-2b27-582b-92f9-1958cadc443a', '98751e6e-34dd-547a-bc9e-6548f561bba7', 'في «جئتُ احترامًا للضيفِ»، ما إعراب «احترامًا»؟', '[{"id":"a","text":"مفعول به منصوب بالفتحة"},{"id":"b","text":"مفعول لأجله منصوب بالفتحة"},{"id":"c","text":"حال منصوب بالفتحة"},{"id":"d","text":"مفعول مطلق منصوب بالفتحة"}]'::jsonb, 'b', '«احترامًا» مصدر قلبيّ ذُكر سببًا لوقوع الفعل «جئتُ»، فهو مفعول لأجله منصوب وعلامة نصبه الفتحة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8741a006-cd0d-57e2-becf-e1aa8526f6d3', '98751e6e-34dd-547a-bc9e-6548f561bba7', 'في «جلستُ أمامَ الأستاذِ»، ما إعراب «أمامَ»؟', '[{"id":"a","text":"مفعول به منصوب بالفتحة"},{"id":"b","text":"حرف جرّ"},{"id":"c","text":"حال منصوب بالفتحة"},{"id":"d","text":"ظرف مكان منصوب وعلامة نصبه الفتحة"}]'::jsonb, 'd', '«أمامَ» ظرف مكان منصوب على الظرفيّة وعلامة نصبه الفتحة، وهو مضاف و«الأستاذِ» مضاف إليه مجرور.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a51ebe9-cc52-5331-82c0-28426ef7be75', '98751e6e-34dd-547a-bc9e-6548f561bba7', 'في «عادَ الجنديُّ منتصرًا»، ما إعراب «منتصرًا»؟', '[{"id":"a","text":"مفعول به منصوب بالفتحة"},{"id":"b","text":"خبر مرفوع بالضمّة"},{"id":"c","text":"حال منصوب وعلامة نصبه الفتحة"},{"id":"d","text":"تمييز منصوب بالفتحة"}]'::jsonb, 'c', '«منتصرًا» نكرة تُبيّن هيئة الجنديّ وقت عودته، فهو حال منصوب وعلامة نصبه الفتحة، وصاحب الحال «الجنديُّ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fefed5f6-3cbc-5c58-8efb-39404470fe91', '98751e6e-34dd-547a-bc9e-6548f561bba7', 'في «حضرَ الطلابُ إلّا زيدًا»، ما إعراب «زيدًا»؟', '[{"id":"a","text":"مستثنى منصوب وعلامة نصبه الفتحة"},{"id":"b","text":"فاعل مرفوع بالضمّة"},{"id":"c","text":"مفعول به منصوب بالفتحة"},{"id":"d","text":"بدل مرفوع بالضمّة"}]'::jsonb, 'a', 'الجملة تامّة مثبتة (لم يسبقها نفي)، فالمستثنى بعد «إلّا» واجب النصب، فـ«زيدًا» مستثنى منصوب وعلامة نصبه الفتحة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3a0414d1-56e5-50c3-ae38-91a93aca51e0', '7ffcf241-6fe1-5136-87ff-53ecbdbbdaeb', 'arabic', '⚔️ زعيم الفصل: المنصوبات — إعراب متقدّم', 3, 120, 30, 'boss', 'admin', 2)
