INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd5b5fda-475d-56e2-8d50-b027ce4f4a70', '3a0414d1-56e5-50c3-ae38-91a93aca51e0', 'في «قرأَ الطلابُ صامتينَ»، ما علامة نصب «صامتينَ»؟', '[{"id":"a","text":"الياء لأنّه جمع مذكّر سالم"},{"id":"b","text":"الفتحة لأنّه اسم مفرد"},{"id":"c","text":"الكسرة لأنّه جمع مؤنّث سالم"},{"id":"d","text":"الألف لأنّه مثنّى"}]'::jsonb, 'a', '«صامتين» حال منصوب وهو جمع مذكّر سالم، فعلامة نصبه الياء نيابة عن الفتحة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e03ae7c4-cbef-5400-90b0-94735107fe41', '3a0414d1-56e5-50c3-ae38-91a93aca51e0', 'أيٌّ من الجمل الآتية يحتوي على مفعول لأجله صحيح؟', '[{"id":"a","text":"«وقفتُ تعظيمًا للعَلَمِ»"},{"id":"b","text":"«وقفتُ أمامَ العَلَمِ»"},{"id":"c","text":"«وقفتُ وقوفًا»"},{"id":"d","text":"«وقفتُ الطالبُ خلفَ الصفِّ»"}]'::jsonb, 'a', '«تعظيمًا» مصدر قلبيّ يدلّ على سبب الوقوف، متّحد مع الفعل في الزمن والفاعل — فهو مفعول لأجله منصوب. أمّا «أمامَ» فظرف مكان، و«وقوفًا» مفعول مطلق مؤكِّد.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24be4b4a-ea07-567b-8fdf-aef13d1cc486', '3a0414d1-56e5-50c3-ae38-91a93aca51e0', 'في «اشتريتُ عشرينَ كتابًا»، ما إعراب «كتابًا»؟', '[{"id":"a","text":"تمييز منصوب وعلامة نصبه الفتحة"},{"id":"b","text":"مفعول به منصوب وعلامة نصبه الفتحة"},{"id":"c","text":"مضاف إليه مجرور وعلامة جرّه الكسرة"},{"id":"d","text":"حال منصوب وعلامة نصبه الفتحة"}]'::jsonb, 'a', 'العدد «عشرين» (من 11 إلى 99) يُميَّز بمفرد منصوب، فـ«كتابًا» تمييز ذات منصوب وعلامة نصبه الفتحة يُزيل إبهام العدد.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('817eab45-baf2-584e-aebd-15e49473aebc', '3a0414d1-56e5-50c3-ae38-91a93aca51e0', 'في «سارَ الجنديُّ سيرَ الأبطالِ»، ما نوع «سيرَ» ولماذا؟', '[{"id":"a","text":"مفعول مطلق مبيِّن للنوع لأنّه يصف كيفيّة السير"},{"id":"b","text":"مفعول مطلق مؤكِّد للفعل لأنّه من لفظه"},{"id":"c","text":"مفعول به لأنّه وقع عليه الفعل"},{"id":"d","text":"مفعول مطلق مبيِّن للعدد لأنّه يحدّد المرّات"}]'::jsonb, 'a', '«سيرَ الأبطال» مفعول مطلق مبيِّن للنوع لأنّه يُبيّن صفة السير وكيفيّته (كالأبطال)، لا لمجرّد التأكيد؛ وهو منصوب مضاف و«الأبطالِ» مضاف إليه مجرور.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('572ec24d-bb8e-5d35-9314-2dc2920f6ef1', '3a0414d1-56e5-50c3-ae38-91a93aca51e0', 'أيٌّ من الكلمات الآتية يُعرب تمييز نسبة لا تمييز ذات؟', '[{"id":"a","text":"«كتابًا» في «اشتريتُ عشرينَ كتابًا»"},{"id":"b","text":"«ماءً» في «عندي لتران ماءً»"},{"id":"c","text":"«شوقًا» في «ازدادَ المحبُّ شوقًا»"},{"id":"d","text":"«طالبًا» في «رأيتُ ثلاثةَ طلّابٍ» (تمييز مجرور لا منصوب)"}]'::jsonb, 'c', '«شوقًا» في «ازداد المحبُّ شوقًا» تمييز نسبة لأنّه يُزيل إبهام الجملة كلّها (ماذا ازداد؟)، أمّا «كتابًا» و«ماءً» فتمييز ذات يُزيل إبهام عدد أو مقدار مفرد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5ab3fa4a-69b5-5ed6-a093-fbcbf612e782', '3a0414d1-56e5-50c3-ae38-91a93aca51e0', 'في «ما حضرَ إلّا زيدٌ»، لماذا رُفع «زيدٌ» ولم يُنصب؟', '[{"id":"a","text":"لأنّ الجملة ناقصة منفيّة فيُعرب المستثنى حسب موقعه (فاعل مرفوع)"},{"id":"b","text":"لأنّ المستثنى بعد النفي يجب رفعه دائمًا"},{"id":"c","text":"لأنّ «إلّا» في الجملة المنفيّة لا تعمل"},{"id":"d","text":"لأنّ «زيد» معرفة فلا يُنصب"}]'::jsonb, 'a', 'الجملة ناقصة (لم يُذكر المستثنى منه)، فيُعرب ما بعد «إلّا» حسب موقعه من الجملة: «ما حضرَ إلّا زيدٌ» — «زيدٌ» فاعل مرفوع بالضمّة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('5942675f-5063-565d-a33b-9715493c48b3', '7ffcf241-6fe1-5136-87ff-53ecbdbbdaeb', 'arabic', '👑 تحدّي النخبة: المنصوبات — دقائق الإعراب', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7fb75c28-12c7-59a5-be95-5d49608f7b3f', '5942675f-5063-565d-a33b-9715493c48b3', 'في الجملة «غلا السعرُ ذهبًا وفاضَ النهرُ ماءً»، أيٌّ من التحليلَين الآتيَين صحيح، وما الدليل؟', '[{"id":"a","text":"«ذهبًا» و«ماءً» كلاهما تمييز نسبة منصوب، لأنّ الفعلَين «غلا» و«فاضَ» مبهمان في نسبتهما (غلا — ماذا؟، فاضَ — ماذا؟)، والتمييز يُزيل إبهام الجملة لا إبهام مفرد"},{"id":"b","text":"«ذهبًا» حال منصوب لأنّ السعر يشبه الذهب، و«ماءً» تمييز ذات لأنّه يُزيل إبهام كميّة النهر"},{"id":"c","text":"«ذهبًا» تمييز ذات لأنّه يأتي بعد اسم مبهم، و«ماءً» مفعول به لأنّ «فاضَ» فعل متعدٍّ"},{"id":"d","text":"كلاهما مفعول مطلق مبيِّن للنوع لأنّ كليهما يصف كيفيّة وقوع الفعل"}]'::jsonb, 'a', '«غلا السعرُ ذهبًا» الفعل «غلا» تامّ لكنّه مبهم في نسبته: بماذا غلا؟ فـ«ذهبًا» يُزيل الإبهام عن الجملة — وهو بالضبط تعريف تمييز النسبة. كذلك «فاضَ النهرُ ماءً»: بماذا فاضَ؟ فـ«ماءً» تمييز نسبة منصوب. كلاهما مصدره الإبهام في الجملة لا في مفرد، فلا يصحّ جعلهما تمييز ذات ولا حالًا (الحال يُجيب عن «كيف؟» لصاحبه المعرفة). ولا يصحّ جعل «غلا» و«فاضَ» متعدِّيَين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd8d5cae-22c4-5b69-8c03-466898debc29', '5942675f-5063-565d-a33b-9715493c48b3', 'في «ضربتُ اللصَّ ضربتَينِ مؤلمتَينِ»، ما الإعراب الكامل لـ«ضربتَينِ» بما في ذلك نوعه وعلامة نصبه وسبب النيابة؟', '[{"id":"a","text":"مفعول به منصوب وعلامة نصبه الياء لأنّه مثنّى، والألف علامة الرفع فيه"},{"id":"b","text":"مفعول مطلق مبيِّن للعدد منصوب وعلامة نصبه الياء نيابة عن الفتحة، لأنّه مثنّى"},{"id":"c","text":"مفعول مطلق مؤكِّد للفعل منصوب بالفتحة، لأنّه مصدر من لفظ الفعل"},{"id":"d","text":"تمييز منصوب وعلامة نصبه الياء، يُزيل إبهام عدد الضربات"}]'::jsonb, 'b', '«ضربتَين» مفعول مطلق مبيِّن للعدد لأنّه يُحدِّد عدد مرّات وقوع الفعل (مرّتان)، وهو من لفظ الفعل «ضرب». وهو مثنّى فعلامة نصبه الياء نيابة عن الفتحة (لأنّ المثنّى ينصب بالياء وما قبلها مفتوح). ولا يصحّ أن يكون مفعولًا به لأنّ الفعل «ضرب» قد استوفى مفعوله «اللصَّ»، ولا تمييزًا لأنّه من لفظ الفعل ومبيِّن لعدد وقوعه لا مُزيل إبهام اسم مفرد مبهم.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f8cd8ae-d790-581e-8f02-2fb0ff2a051d', '5942675f-5063-565d-a33b-9715493c48b3', 'في الجملة «ما تخلَّفَ عن الدرسِ إلّا طالبٌ مريضٌ»، ما إعراب «طالبٌ» وما السبب التفصيليّ؟', '[{"id":"a","text":"مستثنى منصوب وعلامة نصبه الفتحة، لأنّ الجملة منفيّة والاستثناء وجوبيّ"},{"id":"b","text":"فاعل مرفوع وعلامة رفعه الضمّة، لأنّ الجملة ناقصة منفيّة فيُعرب ما بعد «إلّا» بحسب موقعه"},{"id":"c","text":"بدل مرفوع من الفاعل المحذوف، لأنّ الجملة التامّة المنفيّة تجيز البدل مرفوعًا"},{"id":"d","text":"مستثنى منصوب أو بدل مرفوع، كلاهما جائز لأنّ الجملة تامّة منفيّة"}]'::jsonb, 'b', 'الجملة «ما تخلَّفَ عن الدرسِ» ناقصة: لم يُذكر المستثنى منه (لم يُقَل «ما تخلَّف الطلابُ… إلّا طالبٌ»)، فهي استثناء مفرَّغ. في هذه الحالة لا تعمل «إلّا» بوصفها أداة استثناء، بل تُعرب ما بعدها بحسب موقعه من الجملة: الفعل «تخلَّفَ» يحتاج فاعلًا، فـ«طالبٌ» فاعل مرفوع وعلامة رفعه الضمّة. هذا هو الحكم الحاسم: الجملة الناقصة المنفيّة → ما بعد «إلّا» يُعرب حسب موقعه، ولا يُنصب على الاستثناء.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('676cf0eb-45e7-5c7f-aa7e-2113e3463aac', '5942675f-5063-565d-a33b-9715493c48b3', 'أيٌّ من التراكيب التالية يشتمل على مفعول لأجله صحيح مستوفٍ للشروط الثلاثة، وأيٌّها مرفوض ولماذا؟', '[{"id":"a","text":"«ركضَ الولدُ ركضًا سريعًا نجاةً من الخطرِ»: «نجاةً» مفعول لأجله، وهو مستوفٍ للشروط لأنّه مصدر قلبيّ (النجاة تعني التخلّص وهو معنًى نفسيّ) متّحد مع الفعل في الزمن والفاعل"},{"id":"b","text":"«ركضَ الولدُ ركضًا طلبًا للمساعدةِ»: «طلبًا» مفعول لأجله صحيح لأنّ «الطلب» معنًى نفسيّ ذهنيّ"},{"id":"c","text":"«كافأَ المعلّمُ التلاميذَ تشجيعًا على الاجتهادِ»: «تشجيعًا» مفعول لأجله لكنّه مرفوض لأنّ فاعله (المعلّم) يختلف عن فاعل النتيجة (التلاميذ)"},{"id":"d","text":"«جاءَ الأبُ سعادةً برؤيةِ ابنِه»: «سعادةً» مفعول لأجله صحيح لأنّ فعل المجيء وسببه متّحدان زمنًا وفاعلًا"}]'::jsonb, 'd', '«جاءَ الأبُ سعادةً برؤية ابنِه»: «سعادةً» مصدر (1)، قلبيّ يدلّ على معنًى نفسيّ عاطفيّ (2)، وفاعله الأب هو نفسه فاعل «جاء» وزمناهما متّحدان (3) — مستوفٍ للشروط الثلاثة. أمّا «نجاةً» في الخيار أ: «النجاة» نتيجة لا شعور قلبيّ محرِّك للفعل، فهي أقرب لمفعول لأجله مجازيّ مقبول في بعض الآراء لكنّها أضعف. «طلبًا» في ب صحيح أيضًا لكنّه مسبوق بمفعول مطلق فيُربك السياق. «تشجيعًا» في ج صحيح نحويًّا لأنّ فاعل الفعل والمصدر القلبيّ واحد (المعلّم هو من يُشجِّع وهو من كافأ).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4fe7892b-5622-52b0-ad66-7fe8cef5f348', '5942675f-5063-565d-a33b-9715493c48b3', 'في «عادَ الجنودُ مئةً وثمانيةً وأربعينَ جنديًّا منتصرينَ»، ما إعراب «جنديًّا» و«منتصرينَ» على الترتيب؟', '[{"id":"a","text":"«جنديًّا» تمييز منصوب بالفتحة (تمييز العدد المركّب من 11 إلى 99: مفرد منصوب)، و«منتصرينَ» حال منصوب وعلامة نصبه الياء لأنّه جمع مذكّر سالم"},{"id":"b","text":"«جنديًّا» مفعول به منصوب بالفتحة، و«منتصرينَ» حال منصوب بالفتحة"},{"id":"c","text":"«جنديًّا» تمييز مجرور لأنّ العدد المركّب يتبع حكم الأعداد من 3 إلى 10، و«منتصرينَ» تمييز نسبة منصوب"},{"id":"d","text":"«جنديًّا» تمييز منصوب بالفتحة، و«منتصرينَ» مفعول مطلق مبيِّن للنوع لأنّه يصف كيفيّة العودة"}]'::jsonb, 'a', 'العدد 148 مركّب يقع بين 11 و99 (نأخذ الآحاد والعشرات)، فتمييزه مفرد منصوب: «جنديًّا» تمييز ذات منصوب وعلامة نصبه الفتحة. أمّا «منتصرينَ» فنكرة مشتقّة (اسم فاعل) تُبيّن هيئة «الجنود» صاحب الحال وقت العودة، فهو حال منصوب؛ وعلامة نصبه الياء نيابة عن الفتحة لأنّه جمع مذكّر سالم. لا يصحّ جعله مفعولًا مطلقًا لأنّه ليس من لفظ الفعل ولا يدلّ على كيفيّة الفعل ذاته بل على هيئة الفاعل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('953541e2-d500-50c7-b1ea-38463f0d0ac2', '5942675f-5063-565d-a33b-9715493c48b3', 'في الجملة «جلسَ الأستاذُ أمامَ الطلّابِ يومَ الامتحانِ هادئًا»، أعرب الكلمات الثلاث المنصوبة «أمامَ» و«يومَ» و«هادئًا» وحدِّد أيٌّها يصحّ إحلاله بحرف الجرّ «في»؟', '[{"id":"a","text":"«أمامَ» ظرف مكان منصوب يصحّ تقدير «في» معه، و«يومَ» ظرف زمان منصوب يصحّ تقدير «في» معه، و«هادئًا» حال منصوب لا يصحّ تقدير «في» معه"},{"id":"b","text":"الثلاثة ظروف منصوبة يصحّ تقدير «في» مع كلٍّ منها لأنّها جميعًا تدلّ على مكان أو زمان أو حالة"},{"id":"c","text":"«أمامَ» مفعول به منصوب، و«يومَ» مضاف منصوب لا ظرف، و«هادئًا» ظرف حال يصحّ تقدير «في» معه"},{"id":"d","text":"«أمامَ» و«هادئًا» ظرفان منصوبان يصحّ تقدير «في» معهما، و«يومَ» مفعول به منصوب لأنّ الجلوس يقتضي زمنًا"}]'::jsonb, 'a', 'الضابط الجوهريّ: المفعول فيه (الظرف) هو ما يصحّ تقدير حرف الجرّ «في» معه. «أمامَ الطلّابِ»: ظرف مكان منصوب يصحّ قول «في أمامِ الطلّاب» تقديرًا، وهو من الظروف المبهمة الملازمة للنصب. «يومَ الامتحانِ»: ظرف زمان منصوب يصحّ «في يومِ الامتحان» تقديرًا. «هادئًا»: حال منصوب يُبيّن هيئة الأستاذ، ولا يصحّ تقدير «في» معه إذ لا يدلّ على زمان أو مكان، بل على صفة الفاعل. الفارق الحاسم: الظرف يتعلّق بالفعل زمانًا أو مكانًا، والحال يتعلّق بالفاعل أو المفعول هيئةً.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', '7ffcf241-6fe1-5136-87ff-53ecbdbbdaeb', 'arabic', '📝 تدريب مراجعة: المنصوبات', 3, 120, 30, 'boss', 'admin', 5)
