  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8dc09b7c-9e14-554c-b4e6-5b47264bf51a', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'في «شربتُ الماءَ»، ما إعراب «الماءَ»؟', '[{"id":"a","text":"مفعول به منصوب وعلامة نصبه الفتحة"},{"id":"b","text":"فاعل مرفوع بالضمّة"},{"id":"c","text":"حال منصوب"},{"id":"d","text":"تمييز منصوب"}]'::jsonb, 'a', '«الماءَ» وقع عليه فعل الشرب فهو مفعول به منصوب وعلامة نصبه الفتحة الظاهرة. وليس فاعلًا لأنّ الفاعل هو التاء في «شربتُ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb0faa2d-c8aa-5ca1-a6fe-b354bcc1d763', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'أيّ الجمل التالية تحتوي على مفعول مطلق؟', '[{"id":"a","text":"سافرتُ صباحًا"},{"id":"b","text":"اجتهدتُ اجتهادًا"},{"id":"c","text":"قرأتُ كتابًا"},{"id":"d","text":"وقفتُ احترامًا"}]'::jsonb, 'b', '«اجتهادًا» مصدر من لفظ الفعل «اجتهدتُ» يؤكّده، فهو مفعول مطلق منصوب. أمّا «صباحًا» فظرف زمان، و«كتابًا» مفعول به، و«احترامًا» مفعول لأجله.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4c8c7d81-1609-5213-8f33-d0a9e1af1ab0', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'في «عاد الجنودُ منتصرينَ»، ما نوع «منتصرينَ» وعلامة نصبه؟', '[{"id":"a","text":"مفعول به منصوب بالفتحة"},{"id":"b","text":"حال منصوب وعلامة نصبه الياء (جمع مذكّر سالم)"},{"id":"c","text":"تمييز منصوب بالفتحة"},{"id":"d","text":"نعت منصوب بالكسرة"}]'::jsonb, 'b', '«منتصرين» يبيّن هيئة الجنود وقت العودة فهو حال منصوب، وهو جمع مذكّر سالم فعلامة نصبه الياء نيابة عن الفتحة. وليس مفعولًا به لأنّه لم يقع عليه الفعل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('29d79992-2c56-5b6f-9dea-93fdce7f22ef', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'في «جلستُ تحتَ الشجرةِ»، ما إعراب «تحتَ»؟', '[{"id":"a","text":"مفعول لأجله منصوب"},{"id":"b","text":"مفعول مطلق منصوب"},{"id":"c","text":"مفعول فيه (ظرف مكان) منصوب"},{"id":"d","text":"حال منصوب"}]'::jsonb, 'c', '«تحتَ» يدلّ على مكان وقوع الجلوس فهو مفعول فيه (ظرف مكان) منصوب بالفتحة، و«الشجرة» مضاف إليه مجرور. وليس مفعولًا لأجله لأنّه لا يبيّن سبب الفعل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90b712e4-7c3a-544d-9fc0-52c7c2b4f32e', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'في «حضر الطلابُ إلّا طالبًا»، ما إعراب «طالبًا» ولماذا؟', '[{"id":"a","text":"بدل من «الطلاب» مرفوع"},{"id":"b","text":"مستثنى بإلّا منصوب لأنّ الكلام تامّ مثبت"},{"id":"c","text":"فاعل مرفوع"},{"id":"d","text":"تمييز منصوب"}]'::jsonb, 'b', 'الكلام تامّ (ذُكر المستثنى منه «الطلاب») مثبت (لا نفي فيه)، فيجب نصب المستثنى بعد «إلّا»، فـ«طالبًا» مستثنى منصوب بالفتحة. ولو كان الكلام منفيًّا لجاز فيه النصب على الاستثناء أو الإتباع للبدليّة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('20e1cd8f-7099-5a40-8f8a-d22091bf2d7f', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'في «امتلأ الإناءُ ماءً» و«اشتريتُ مترًا قماشًا»، ما القاسم المشترك بين «ماءً» و«قماشًا»؟', '[{"id":"a","text":"كلاهما مفعول به منصوب"},{"id":"b","text":"كلاهما تمييز منصوب يُزيل الإبهام (تمييز ذات/نسبة)"},{"id":"c","text":"كلاهما حال منصوب"},{"id":"d","text":"كلاهما مفعول مطلق"}]'::jsonb, 'b', '«ماءً» تمييز نسبة يُزيل إبهام النسبة (بماذا امتلأ؟)، و«قماشًا» تمييز ذات يُزيل إبهام المقدار (متر من ماذا؟)، وكلاهما اسم نكرة منصوب يُفسّر المبهم. فالقاسم المشترك أنّهما تمييز منصوب لا مفعول به ولا حال.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('e51efe95-c023-52da-9ebf-efa5286abc89', '7ffcf241-6fe1-5136-87ff-53ecbdbbdaeb', 'arabic', '👑 تحدّي المناظرة ⭐⭐⭐⭐: المنصوبات — مفاعيل وحال وتمييز واستثناء', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0df39dfa-9a6a-594d-9ead-2c272219294a', 'e51efe95-c023-52da-9ebf-efa5286abc89', 'في الجملة: «سافرتُ طلبًا للعلمِ»، ما إعراب «طلبًا»؟', '[{"id":"a","text":"مفعول لأجله منصوب بالفتحة"},{"id":"b","text":"مفعول مطلق منصوب"},{"id":"c","text":"حال منصوبة"},{"id":"d","text":"تمييز منصوب"}]'::jsonb, 'a', '«طلبًا» مصدر قلبيّ يبيّن سبب وقوع الفعل «سافرتُ» ويشارك فعلَه في الزمان والفاعل، فهو مفعول لأجله منصوب. ✓ الخطأ الشائع: عدّه مفعولًا مطلقًا (المطلق من لفظ الفعل نفسه: سافرتُ سَفَرًا)؛ أو حالًا (الحال تبيّن الهيئة لا السبب).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fe31dc33-3a62-5f48-bc20-c33620b8dc03', 'e51efe95-c023-52da-9ebf-efa5286abc89', 'قال تلميذ: «في جملة (رجعَ القائدُ منتصرًا) كلمة (منتصرًا) مفعول به». ما الخطأ؟', '[{"id":"a","text":"«منتصرًا» حال منصوبة تبيّن هيئة القائد؛ و«رجعَ» فعل لازم لا مفعول به له"},{"id":"b","text":"لا خطأ، «منتصرًا» مفعول به فعلًا"},{"id":"c","text":"«منتصرًا» تمييز منصوب"},{"id":"d","text":"«منتصرًا» مفعول مطلق"}]'::jsonb, 'a', '«منتصرًا» اسم نكرة منصوب يبيّن هيئة صاحبه (القائد) وقت الرجوع، فهو حال. والفعل «رجعَ» لازم لا ينصب مفعولًا به. (تمرين «صيد الخطأ».) الخطأ الشائع: تسمية كلّ منصوبٍ بعد الفعل مفعولًا به دون النظر إلى معناه (هيئة) ولزوم الفعل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a973bd8-6897-5920-bea2-b114ee294723', 'e51efe95-c023-52da-9ebf-efa5286abc89', 'في الجملة: «جاءَ الطفلُ يبكي»، ما إعراب جملة «يبكي»؟', '[{"id":"a","text":"جملة فعلية في محلّ نصب حال"},{"id":"b","text":"جملة في محلّ رفع نعت"},{"id":"c","text":"جملة في محلّ رفع خبر"},{"id":"d","text":"جملة لا محلّ لها من الإعراب"}]'::jsonb, 'a', 'جاء الطفلُ (معرفة) وجملة «يبكي» بعده تبيّن هيئته حين المجيء، وصاحبها معرفة، فهي جملة حالية في محلّ نصب حال. ✓ الخطأ الشائع: عدّها نعتًا (النعت يتبع نكرة، وصاحبها هنا معرفة)؛ الجملة بعد المعرفة حالٌ وبعد النكرة نعتٌ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3bd677e9-2977-5cd4-bda5-4da0ec260e7c', 'e51efe95-c023-52da-9ebf-efa5286abc89', 'في الجملة: «سِرتُ سيرَ الكرامِ»، ما إعراب «سيرَ»؟', '[{"id":"a","text":"مفعول مطلق منصوب مبيّن للنوع، وهو مضاف"},{"id":"b","text":"مفعول به منصوب"},{"id":"c","text":"ظرف منصوب"},{"id":"d","text":"حال منصوبة"}]'::jsonb, 'a', '«سيرَ» مصدر من لفظ الفعل «سِرتُ»، أُضيف إلى «الكرامِ» فبيّن نوع السير، فهو مفعول مطلق منصوب (مبيّن للنوع) وهو مضاف، و«الكرامِ» مضاف إليه مجرور. ✓ الخطأ الشائع: عدّه مفعولًا به مع أنّ «سار» فعل لازم لا مفعول به له.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c5060aa-d89b-5021-a44d-a08980e689cf', 'e51efe95-c023-52da-9ebf-efa5286abc89', 'في الجملة: «طابَتِ المدينةُ هواءً»، ما إعراب «هواءً» وما أصله؟', '[{"id":"a","text":"تمييز منصوب، محوّل عن فاعل (الأصل: طابَ هواءُ المدينةِ)"},{"id":"b","text":"حال منصوبة"},{"id":"c","text":"مفعول به منصوب"},{"id":"d","text":"مفعول مطلق منصوب"}]'::jsonb, 'a', '«هواءً» اسم نكرة منصوب يزيل إبهام النسبة في الجملة، فهو تمييز نسبة منصوب، وأصله فاعل (طابَ هواءُ المدينةِ) ثمّ حُوّل إلى تمييز لإفادة المبالغة. ✓ الخطأ الشائع: عدّه حالًا؛ التمييز يزيل إبهام الذات أو النسبة، والحال تبيّن الهيئة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('185a0641-8936-5ed9-ba56-0b2c3c479c0f', 'e51efe95-c023-52da-9ebf-efa5286abc89', 'في الجملة: «حضرَ الطلّابُ غيرَ طالبٍ»، ما إعراب «غيرَ» و«طالبٍ»؟', '[{"id":"a","text":"«غيرَ» مستثنى منصوب بالفتحة ; «طالبٍ» مضاف إليه مجرور"},{"id":"b","text":"«غيرَ» حال منصوبة ; «طالبٍ» مضاف إليه"},{"id":"c","text":"«غيرَ» مفعول به ; «طالبٍ» بدل"},{"id":"d","text":"«غيرَ» مبتدأ ; «طالبٍ» خبر"}]'::jsonb, 'a', 'الاستثناء بـ«غير» في كلام تامّ مثبت: تُعرب «غيرَ» إعراب المستثنى بـ«إلّا»، أي منصوبة على الاستثناء، ويُجرّ الاسم بعدها بالإضافة. فـ«غيرَ» مستثنى منصوب، و«طالبٍ» مضاف إليه مجرور. ✓ الخطأ الشائع: رفع «غير» أو نصب «طالب»؛ الاسم بعد «غير» و«سوى» مجرورٌ دائمًا بالإضافة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9d95b6e1-4794-5055-aae8-6955ddf0d606', 'ccaffc76-5b0e-539a-b938-127edf17aa08', 'arabic', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bdf4df9d-47aa-5db9-994d-cba4d0e2893d', '9d95b6e1-4794-5055-aae8-6955ddf0d606', 'ما الفرق بين أسلوب الإغراء وأسلوب التحذير؟', '[{"id":"a","text":"الإغراء يدعو إلى فعل الخير، والتحذير يُبعد عن الشرّ"},{"id":"b","text":"الإغراء للغائب، والتحذير للمخاطَب"},{"id":"c","text":"الإغراء يستخدم «إيّا»، والتحذير لا يستخدمها"},{"id":"d","text":"الإغراء مرفوع، والتحذير منصوب"}]'::jsonb, 'a', 'الإغراء أسلوب يحثّ المخاطَب على أمر محمود (فعل الخير)، أمّا التحذير فيُنبّهه إلى أمر مكروه ليتجنّبه. كلاهما يُنصب فيه الاسم بفعل محذوف وجوبًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf41c62d-4cc4-5571-b2b0-02e8edcff6be', '9d95b6e1-4794-5055-aae8-6955ddf0d606', 'في أسلوب النداء، يُعرب المنادى المضاف على أنّه:', '[{"id":"a","text":"مبنيّ على الضمّ في محلّ نصب"},{"id":"b","text":"منصوب"},{"id":"c","text":"مرفوع بالضمّة"},{"id":"d","text":"مجرور بحرف النداء"}]'::jsonb, 'b', 'المنادى المضاف يُعرب منصوبًا، كـ«يا طالبَ العلمِ»، على خلاف المنادى العلم والنكرة المقصودة اللذَين يُبنيان على الضمّ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d24a486-3e0e-5169-a0ee-fa4c4713e0ff', '9d95b6e1-4794-5055-aae8-6955ddf0d606', 'أداة الاستفهام «هل» تختلف عن الهمزة في أنّها:', '[{"id":"a","text":"تُستخدم للسؤال عن العاقل فقط"},{"id":"b","text":"تُستخدم للسؤال عن الزمان"},{"id":"c","text":"تسأل عن الجملة بجواب نعم أو لا ولا تُستخدم للتعيين"},{"id":"d","text":"تدخل على الأسماء المفردة دون الجمل"}]'::jsonb, 'c', '«هل» تسأل عن الجملة وجوابها نعم أو لا، ولا تُستخدم للتعيين (الاختيار بين شيئين)، بخلاف الهمزة التي تُستخدم للاستفهام عن الجملة والتعيين معًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80e55757-a6fc-5faf-aebf-caf6c7f31ae5', '9d95b6e1-4794-5055-aae8-6955ddf0d606', 'في صيغة التعجّب «أجمِلْ بالسماءِ»، تُعرب «السماءِ» على أنّها:', '[{"id":"a","text":"مفعول به منصوب"},{"id":"b","text":"مضاف إليه مجرور"},{"id":"c","text":"فاعل مرفوع محلًّا مجرور لفظًا"},{"id":"d","text":"خبر مرفوع"}]'::jsonb, 'c', 'في صيغة التعجّب «أفعِلْ به» تكون الباء زائدة، والاسم بعدها فاعل مرفوع محلًّا مجرور لفظًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ff9ef25d-f591-5253-b511-6d81efd260d4', '9d95b6e1-4794-5055-aae8-6955ddf0d606', 'في «نحنُ — العربَ — نُكرم الضيفَ»، ما إعراب «العربَ»؟', '[{"id":"a","text":"مفعول به منصوب"},{"id":"b","text":"بدل من نحن"},{"id":"c","text":"منصوب على الاختصاص بفعل محذوف تقديره أخصّ"},{"id":"d","text":"حال منصوب"}]'::jsonb, 'c', '«العربَ» اسم اختصاص منصوب على الاختصاص بفعل محذوف تقديره «أخصّ»، وهو أسلوب يُخصَّص به ضمير المتكلّم أو المخاطَب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3068696f-694a-58fa-82ef-d8f555c9e779', 'ccaffc76-5b0e-539a-b938-127edf17aa08', 'arabic', 'تمرين: التعرّف على الأساليب النحوية', 2, 75, 15, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
