  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a1d03de4-820b-5bd8-80fa-3c139ff1fe95', '3068696f-694a-58fa-82ef-d8f555c9e779', 'في قولنا «إيّاكَ والكسلَ!»، ما نوع هذا الأسلوب؟', '[{"id":"a","text":"أسلوب إغراء"},{"id":"b","text":"أسلوب اختصاص"},{"id":"c","text":"أسلوب تحذير"},{"id":"d","text":"أسلوب نداء"}]'::jsonb, 'c', '«إيّاكَ والكسلَ» أسلوب تحذير يُنبَّه فيه المخاطَب إلى أمر مكروه (الكسل) ليتجنّبه. «إيّاكَ» ضمير منفصل مفعول به لفعل محذوف تقديره «احذَر».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4159ad95-8876-5f6a-9a53-3ce763847189', '3068696f-694a-58fa-82ef-d8f555c9e779', 'أيّ الجمل التالية تحتوي على أسلوب تعجّب بالصيغة القياسية الأولى (ما أفعلَه)؟', '[{"id":"a","text":"أجمِلْ بالقمرِ!"},{"id":"b","text":"يا لجمالِ القمرِ!"},{"id":"c","text":"كم القمرُ جميلٌ!"},{"id":"d","text":"ما أجملَ القمرَ!"}]'::jsonb, 'd', '«ما أجملَ القمرَ!» هي الصيغة القياسية الأولى للتعجّب: ما (مبتدأ تعجّبيّة) + أجملَ (فعل ماضٍ على وزن أفعَلَ) + القمرَ (مفعول به منصوب). أمّا «أجمِلْ بالقمرِ!» فهي الصيغة الثانية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1709f9da-92da-5523-91d8-0cfdad3dc8a7', '3068696f-694a-58fa-82ef-d8f555c9e779', 'في قولنا «الصِّدقَ الصِّدقَ!»، ما إعراب «الصِّدقَ» الأول؟', '[{"id":"a","text":"مفعول به منصوب بالفتحة وعامله فعل مذكور"},{"id":"b","text":"مُغرى به منصوب بالفتحة وعامله فعل محذوف وجوبًا تقديره الزَم"},{"id":"c","text":"منادى منصوب بالفتحة"},{"id":"d","text":"مبتدأ مرفوع بالضمّة"}]'::jsonb, 'b', '«الصِّدقَ» في أسلوب الإغراء مُغرى به منصوب بالفتحة، وعامله فعل محذوف وجوبًا تقديره «الزَم» أو «عليك»، لأنّ الإغراء يحثّ المخاطَب على فعل محمود.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('11685e0d-79bc-5851-a88b-ff6e367a800e', '3068696f-694a-58fa-82ef-d8f555c9e779', 'في «يا طالبَ العلمِ اجتهدْ»، ما إعراب «طالبَ»؟', '[{"id":"a","text":"منادى منصوب بالفتحة لأنّه مضاف"},{"id":"b","text":"منادى مبنيّ على الضمّ في محلّ نصب"},{"id":"c","text":"مُغرى به منصوب"},{"id":"d","text":"فاعل مرفوع بالضمّة"}]'::jsonb, 'a', '«طالبَ» منادى مضاف فيُعرب منصوبًا بالفتحة، لأنّ المنادى المضاف يُنصب ولا يُبنى. وهو مضاف و«العلمِ» مضاف إليه مجرور.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ffc48f6-1162-55c6-8308-ab17054d876b', '3068696f-694a-58fa-82ef-d8f555c9e779', 'في «نحنُ — العربَ — نُكرم الضيفَ»، ما إعراب «العربَ»؟', '[{"id":"a","text":"مفعول به منصوب بالفتحة"},{"id":"b","text":"منصوب على الاختصاص بفعل محذوف تقديره أخصّ"},{"id":"c","text":"منادى منصوب"},{"id":"d","text":"بدل من الضمير «نحن» مرفوع"}]'::jsonb, 'b', '«العربَ» منصوب على الاختصاص، إذ يُخصَّص به الحكم المسند إلى ضمير المتكلّم «نحن»، وعامله فعل محذوف وجوبًا تقديره «أخصّ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('102df544-69c1-5ca9-b494-a7a5d1cfdcfb', '3068696f-694a-58fa-82ef-d8f555c9e779', 'ما الفرق بين «هل» والهمزة في أسلوب الاستفهام؟', '[{"id":"a","text":"هل للتصديق فقط (جواب نعم/لا)، والهمزة للتصديق والتعيين"},{"id":"b","text":"هل للتعيين والهمزة للتصديق فقط"},{"id":"c","text":"هل تختصّ بالسؤال عن العاقل، والهمزة بغير العاقل"},{"id":"d","text":"هل وهمزة الاستفهام بمعنى واحد لا فرق بينهما"}]'::jsonb, 'a', '«هل» أداة استفهام للتصديق فقط، أي يكون جوابها بنعم أو لا. أمّا همزة الاستفهام فتُستخدم للتصديق وللتعيين (أي للاختيار بين شيئين: أأنتَ فعلتَ أم أخوك؟)، وهي أمّ أدوات الاستفهام.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9bf8d840-480b-5538-8e3a-5dc83c7a4214', 'ccaffc76-5b0e-539a-b938-127edf17aa08', 'arabic', '⚔️ زعيم الفصل: الأساليب النحوية — تحدّي الأستاذ', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24b59f07-e892-5d8d-b996-45e72380e12f', '9bf8d840-480b-5538-8e3a-5dc83c7a4214', 'حدِّد أسلوب «الإغراء» من بين الجمل التالية:', '[{"id":"a","text":"الجِدَّ والمثابرةَ أيّها الطلابُ!"},{"id":"b","text":"إيّاكَ والتهاونَ!"},{"id":"c","text":"نحنُ — الشبابَ — نبني الوطنَ"},{"id":"d","text":"يا أيّها الطلابُ اجتهدوا!"}]'::jsonb, 'a', '«الجِدَّ والمثابرةَ» أسلوب إغراء يحثّ المخاطَب على فعل محمود (الجدّ والمثابرة)، والاسمان منصوبان بفعل محذوف وجوبًا تقديره «الزَموا». أمّا «إيّاكَ والتهاونَ» فهو تحذير، و«نحن — الشبابَ» فهو اختصاص.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a1266f09-f2b1-5d55-87bf-4af1a1473f3b', '9bf8d840-480b-5538-8e3a-5dc83c7a4214', 'في «يا محمّدُ أقبِلْ»، ما إعراب «محمّدُ» تفصيلًا؟', '[{"id":"a","text":"منادى منصوب بالفتحة لأنّه مضاف"},{"id":"b","text":"منادى علم مفرد مبنيّ على الضمّ في محلّ نصب"},{"id":"c","text":"فاعل مرفوع بالضمّة"},{"id":"d","text":"منادى مبنيّ على الكسر في محلّ نصب"}]'::jsonb, 'b', '«محمّدُ» منادى مفرد علم، وحكمه أن يُبنى على الضمّ في محلّ نصب. «يا» حرف نداء مبنيّ لا محلّ له من الإعراب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a52f3540-4a88-5b6f-8566-d337a8c5e6aa', '9bf8d840-480b-5538-8e3a-5dc83c7a4214', 'في «أجمِلْ بالسماءِ!»، ما إعراب «السماءِ» في هذا أسلوب التعجّب؟', '[{"id":"a","text":"مفعول به منصوب"},{"id":"b","text":"مضاف إليه مجرور"},{"id":"c","text":"فاعل مرفوع محلًّا مجرور لفظًا بالباء الزائدة"},{"id":"d","text":"منادى مجرور بحرف النداء"}]'::jsonb, 'c', 'في صيغة «أفعِلْ به» التعجّبية، «الباء» زائدة وما بعدها فاعل مرفوع في المحلّ مجرور لفظًا. فـ«السماءِ» فاعل لـ«أجمِلْ» (الفعل الجامد)، مجرور لفظًا بالباء الزائدة ومرفوع محلًّا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e1971226-359d-59ed-9845-51514c0a53f0', '9bf8d840-480b-5538-8e3a-5dc83c7a4214', 'في «يا رجلًا أعنِّي بحاجتي»، لماذا نُصب المنادى «رجلًا»؟', '[{"id":"a","text":"لأنّه مضاف فيُنصب"},{"id":"b","text":"لأنّه نكرة غير مقصودة فيُنصب"},{"id":"c","text":"لأنّه علم مفرد فيُبنى على الضمّ"},{"id":"d","text":"لأنّه شبيه بالمضاف فيُنصب"}]'::jsonb, 'b', 'المنادى «رجلًا» نكرة غير مقصودة (أي المتكلّم لا يخاطب شخصًا بعينه بل يُنادي أيّ رجل)، فالنكرة غير المقصودة تُنصب بالتنوين. وهي تختلف عن النكرة المقصودة (يا رجلُ) التي تُبنى على الضمّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f3f7012-fad9-5670-9ab3-1ca1ee0fee0d', '9bf8d840-480b-5538-8e3a-5dc83c7a4214', 'ما الشرط المفقود الذي يمنع قول «ما أحمرَ الوردةَ!» بالصيغة القياسية مباشرةً؟', '[{"id":"a","text":"الفعل «احمرَّ» رباعيّ فلا يُصاغ منه التعجّب قياسًا"},{"id":"b","text":"الفعل «احمرَّ» يدلّ على لون فلا يُصاغ منه التعجّب قياسًا"},{"id":"c","text":"الفعل «احمرَّ» جامد فلا يُصاغ منه التعجّب"},{"id":"d","text":"الفعل «احمرَّ» على وزن افعلَّ ولكنّه ثلاثيّ الجذر فيجوز التعجّب منه"}]'::jsonb, 'b', 'من شروط صياغة التعجّب القياسي أن لا يدلّ الفعل على لون أو عيب أو حلية. «احمرَّ» يدلّ على لون (الحمرة) فلا يُصاغ منه التعجّب قياسًا مباشرةً، بل نستعين بفعل مساعد: «ما أشدَّ احمرارَ الوردةِ!»', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdb37151-e123-5c4e-97d5-b69f3b75e554', '9bf8d840-480b-5538-8e3a-5dc83c7a4214', 'في «هل درستَ دروسَك؟» و«أدرستَ دروسَك؟»، ما الفرق الدقيق في الاستعمال؟', '[{"id":"a","text":"«هل» للمستقبل وهمزة الاستفهام للماضي"},{"id":"b","text":"«هل» أقوى تأكيدًا من الهمزة في الاستفهام"},{"id":"c","text":"«هل» تدخل على الأسماء وهمزة الاستفهام تدخل على الأفعال فقط"},{"id":"d","text":"الجملتان للتصديق، لكنّ الهمزة تُفيد التعيين أيضًا خلافًا لـ«هل»"}]'::jsonb, 'd', 'كلتا الجملتين استفهام للتصديق (جوابهما نعم أو لا). الفارق أنّ همزة الاستفهام تُستخدم أيضًا للتعيين (الاختيار بين بديلين: أدرستَ أم لا؟)، بينما «هل» قاصرة على التصديق فقط ولا تدخل في سياق التعيين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('acd6eb5c-3981-5b02-bf6d-8df8daf6641f', 'ccaffc76-5b0e-539a-b938-127edf17aa08', 'arabic', '👑 تحدّي النخبة: دقائق الأساليب وإعرابها', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aef9a0ad-01c2-5c3d-8767-5c5e1002e661', 'acd6eb5c-3981-5b02-bf6d-8df8daf6641f', 'في «نحنُ — المعلّمينَ — نُقدِّر العلمَ»، ما الإعراب الدقيق لـ«المعلّمينَ» وما علامة إعرابه؟', '[{"id":"a","text":"منصوب على الاختصاص بفعل محذوف تقديره «أخصّ»، وعلامة نصبه الياء لأنّه جمع مذكّر سالم"},{"id":"b","text":"بدل من «نحنُ» منصوب بالياء"},{"id":"c","text":"توكيد معنويّ مرفوع بالواو لأنّه جمع مذكّر سالم"},{"id":"d","text":"حال منصوب بالياء من ضمير المتكلّم"}]'::jsonb, 'a', '«المعلّمينَ» اسم اختصاص منصوب على الاختصاص بفعل محذوف وجوبًا تقديره «أخصّ»، وجاء بعد ضمير المتكلّم «نحنُ» لتخصيص الحكم به. وعلامة نصبه الياء نيابةً عن الفتحة لأنّه جمع مذكّر سالم. وليس بدلًا لأنّ البدل لا يُحذف عامله، ولا توكيدًا لأنّ التوكيد يتبع المؤكَّد في إعرابه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd91f1e0-c396-5bb8-b0c9-c50017dbabc8', 'acd6eb5c-3981-5b02-bf6d-8df8daf6641f', 'في «إيّاكَ والكذبَ!»، ما الإعراب الصحيح لـ«إيّاكَ» وما الفعل المقدَّر؟', '[{"id":"a","text":"ضمير منفصل مبنيّ في محلّ رفع مبتدأ، والفعل المقدَّر «احذَر»"},{"id":"b","text":"ضمير منفصل مبنيّ في محلّ جرّ بحرف محذوف"},{"id":"c","text":"ضمير منفصل مبنيّ في محلّ نصب مفعول به لفعل محذوف وجوبًا تقديره «احذَر»"},{"id":"d","text":"ضمير منفصل مبنيّ في محلّ نصب على الإغراء"}]'::jsonb, 'c', '«إيّاكَ» في أسلوب التحذير ضمير منفصل مبنيّ في محلّ نصب مفعول به لفعل محذوف وجوبًا تقديره «احذَر». وفعل التحذير يُحذف وجوبًا مع «إيّا» اتّفاقًا. وليس مبتدأً لأنّ الضمائر المنفصلة قد تقع مفعولًا به، وليس مجرورًا إذ لا حرف جرّ هنا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('afa45a0e-0e4f-5f04-8018-4469055b5d0c', 'acd6eb5c-3981-5b02-bf6d-8df8daf6641f', 'أيّ الجمل التالية يستوفي فعلُها شروطَ التعجّب القياسيّ المباشر (الصيغة: ما أفعلَه / أفعِلْ به)؟', '[{"id":"a","text":"ما أموتَ فلانًا! (من «مات»)"},{"id":"b","text":"ما أحسنَ الفتاةَ! (من «حسُن»)"},{"id":"c","text":"ما أبيضَ الثلجَ! (من «ابيضَّ»)"},{"id":"d","text":"ما أعورَ الرجلَ! (من «عَوِرَ»)"}]'::jsonb, 'b', '«حسُن» فعل ثلاثيّ تامّ متصرّف لا يدلّ على لون ولا عيب وهو قابل للتفاضل، فتستوفي «ما أحسنَ الفتاةَ!» جميع الشروط. أمّا «مات» فجامد في التعجّب (لا يُصاغ منه قياسًا)، و«ابيضَّ» يدلّ على لون على وزن افعلَّ السداسيّ فلا يُصاغ منه مباشرةً، و«عَوِرَ» يدلّ على عيب فلا يُصاغ منه التعجّب قياسًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('22d1aaae-7eef-5df7-8209-c4955f3e392b', 'acd6eb5c-3981-5b02-bf6d-8df8daf6641f', 'في «يا أيّها الطلابُ اجتهدوا!»، ما الإعراب الصحيح لـ«الطلابُ» ولـ«أيّها»؟', '[{"id":"a","text":"«أيّها»: منادى مبنيّ على الضمّ في محلّ نصب؛ «الطلابُ»: بدل أو نعت مرفوع بالضمّة"},{"id":"b","text":"«أيّها»: منادى منصوب بالفتحة لأنّه مضاف؛ «الطلابُ»: مضاف إليه مجرور"},{"id":"c","text":"«أيّها»: حرف نداء؛ «الطلابُ»: منادى مبنيّ على الضمّ"},{"id":"d","text":"«أيّها»: اسم إشارة في محلّ نصب؛ «الطلابُ»: عطف بيان مرفوع"}]'::jsonb, 'a', 'في النداء بـ«يا أيّها»: «أيّ» هي المنادى وتُبنى على الضمّ في محلّ نصب، و«ها» للتنبيه. أمّا «الطلابُ» فهو نعت لـ«أيّ» أو بدل منه، ويجب أن يكون مرفوعًا لأنّ «أيّ» لا تُضاف فعلًا وما بعدها صفة مرفوعة. وهذا ما يُميّز هذا النوع من النداء عن نداء المضاف.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('42fee5e6-ebba-59f2-8bbb-b082518abb07', 'acd6eb5c-3981-5b02-bf6d-8df8daf6641f', 'في جملة «الأمانةَ يا صديقي»، ما الأساليب النحوية الواردة فيها وما إعراب «صديقي»؟', '[{"id":"a","text":"أسلوب تحذير فقط؛ «صديقي»: منادى مضاف منصوب بالفتحة المقدَّرة"},{"id":"b","text":"أسلوب اختصاص فقط؛ «صديقي»: منصوب على الاختصاص"},{"id":"c","text":"أسلوب إغراء فقط؛ «صديقي»: مضاف إليه مجرور بالكسرة"},{"id":"d","text":"أسلوبا إغراء ونداء معًا؛ «صديقي»: منادى مضاف منصوب وعلامة نصبه الفتحة المقدَّرة على ما قبل الياء"}]'::jsonb, 'd', 'تجمع الجملة أسلوبَين: «الأمانةَ» إغراء (مُغرى به منصوب بفعل محذوف وجوبًا تقديره «الزَم») يحثّ المخاطَب على التمسّك بالأمانة، و«يا صديقي» نداء. «صديقي» منادى مضاف منصوب وعلامة نصبه الفتحة المقدَّرة على ما قبل ياء المتكلّم، منَع من ظهورها اشتغالُ المحلّ بحركة المناسبة، والياء ضمير متّصل مضاف إليه في محلّ جرّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de13056c-6dd5-5da7-9b63-d6efb31b7829', 'acd6eb5c-3981-5b02-bf6d-8df8daf6641f', 'أيّ الجمل التالية تمثّل استخدامًا صحيحًا لهمزة الاستفهام دون «هل»، بحيث لا يصحّ استبدالها بـ«هل»؟', '[{"id":"a","text":"أسافرتَ أمس؟"},{"id":"b","text":"أيُّهما أحسنُ خُلُقًا: زيدٌ أم عمرٌو؟"},{"id":"c","text":"أأنتَ كتبتَ الدرسَ؟"},{"id":"d","text":"أفهمتَ الشرحَ؟"}]'::jsonb, 'b', 'الهمزة وحدها تُفيد «التعيين» أي الاختيار بين أمرين أو أكثر بعد «أم». في «أيُّهما أحسنُ خُلُقًا: زيدٌ أم عمرٌو؟» يُطلب تعيين الأحسن بين اثنين، ولا يصحّ هنا استبدال الهمزة بـ«هل» لأنّ «هل» قاصرة على التصديق (جوابه نعم أو لا) ولا تدخل في سياق التعيين. أمّا الجمل الأخرى (أسافرتَ، أأنتَ، أفهمتَ) فهي للتصديق ويمكن نظريًّا صياغتها بـ«هل» وإن تفاوتت في السياق.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'ccaffc76-5b0e-539a-b938-127edf17aa08', 'arabic', '📝 تدريب مراجعة: الأساليب النحوية', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
