  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('feb27f89-41ca-5d2a-9cb3-41a25c52619d', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'في «يا طالبُ اجتهدْ»، ما نوع المنادى «طالبُ» وحكمه؟', '[{"id":"a","text":"نكرة مقصودة مبنيّ على الضمّ في محلّ نصب"},{"id":"b","text":"مضاف منصوب بالفتحة"},{"id":"c","text":"نكرة غير مقصودة منصوب"},{"id":"d","text":"شبيه بالمضاف منصوب"}]'::jsonb, 'a', '«طالبُ» نكرة مقصودة (يُنادى بها طالب معيّن حاضر)، وحكمها البناء على الضمّ في محلّ نصب مثل العلم المفرد. ولو كانت نكرة غير مقصودة لنُصبت بالتنوين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b98146d5-625e-5d11-8d29-b1d9033e283e', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'أيّ الجمل التالية تمثّل أسلوب استفهام؟', '[{"id":"a","text":"ما أروعَ المنظرَ!"},{"id":"b","text":"متى يبدأ الامتحانُ؟"},{"id":"c","text":"يا محمّدُ تعالَ"},{"id":"d","text":"الصدقَ يا أبنائي"}]'::jsonb, 'b', '«متى يبدأ الامتحان؟» أسلوب استفهام يطلب تعيين الزمن بأداة الاستفهام «متى». أمّا الأولى فتعجّب، والثالثة نداء، والرابعة إغراء.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fce6128e-2dff-56e5-af0d-e84ec9ed43f5', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'في «إيّاكَ والكذبَ»، ما الأسلوب وما إعراب «الكذبَ»؟', '[{"id":"a","text":"إغراء، و«الكذب» منصوب بفعل محذوف تقديره الزم"},{"id":"b","text":"تحذير، و«الكذب» منصوب بفعل محذوف تقديره احذر"},{"id":"c","text":"اختصاص، و«الكذب» مفعول به"},{"id":"d","text":"نداء، و«الكذب» منادى"}]'::jsonb, 'b', '«إيّاكَ والكذبَ» أسلوب تحذير يُحذّر من أمر مكروه (الكذب)، و«الكذبَ» منصوب بفعل محذوف وجوبًا تقديره «احذر». ويختلف عن الإغراء الذي يحثّ على أمر محمود.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('00a0477d-0c72-5ad6-b989-2b2716b1154c', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'في «ما أجملَ السماءَ!»، ما إعراب «أجملَ»؟', '[{"id":"a","text":"اسم تفضيل"},{"id":"b","text":"فعل ماضٍ جامد للتعجّب مبنيّ على الفتح"},{"id":"c","text":"فعل أمر مبنيّ على السكون"},{"id":"d","text":"اسم مبنيّ على الفتح"}]'::jsonb, 'b', 'في صيغة «ما أفعلَ» التعجّبية، «أجملَ» فعل ماضٍ جامد للتعجّب مبنيّ على الفتح، و«ما» اسم تعجّب مبتدأ، و«السماءَ» مفعول به منصوب. وليس اسم تفضيل وإن تشابهت الصورة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30e3371a-46e4-5ccd-88b6-c90cc1d034e8', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'في «نحنُ — العربَ — نُكرمُ الضيفَ»، ما إعراب «العربَ»؟', '[{"id":"a","text":"منادى منصوب"},{"id":"b","text":"مفعول به منصوب"},{"id":"c","text":"اسم منصوب على الاختصاص بفعل محذوف تقديره أخصّ"},{"id":"d","text":"بدل من الضمير «نحن» مرفوع"}]'::jsonb, 'c', '«العربَ» اسم منصوب على الاختصاص يأتي بعد ضمير ليُخصّصه ويوضّحه، وهو منصوب بفعل محذوف وجوبًا تقديره «أخصّ» أو «أعني». ولا يُعرب بدلًا لأنّ المختصّ لا يتبع ما قبله في الإعراب بل يُنصب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0927fb33-92a2-5c54-abdc-9140e573a15e', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'أيّ الصيغتين تُمثّل التعجّب القياسي صياغةً صحيحة من الفعل «اجتهد»؟', '[{"id":"a","text":"ما أكثرَ اجتهادَه! / أكثِرْ باجتهادِه!"},{"id":"b","text":"ما أجتهدَه! / أجتهِدْ به!"},{"id":"c","text":"ما اجتهدَه! / اجتهدْ به!"},{"id":"d","text":"ما أجهدَه! / أجهِدْ به!"}]'::jsonb, 'a', '«اجتهد» فعل غير ثلاثي (خماسي)، ولا يُصاغ منه التعجّب مباشرة، فيُتوسَّل بمصدره مع فعل تعجّب مساعد من الثلاثي: «ما أكثرَ اجتهادَه!» و«أكثِرْ باجتهادِه!». فالصياغة المباشرة من الفعل الزائد على الثلاثي غير قياسية.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('400e4036-b8f4-56bf-8097-54b007543c06', 'ccaffc76-5b0e-539a-b938-127edf17aa08', 'arabic', '👑 تحدّي المناظرة ⭐⭐⭐⭐: الأساليب النحوية — مدح وقسم ونداء وشرط وإغراء', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5e14bc92-c244-5cab-8f97-311e57713e15', '400e4036-b8f4-56bf-8097-54b007543c06', 'قال تلميذ: «في (يا محمّدُ اجتهدْ) كلمة (محمّدُ) منادى منصوب». ما الخطأ؟', '[{"id":"a","text":"«محمّدُ» منادى مفرد علم، مبنيّ على الضمّ في محلّ نصب (لا منصوب لفظًا)"},{"id":"b","text":"لا خطأ، «محمّدُ» منصوب بالفتحة"},{"id":"c","text":"«محمّدُ» مرفوع بالضمّة فاعلٌ"},{"id":"d","text":"«محمّدُ» مبتدأ مرفوع"}]'::jsonb, 'a', 'المنادى المفرد العلم (غير المضاف ولا الشبيه بالمضاف) يُبنى على ما يُرفع به في محلّ نصب: «محمّدُ» مبنيّ على الضمّ في محلّ نصب منادى. فهو منصوب المحلّ لا اللفظ. (تمرين «صيد الخطأ».) الخطأ الشائع: نصبه لفظًا لأنّ المنادى مفعول في الأصل، وإهمال أنّه مبنيّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('be99578d-1e3f-59c3-9d11-dc8303100e93', '400e4036-b8f4-56bf-8097-54b007543c06', 'في أسلوب المدح: «نِعمَ الخلقُ الصدقُ»، ما إعراب «الصدقُ»؟', '[{"id":"a","text":"المخصوص بالمدح: مبتدأ مؤخّر مرفوع (وجملة «نِعم الخلقُ» خبر مقدّم)"},{"id":"b","text":"فاعل «نِعم» مرفوع"},{"id":"c","text":"خبر «نِعم» منصوب"},{"id":"d","text":"مفعول به منصوب"}]'::jsonb, 'a', '«نِعمَ» فعل ماضٍ جامد لإنشاء المدح، و«الخلقُ» فاعله، و«الصدقُ» هو المخصوص بالمدح ويُعرب مبتدأ مؤخّرًا مرفوعًا، والجملة الفعلية قبله «نِعم الخلقُ» في محلّ رفع خبر مقدّم. ✓ الخطأ الشائع: عدّ «الصدقُ» فاعلًا ثانيًا لـ«نِعم» (فاعلها هو «الخلقُ»)، أو خبرًا منصوبًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('407b9215-e9db-50fb-af59-e7754f105781', '400e4036-b8f4-56bf-8097-54b007543c06', 'في أسلوب القسم: «واللهِ لأجتهدنَّ»، ما إعراب «الواو» و«اللهِ»؟', '[{"id":"a","text":"«الواو» حرف جرّ وقسم ; «اللهِ» اسم مجرور بواو القسم"},{"id":"b","text":"«الواو» حرف عطف ; «اللهِ» معطوف مجرور"},{"id":"c","text":"«الواو» حالية ; «اللهِ» مبتدأ"},{"id":"d","text":"«الواو» للاستئناف ; «اللهِ» فاعل"}]'::jsonb, 'a', 'الواو هنا واو القسم، وهي حرف جرّ وقسم، و«اللهِ» (لفظ الجلالة) اسم مجرور بها، والجملة بعده «لأجتهدنَّ» جواب القسم. ✓ الخطأ الشائع: عدّ الواو عاطفةً أو حاليّة؛ واو القسم حرف جرّ يخفض الاسم بعده.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('64ffd41e-09e2-5789-89ea-818f05e12bff', '400e4036-b8f4-56bf-8097-54b007543c06', 'في أسلوب النداء: «يا عبدَ اللهِ اجتهدْ»، ما إعراب «عبدَ»؟', '[{"id":"a","text":"منادى مضاف منصوب بالفتحة"},{"id":"b","text":"منادى مبنيّ على الضمّ في محلّ نصب"},{"id":"c","text":"مبتدأ مرفوع"},{"id":"d","text":"منادى مرفوع بالضمّة"}]'::jsonb, 'a', 'المنادى المضاف يُنصب دائمًا: «عبدَ» منادى مضاف منصوب بالفتحة، و«اللهِ» مضاف إليه مجرور. أمّا البناء على الضمّ فيكون للمنادى المفرد العلم لا المضاف. ✓ الخطأ الشائع: بناء المنادى المضاف على الضمّ قياسًا على المفرد العلم؛ الإضافة تُوجب النصب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d63e528-de22-59a2-a100-e6e198066d6b', '400e4036-b8f4-56bf-8097-54b007543c06', 'في أسلوب الشرط: «إنْ تدرسْ تنجحْ»، ما نوع «إنْ» وما إعراب الفعلَين «تدرسْ» و«تنجحْ»؟', '[{"id":"a","text":"«إنْ» أداة شرط جازمة ; «تدرسْ» فعل الشرط مجزوم و«تنجحْ» جوابه مجزوم"},{"id":"b","text":"«إنْ» نافية ; الفعلان مرفوعان"},{"id":"c","text":"«إنْ» أداة شرط غير جازمة ; الفعلان منصوبان"},{"id":"d","text":"«إنْ» زائدة ; «تدرسْ» مجزوم و«تنجحْ» مرفوع"}]'::jsonb, 'a', '«إنْ» أداة شرط جازمة تجزم فعلَين: «تدرسْ» فعل الشرط مجزوم بالسكون، و«تنجحْ» جواب الشرط مجزوم بالسكون. ✓ الخطأ الشائع: جزم فعل الشرط وحده ورفع الجواب؛ «إنْ» تجزم فعلَيها معًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65625db4-ed67-53ae-b2cd-13824b61cea4', '400e4036-b8f4-56bf-8097-54b007543c06', 'في أسلوب الإغراء: «الصدقَ الصدقَ يا بنيَّ»، ما إعراب «الصدقَ» الأولى؟', '[{"id":"a","text":"مفعول به لفعل محذوف وجوبًا تقديره «الزَمِ»، منصوب"},{"id":"b","text":"مبتدأ مرفوع محذوف الخبر"},{"id":"c","text":"منادى منصوب"},{"id":"d","text":"توكيد لفظيّ منصوب"}]'::jsonb, 'a', 'الإغراء إغراءٌ بالمكرَّر «الصدقَ الصدقَ»: تُعرب الأولى مفعولًا به لفعل محذوف وجوبًا تقديره «الزَمِ» (أو «خُذِ»)، والثانية توكيدًا لفظيًّا منصوبًا. ✓ الخطأ الشائع: عدّها مبتدأ أو منادى؛ الإغراء أسلوبٌ فعلُه محذوف والاسم المُغرى به مفعولٌ منصوب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a0438595-3493-5da8-b730-749033eac9b6', '0e711bc7-a998-5955-bb59-5818797e887b', 'arabic', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
