INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8106810a-8721-525f-b876-bab4b4a8f741', 'a0438595-3493-5da8-b730-749033eac9b6', 'ما الأحرف الثلاثة التي يقوم عليها الميزان الصرفي؟', '[{"id":"a","text":"الفاء والعين واللام"},{"id":"b","text":"الألف والواو والياء"},{"id":"c","text":"الهمزة والسين والتاء"},{"id":"d","text":"الميم والنون والراء"}]'::jsonb, 'a', 'الميزان الصرفي يقوم على ثلاثة أحرف: الفاء تقابل الحرف الأصلي الأوّل، والعين تقابل الثاني، واللام تقابل الثالث؛ والأصل فيه «فَعَلَ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bfaa4bc7-ba5d-5e6e-be0e-a1c8cbd03d63', 'a0438595-3493-5da8-b730-749033eac9b6', 'ما وزن الفعل المجرّد الثلاثي «عَلِمَ»؟', '[{"id":"a","text":"فَعَلَ"},{"id":"b","text":"فَعُلَ"},{"id":"c","text":"فَعَّلَ"},{"id":"d","text":"فَعِلَ"}]'::jsonb, 'd', '«عَلِمَ» فعل ثلاثي مجرّد حركة عينه كسرة، فوزنه «فَعِلَ»، وهو أحد أوزان الثلاثي المجرّد الثلاثة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b349c7bf-d1a3-5985-a69d-cfebcbc4fb26', 'a0438595-3493-5da8-b730-749033eac9b6', 'الجملة التذكيرية «سَأَلْتُمُونِيهَا» تجمع حروف الزيادة. ما الغرض منها؟', '[{"id":"a","text":"تُستخدم لحفظ حروف الهجاء بترتيبها"},{"id":"b","text":"تُستخدم للتعرّف على الحروف الزائدة في الكلمة"},{"id":"c","text":"تُستخدم لبناء الجملة الاسمية الصحيحة"},{"id":"d","text":"تُستخدم لتحديد حالة الإعراب"}]'::jsonb, 'b', '«سألتمونيها» جملة تذكيرية تجمع الحروف العشرة التي تُزاد في الكلمات؛ فإذا وُجد في الكلمة حرف من هذه الحروف وليس من جذرها فهو زائد.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24a65b0c-de48-562c-9c00-e8658488048c', 'a0438595-3493-5da8-b730-749033eac9b6', 'ما وزن كلمة «اجْتَمَعَ»؟', '[{"id":"a","text":"فَعَّلَ"},{"id":"b","text":"انْفَعَلَ"},{"id":"c","text":"افْتَعَلَ"},{"id":"d","text":"أَفْعَلَ"}]'::jsonb, 'c', '«اجتمع» جذره (ج م ع) والحرفان الزائدان هما الهمزة في الأوّل والتاء في الرابع، فوزنه «افْتَعَلَ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('81c6d5d2-68c7-5d2a-b21e-34600aa73ea2', 'a0438595-3493-5da8-b730-749033eac9b6', 'وزن «أَفْعَلَ» في الفعل المزيد بحرف واحد يُفيد في الغالب معنى:', '[{"id":"a","text":"المطاوعة (قبول الأثر)"},{"id":"b","text":"المشاركة بين اثنين"},{"id":"c","text":"الطلب والاستدعاء"},{"id":"d","text":"التعدية (جعل الغير يفعل)"}]'::jsonb, 'd', 'وزن «أفعَلَ» يُفيد التعدية غالبًا، أي جعل الغير يفعل الفعل، كـ«أكرمَ زيدٌ الضيفَ» بمعنى جعله كريمًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9f735203-952b-59e2-b286-6928d4ddf273', '0e711bc7-a998-5955-bb59-5818797e887b', 'arabic', 'تمرين: الميزان الصرفي والمجرّد والمزيد', 2, 75, 15, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('771815ee-d1cb-5ff8-9050-c33f3942af1b', '9f735203-952b-59e2-b286-6928d4ddf273', 'ما وزن الفعل «كَتَبَ»؟', '[{"id":"a","text":"فَعِلَ"},{"id":"b","text":"فَعُلَ"},{"id":"c","text":"فَعَلَ"},{"id":"d","text":"أَفْعَلَ"}]'::jsonb, 'c', '«كَتَبَ» فعل ثلاثيّ مجرّد: الكاف مقابل الفاء، والتاء مقابل العين، والباء مقابل اللام، وحركاتها فتح-فتح-فتح. إذن وزنه «فَعَلَ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a499ba69-ef76-5d05-b53c-dd56d54005ce', '9f735203-952b-59e2-b286-6928d4ddf273', 'أيّ الأفعال التالية فعل ثلاثيّ مجرّد؟', '[{"id":"a","text":"ذَهَبَ"},{"id":"b","text":"تَعَلَّمَ"},{"id":"c","text":"اسْتَغْفَرَ"},{"id":"d","text":"أَرْسَلَ"}]'::jsonb, 'a', '«ذَهَبَ» فعل ثلاثيّ مجرّد من الجذر (ذ هـ ب) بلا زيادة ووزنه «فَعَلَ». أمّا «تعلَّم» فمزيد بتاء وتضعيف (تَفَعَّلَ)، و«استغفر» مزيد بثلاثة (اسْتَفْعَلَ)، و«أرسل» مزيد بهمزة (أَفْعَلَ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('369bc86d-868c-580c-bee1-9d0e1c59d894', '9f735203-952b-59e2-b286-6928d4ddf273', 'حروف الزيادة العشرة مجموعة في أيّ الجمل التذكيريّة؟', '[{"id":"a","text":"ما أجمل صوتها"},{"id":"b","text":"أمان وسلامة"},{"id":"c","text":"هيّا نتعلّم معًا"},{"id":"d","text":"سَأَلْتُمُونِيهَا"}]'::jsonb, 'd', 'حروف الزيادة العشرة (سين، همزة، لام، تاء، ميم، واو، نون، ياء، هاء، ألف) مجموعة في الجملة التذكيريّة «سَأَلْتُمُونِيهَا». كلّ حرف من هذه يمكن أن يكون زائدًا إذا لم يكن من أصل الجذر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('448a6499-4b96-5017-b5c7-fd980c73b962', '9f735203-952b-59e2-b286-6928d4ddf273', 'ما وزن الفعل «أَكْرَمَ»؟', '[{"id":"a","text":"فَعَّلَ"},{"id":"b","text":"أَفْعَلَ"},{"id":"c","text":"فَاعَلَ"},{"id":"d","text":"انْفَعَلَ"}]'::jsonb, 'b', 'جذر «أكرم» هو (ك ر م)، وزيادته الهمزة في أوّله. فالكاف مقابل الفاء وهو ساكن، والراء مقابل العين مفتوحة، والميم مقابل اللام مفتوحة. وزنه «أَفْعَلَ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7bc5214d-d379-55df-a17c-f01cdce8356b', '9f735203-952b-59e2-b286-6928d4ddf273', 'ما الحروف الزائدة في «انْكَسَرَ»؟', '[{"id":"a","text":"الألف والنون"},{"id":"b","text":"الهمزة والنون"},{"id":"c","text":"الهمزة والسين"},{"id":"d","text":"الهمزة فقط"}]'::jsonb, 'b', 'جذر «انكسر» هو (ك س ر). الحروف في الكلمة هي: همزة - نون - كاف - سين - راء. الكاف والسين والراء هي الجذر، إذن الهمزة والنون زائدتان. وزنه «انْفَعَلَ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('613573fe-600d-5c85-9304-64491a5920b7', '9f735203-952b-59e2-b286-6928d4ddf273', 'ما وزن «اجْتَمَعَ»؟', '[{"id":"a","text":"انْفَعَلَ"},{"id":"b","text":"افْتَعَلَ"},{"id":"c","text":"اسْتَفْعَلَ"},{"id":"d","text":"تَفَاعَلَ"}]'::jsonb, 'b', 'جذر «اجتمع» هو (ج م ع). الحروف: همزة - جيم - تاء - ميم - عين. الجيم مقابل الفاء، والميم مقابل العين، والعين مقابل اللام. الزائدان هما الهمزة والتاء في الموضع الثاني. وزنه «افْتَعَلَ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('7976d2b4-e83d-58d9-8a37-5ccd181ac151', '0e711bc7-a998-5955-bb59-5818797e887b', 'arabic', '⚔️ زعيم الفصل: الميزان الصرفي — تحدّي الصرف الأكبر', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4a14104-4416-5212-a515-df1e97624d88', '7976d2b4-e83d-58d9-8a37-5ccd181ac151', 'ما المعنى الصرفيّ الغالب لوزن «انْفَعَلَ» مثل «انكسرَ» و«انقطعَ»؟', '[{"id":"a","text":"التعدية، أي جعل الغير يفعل الفعل"},{"id":"b","text":"الطلب، أي طلب حدوث الفعل"},{"id":"c","text":"المشاركة بين اثنين"},{"id":"d","text":"المطاوعة، أي قبول الأثر وقوعًا على المفعول"}]'::jsonb, 'd', 'وزن «انفعل» يدلّ غالبًا على **المطاوعة**: أي أنّ الشيء قبِل الأثر الواقع عليه. «انكسرَ الزجاجُ» أي طاوع الكسرَ، و«انقطعَ الحبلُ» أي طاوع القطعَ. فهو مقابل «كسرَ / قطعَ» المتعدّيَين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a776ef9-d363-5b0f-9d0f-cd2df17dc29d', '7976d2b4-e83d-58d9-8a37-5ccd181ac151', 'أيّ الأفعال التالية على وزن «فَعِلَ» (بكسر العين)؟', '[{"id":"a","text":"فَرِحَ"},{"id":"b","text":"كَتَبَ"},{"id":"c","text":"كَرُمَ"},{"id":"d","text":"أَكَلَ"}]'::jsonb, 'a', '«فَرِحَ»: الفاء مفتوحة، والراء مكسورة (مقابل العين)، والحاء مفتوحة — وزنه «فَعِلَ» بكسر العين. أمّا «كتبَ» و«أكلَ» فعلى «فَعَلَ» بفتح العين، و«كرُم» على «فَعُلَ» بضمّ العين.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cbaea361-268e-5742-8759-7a7f759941d0', '7976d2b4-e83d-58d9-8a37-5ccd181ac151', 'ما وزن «اسْتَخْرَجَ»، وما الحروف الزائدة فيه؟', '[{"id":"a","text":"وزنه افْتَعَلَ، والزائد الهمزة والتاء"},{"id":"b","text":"وزنه انْفَعَلَ، والزائد الهمزة والنون"},{"id":"c","text":"وزنه أَفْعَلَ، والزائد الهمزة فقط"},{"id":"d","text":"وزنه اسْتَفْعَلَ، والزائد الهمزة والسين والتاء"}]'::jsonb, 'd', 'جذر «استخرج» هو (خ ر ج). الكلمة: همزة - سين - تاء - خاء - راء - جيم. الخاء مقابل الفاء، والراء مقابل العين، والجيم مقابل اللام. الزائدات هي الهمزة في الأوّل، والسين بعدها، والتاء ثالثًا. الوزن: «اسْتَفْعَلَ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a1faccb-c941-556f-aa9c-ad4588c238ae', '7976d2b4-e83d-58d9-8a37-5ccd181ac151', 'ما وزن الفعل «دَحْرَجَ»؟', '[{"id":"a","text":"فَعَّلَ"},{"id":"b","text":"فَاعَلَ"},{"id":"c","text":"فَعْلَلَ"},{"id":"d","text":"أَفْعَلَ"}]'::jsonb, 'c', '«دَحْرَجَ» فعل رباعيّ مجرّد: جذره (د ح ر ج) بأربعة أحرف أصليّة كلّها. الدال مقابل الفاء، والحاء مقابل العين، والراء مقابل اللام الأولى، والجيم مقابل اللام الثانية. وزنه «فَعْلَلَ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9524e0cb-8a17-5b0d-9a84-483e2973696f', '7976d2b4-e83d-58d9-8a37-5ccd181ac151', 'ما وزن «تَقَاتَلَ»، وما الحرفان الزائدان فيه؟', '[{"id":"a","text":"تَفَعَّلَ، والزائدان التاء وتضعيف العين"},{"id":"b","text":"افْتَعَلَ، والزائدان الهمزة والتاء"},{"id":"c","text":"تَفَاعَلَ، والزائدان التاء والألف"},{"id":"d","text":"فَاعَلَ، والزائد الألف فقط"}]'::jsonb, 'c', 'جذر «تقاتل» هو (ق ت ل). الكلمة: تاء - قاف - ألف - تاء - لام. القاف مقابل الفاء، والتاء الأصليّة مقابل العين، واللام مقابل اللام. الزائدان هما التاء في الأوّل والألف بين الفاء والعين. الوزن: «تَفَاعَلَ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('be358054-4e8f-5452-9a52-c372e833da72', '7976d2b4-e83d-58d9-8a37-5ccd181ac151', 'الفعل «تَكَسَّرَ» مزيد بحرفين، أيّهما؟', '[{"id":"a","text":"الهمزة والتاء (وزنه افْتَعَلَ)"},{"id":"b","text":"التاء وتضعيف العين (وزنه تَفَعَّلَ)"},{"id":"c","text":"التاء والألف (وزنه تَفَاعَلَ)"},{"id":"d","text":"الهمزة والنون (وزنه انْفَعَلَ)"}]'::jsonb, 'b', 'جذر «تكسَّر» هو (ك س ر). الكلمة: تاء - كاف - سين (مشدّدة) - راء. الكاف مقابل الفاء، والسين الأولى مقابل العين، والراء مقابل اللام. الزائدان هما التاء في الأوّل وتضعيف السين (العين). الوزن: «تَفَعَّلَ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0a6742b5-e0d5-52fb-a139-6570e057ce7e', '0e711bc7-a998-5955-bb59-5818797e887b', 'arabic', '👑 تحدّي النخبة: دقائق الميزان والإعلال', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('949db6c8-725f-5035-bc66-0f65ac2f3a56', '0a6742b5-e0d5-52fb-a139-6570e057ce7e', 'الفعل «اصْطَفَى» جذره (ص ف ي/و). بعد تطبيق قاعدة الإعلال بالقلب على لامه، ما وزنه الصرفيّ الدقيق؟', '[{"id":"a","text":"افْتَعَلَ، لأنّ اللام محفوظة"},{"id":"b","text":"افْتَعَى، لأنّ الياء في لام الفعل قُلبت ألفًا فصار الوزن المعلّ افْتَعَى"},{"id":"c","text":"افْعَلَّ، لأنّ اللام مشدّدة"},{"id":"d","text":"اسْتَفْعَلَ، لأنّ فيه ثلاثة أحرف زائدة"}]'::jsonb, 'b', 'جذر «اصطفى» هو (ص ف ي): الصاد فاء، والفاء عين، والياء لام. الزائدان: همزة الوصل في الأوّل، والطاء (أصلها تاء افتعل قُلبت طاءً بسبب مجاورة الصاد). أمّا اللام (الياء)، فقد تحرّكت وانفتح ما قبلها فقُلبت ألفًا (إعلال بالقلب). ولذلك يكتب الوزن معلولًا: «افْتَعَى» لا «افْتَعَلَ»، والألف في آخره تقابل الياء المقلوبة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('95b4372c-a2d5-5a6c-903d-c48e90799ad4', '0a6742b5-e0d5-52fb-a139-6570e057ce7e', 'ما الفرق الصرفيّ الدقيق بين «أَقَامَ» و«قَاوَمَ» من حيث الوزن وعدد الأحرف الزائدة؟', '[{"id":"a","text":"كلاهما على وزن «فَاعَلَ» بزيادة الألف فقط"},{"id":"b","text":"«أَقَامَ» على «أَفْعَلَ» بزيادة الهمزة، و«قَاوَمَ» على «فَاعَلَ» بزيادة الألف"},{"id":"c","text":"«أَقَامَ» على «فَاعَلَ» بزيادة الألف، و«قَاوَمَ» على «أَفْعَلَ» بزيادة الهمزة"},{"id":"d","text":"كلاهما على وزن «أَفْعَلَ» بزيادة الهمزة، والألف في كليهما إعلال لا زيادة"}]'::jsonb, 'b', '«أَقَامَ»: جذره (ق و م)، الهمزة زائدة في أوّله والألف في «قَامَ» ليست زائدة بل هي عين الفعل (الواو) قُلبت ألفًا إعلالًا. وزنه «أَفْعَلَ» وأصله «أَقْوَمَ». أمّا «قَاوَمَ»: جذره (ق و م) أيضًا، لكنّ الألف بين القاف والواو هي الحرف الزائد (ألف المفاعلة)، والواو هنا عين الفعل محفوظة. وزنه «فَاعَلَ». الخلاصة: كلٌّ من الكلمتين مزيد بحرف واحد لكنّ الزائد مختلف.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('813bd4e2-fa87-58c0-8c1e-671ce49e87bc', '0a6742b5-e0d5-52fb-a139-6570e057ce7e', 'الفعل «اسْتَقَامَ» مزيد بثلاثة أحرف. ما جذره ووزنه مع بيان موضع الإعلال؟', '[{"id":"a","text":"جذره (ق ي م)، وزنه اسْتَفَالَ، والإعلال في العين بقلب الياء ألفًا"},{"id":"b","text":"جذره (ق و م)، وزنه اسْتَفْعَلَ ولا إعلال فيه"},{"id":"c","text":"جذره (ق و م)، وزنه اسْتَفْعَلَ والألف في «قَام» إعلال للعين (الواو→ألف)، فالوزن المعلّ اسْتَفَالَ"},{"id":"d","text":"جذره (ق م)، وزنه افْتَعَلَ والإعلال في الفاء"}]'::jsonb, 'c', 'جذر «استقام» هو (ق و م). الأحرف الزائدة ثلاثة: همزة الوصل في الأوّل، والسين، والتاء — مجتمعةً تُكوّن بادئة «اسْتَ». الوزن الأصليّ قبل الإعلال: «اسْتَفْعَلَ»، إذ القاف فاء، والواو عين، والميم لام. غير أنّ الواو (عين الفعل) تحرّكت وانفتح ما قبلها فقُلبت ألفًا (إعلال بالقلب)، فصار النطق «اسْتَقَامَ» والوزن المعلّ «اسْتَفَالَ»، وهذا الوزن المعلّ هو الذي يُعدّ الجواب الكامل الدقيق.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdfa76f5-ac19-59b9-8b89-6502614eeff9', '0a6742b5-e0d5-52fb-a139-6570e057ce7e', 'أيّ الأفعال الآتية يُعدّ فعلَ المطاوعة المناسب لـ «عَلَّمَ» على الوزن المتوقَّع صرفيًّا؟', '[{"id":"a","text":"انْعَلَمَ، على وزن انْفَعَلَ"},{"id":"b","text":"تَعَلَّمَ، على وزن تَفَعَّلَ"},{"id":"c","text":"اعْتَلَمَ، على وزن افْتَعَلَ"},{"id":"d","text":"اسْتَعْلَمَ، على وزن اسْتَفْعَلَ"}]'::jsonb, 'b', 'القاعدة الصرفيّة: مطاوع «فَعَّلَ» يأتي على وزن «تَفَعَّلَ». فمطاوع «عَلَّمَ» (فَعَّلَ) هو «تَعَلَّمَ» (تَفَعَّلَ)، ومعناه: قبِل التعليمَ وأثَّر فيه. أمّا «انفعل» فمطاوع «فَعَلَ» الثلاثيّ، و«اسْتَفْعَلَ» يدلّ على الطلب لا المطاوعة، و«افْتَعَلَ» ليس له علاقة صرفيّة مطّردة بمطاوعة «فَعَّلَ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('373f90a2-4443-50f3-a864-832ba079659b', '0a6742b5-e0d5-52fb-a139-6570e057ce7e', 'ما وزن اسم المفعول «مُسْتَخْرَج»، وكيف يُشتقّ من فعله «اسْتَخْرَجَ»؟', '[{"id":"a","text":"مَفْعُول، لأنّ كلّ اسم مفعول على هذا الوزن"},{"id":"b","text":"مُفْتَعَل، لأنّه مشتقّ من «افتعل»"},{"id":"c","text":"مُسْتَفْعَل، بضمّ الميم وفتح العين، لأنّه مشتقّ من «اسْتَفْعَلَ»"},{"id":"d","text":"فَعِيل، كما في كثير من الصفات المشبّهة"}]'::jsonb, 'c', 'تُشتقّ أسماء المفعول من الأفعال المزيدة بإبدال حرف المضارعة ميمًا مضمومةً وفتح ما قبل الآخر. فعل «اسْتَخْرَجَ» وزنه «اسْتَفْعَلَ»؛ مضارعه «يَسْتَخْرِجُ» — نستبدل الياء بميم مضمومة ونفتح ما قبل الآخر: «مُسْتَخْرَج»، ووزنه «مُسْتَفْعَل». وهذا الوزن خاصّ باسم المفعول من «اسْتَفْعَلَ» وليس «مَفْعُول» الذي يُقتصر على الثلاثيّ المجرّد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0abe3a9b-7030-5b6f-b65a-c2f7614708e8', '0a6742b5-e0d5-52fb-a139-6570e057ce7e', 'الفعل «قَالَ» أصله «قَوَلَ» قبل الإعلال. ما وزنه الحقيقيّ قبل الإعلال وما نوع الإعلال الذي طرأ عليه؟', '[{"id":"a","text":"وزنه «فَعَلَ» أصلًا، وطرأ عليه إعلال بالحذف (حُذفت الواو)"},{"id":"b","text":"وزنه «فَعَلَ» أصلًا، وطرأ عليه إعلال بالقلب (الواو→ألف) لتحرّكها وانفتاح ما قبلها"},{"id":"c","text":"وزنه «فَاعَلَ» لأنّ الألف في «قَالَ» زائدة"},{"id":"d","text":"وزنه «فَعِلَ» لأنّ أصله «قَوِلَ» بكسر الواو"}]'::jsonb, 'b', 'أصل «قَالَ» في الميزان الصرفيّ هو «قَوَلَ» على وزن «فَعَلَ»، إذ الجذر (ق و ل): القاف فاء، والواو عين، واللام لام. غير أنّ الواو (عين الفعل) تحرّكت وانفتح ما قبلها (القاف مفتوحة) فوجب قلبها ألفًا — وهذا هو «الإعلال بالقلب». فالألف في «قَالَ» ليست زائدة بل هي عين الفعل بعد الإعلال، ووزنه الحقيقيّ «فَعَلَ» لا «فَاعَلَ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', '0e711bc7-a998-5955-bb59-5818797e887b', 'arabic', '📝 تدريب مراجعة: الميزان الصرفي والمجرّد والمزيد', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a24ff209-0174-5ea7-a1f6-4edc6c4392bf', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'ما وزن الفعل «كَتَبَ»؟', '[{"id":"a","text":"فَعِلَ"},{"id":"b","text":"فَعَلَ"},{"id":"c","text":"فَعُلَ"},{"id":"d","text":"أَفعَلَ"}]'::jsonb, 'b', '«كَتَبَ» فعل ثلاثي مجرّد مفتوح العين: الكاف فاء والتاء عين والباء لام، وكلّها مفتوحة، فوزنه «فَعَلَ». ولو كُسرت العين لكان «فَعِلَ» ولو ضُمّت لكان «فَعُلَ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('633f929b-cbb2-5d1b-bd2f-60dbcc92ee60', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'ما المعنى الصرفيّ الغالب لوزن «فاعَلَ» مثل «قاتلَ» و«شاركَ»؟', '[{"id":"a","text":"المطاوعة"},{"id":"b","text":"المشاركة بين اثنين فأكثر"},{"id":"c","text":"الطلب"},{"id":"d","text":"الصيرورة"}]'::jsonb, 'b', 'وزن «فاعَلَ» يدلّ غالبًا على المشاركة بين طرفين: «قاتلَ» (شارك في القتال) و«شاركَ» و«كاتبَ». ويختلف عن «انفعل» الدالّ على المطاوعة و«استفعل» الدالّ على الطلب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('272ce132-39c4-5714-ba87-676120b21599', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'ما وزن الفعل «أَكرَمَ»، وما الحرف الزائد فيه؟', '[{"id":"a","text":"أَفعَلَ، والزائد الهمزة"},{"id":"b","text":"فَعَّلَ، والزائد تضعيف العين"},{"id":"c","text":"فَاعَلَ، والزائد الألف"},{"id":"d","text":"افتَعَلَ، والزائد التاء"}]'::jsonb, 'a', 'جذر «أكرم» هو (ك ر م)، زِيدت في أوّله همزة قطع. الكاف فاء والراء عين والميم لام، فوزنه «أَفعَلَ» والزائد فيه الهمزة. ووزن «أفعل» يفيد التعدية غالبًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('54959ee1-1a72-5103-8939-a6a6e7c4bb95', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'أيّ الأفعال التالية ثلاثيّ مجرّد؟', '[{"id":"a","text":"استغفرَ"},{"id":"b","text":"تعلّمَ"},{"id":"c","text":"نصرَ"},{"id":"d","text":"انطلقَ"}]'::jsonb, 'c', '«نصرَ» فعل ثلاثي مجرّد أحرفه كلّها أصليّة (ن ص ر) على وزن «فَعَلَ». أمّا «استغفر» و«تعلّم» و«انطلق» فأفعال مزيدة فيها حروف زائدة على الأصل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('451540ac-5426-563a-a3a7-a1eed11c9ae7', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'ما وزن الفعل «اِنكَسَرَ»، وما الحرفان الزائدان فيه؟', '[{"id":"a","text":"افتَعَلَ، والزائدان الهمزة والتاء"},{"id":"b","text":"تَفَاعَلَ، والزائدان التاء والألف"},{"id":"c","text":"انفَعَلَ، والزائدان همزة الوصل والنون"},{"id":"d","text":"استَفعَلَ، والزائدات الهمزة والسين والتاء"}]'::jsonb, 'c', 'جذر «انكسر» هو (ك س ر). الكلمة: همزة وصل - نون - كاف - سين - راء. الكاف فاء والسين عين والراء لام، والزائدان هما همزة الوصل في الأوّل والنون بعدها، فوزنه «انفَعَلَ»، وهو يدلّ على المطاوعة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2d129a7-d540-5300-a162-ea47462701be', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'الفعل «حَوقَلَ» (بمعنى قال: لا حول ولا قوة إلّا بالله) أُلحق بالرباعي المجرّد، فما وزنه؟', '[{"id":"a","text":"فَعّلَ"},{"id":"b","text":"فَوعَلَ"},{"id":"c","text":"فاعَلَ"},{"id":"d","text":"أَفعَلَ"}]'::jsonb, 'b', '«حَوقَلَ» من الأفعال الملحقة بالرباعي (فَعلَلَ)، لكنّه يُوزن بإبقاء حروفه الأصليّة الزائدة في موضعها: الحاء فاء، والواو محسوبة في الميزان كما هي لأنّها زائدة للإلحاق، والقاف عين، واللام لام، فوزنه «فَوعَلَ». فالملحق بالرباعي يُوزن بحروفه لا بـ«فعللَ» مطلقًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('44d9a09a-ca10-5bc8-8221-8f56eec20cfa', '0e711bc7-a998-5955-bb59-5818797e887b', 'arabic', '👑 تحدّي المناظرة ⭐⭐⭐⭐: الصرف والميزان — أوزان وإعلال وإدغام', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6c92f568-71a9-5371-a053-942e688dc8ba', '44d9a09a-ca10-5bc8-8221-8f56eec20cfa', 'ما وزن الفعل «انطلقَ»؟', '[{"id":"a","text":"انفعَلَ"},{"id":"b","text":"افتعَلَ"},{"id":"c","text":"افعلَّ"},{"id":"d","text":"تفعّلَ"}]'::jsonb, 'a', '«انطلقَ» جذره (ط ل ق)، والنون والألف زائدتان في أوّله؛ فنقابل الأصول بـ(ف ع ل) والزائد بلفظه: ا ن ط ل ق = انفعَلَ. ✓ الخطأ الشائع: الخلط بينه وبين «افتعل» (زيادته التاء بعد الفاء، مثل: اجتمع)؛ الميزان يحفظ الزائد في موضعه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8af68e61-d7ca-52b4-9034-5e99f3fa8dc5', '44d9a09a-ca10-5bc8-8221-8f56eec20cfa', 'قال تلميذ: «وزن الفعل (قاتَلَ) هو فَعَّلَ». ما الخطأ؟', '[{"id":"a","text":"وزنه «فاعَلَ»؛ الزيادة ألفٌ بعد الفاء لا تضعيفٌ للعين"},{"id":"b","text":"لا خطأ، وزنه «فعّل»"},{"id":"c","text":"وزنه «أفعل»"},{"id":"d","text":"وزنه «افتعل»"}]'::jsonb, 'a', '«قاتَلَ» جذره (ق ت ل)، والزائد ألفٌ بين الفاء والعين، فوزنه «فاعَلَ». أمّا «فَعَّلَ» فزيادته تضعيفُ العين (مثل: علّم، كسّر). (تمرين «صيد الخطأ».) الخطأ الشائع: الخلط بين ألف «فاعَلَ» وتضعيف «فعّل».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7ffe3485-2a7f-5780-b3c9-6fac7f04d766', '44d9a09a-ca10-5bc8-8221-8f56eec20cfa', 'الفعل «صامَ» أصله «صَوَمَ». ما نوع التغيير الصرفيّ الذي طرأ عليه؟', '[{"id":"a","text":"إعلال بالقلب: قُلبت الواو ألفًا لتحرّكها وانفتاح ما قبلها"},{"id":"b","text":"إعلال بالحذف: حُذفت الواو"},{"id":"c","text":"إعلال بالتسكين"},{"id":"d","text":"إبدال: أُبدلت الواو تاءً"}]'::jsonb, 'a', 'في «صَوَمَ» تحرّكت الواو (فتحة) وانفتح ما قبلها (الصاد)، فقُلبت ألفًا فصارت «صامَ»؛ وهذا إعلال بالقلب. ✓ الخطأ الشائع: عدّه حذفًا مع أنّ الحرف لم يُحذف بل قُلب ألفًا؛ الوزن يبقى «فَعَلَ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('71aa3e90-0011-57d4-9de6-f03cb278cf8e', '44d9a09a-ca10-5bc8-8221-8f56eec20cfa', 'ما اسم الفاعل من الفعل «استخرجَ»، وعلى أيّ وزن؟', '[{"id":"a","text":"مُستخرِج، على وزن مُستفعِل (بكسر العين)"},{"id":"b","text":"مُستخرَج، على وزن مُستفعَل (بفتح العين)"},{"id":"c","text":"مُستخرِج، على وزن مُفتعِل"},{"id":"d","text":"خارِج، على وزن فاعِل"}]'::jsonb, 'a', 'اسم الفاعل من غير الثلاثيّ يُصاغ من مضارعه بإبدال حرف المضارعة ميمًا مضمومة وكسر ما قبل الآخر: يستخرِج ← مُستخرِج، على وزن مُستفعِل. ✓ الخطأ الشائع: فتح العين فيصير اسم مفعول «مُستخرَج» (مُستفعَل)؛ الكسر لاسم الفاعل والفتح لاسم المفعول.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92b83991-e648-5ef1-91a5-108a15575acf', '44d9a09a-ca10-5bc8-8221-8f56eec20cfa', 'الأمر من الفعل المثال «وَعَدَ» (مضارعه يَعِدُ) هو «عِدْ». ما التغيير الصرفيّ في «عِدْ»؟', '[{"id":"a","text":"حُذفت فاء الكلمة (الواو) — إعلال بالحذف"},{"id":"b","text":"حُذفت لام الكلمة (الدال)"},{"id":"c","text":"قُلبت الواو ياءً"},{"id":"d","text":"لا تغيير، الأمر «اوعِدْ»"}]'::jsonb, 'a', 'في المثال الواويّ «وَعَدَ» تُحذف الواو (فاء الكلمة) في المضارع «يَعِدُ» لوقوعها بين ياءٍ وكسرة، وتبقى محذوفةً في الأمر «عِدْ»؛ فهذا إعلال بالحذف. ✓ الخطأ الشائع: ظنّ أنّ الأمر «اوعِدْ» بإثبات الواو؛ الواو محذوفة تبعًا للمضارع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c4f8dd53-c0c4-555a-bfbc-30fbf8e69ef5', '44d9a09a-ca10-5bc8-8221-8f56eec20cfa', 'ما وزن الفعل «مدَّ» (وأصله «مَدَدَ»)؟', '[{"id":"a","text":"فَعَلَ (بإدغام المِثلَين)"},{"id":"b","text":"فَعَّلَ"},{"id":"c","text":"فاعَلَ"},{"id":"d","text":"أفعَلَ"}]'::jsonb, 'a', 'أصل «مدَّ» هو «مَدَدَ» على وزن «فَعَلَ»، ثمّ أُدغمت الدال في الدال (المِثلان) فصار «مدَّ»؛ فالوزن «فَعَلَ» لأنّ التضعيف هنا إدغامٌ لأصلَين لا زيادة. ✓ الخطأ الشائع: عدّ التضعيف زيادةً فيُوزَن «فَعَّلَ»؛ الإدغام في المضعّف الثلاثيّ لا يزيد حرفًا على الأصل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

