  ('9d321826-4676-581f-9584-cf2cd824a0fe', 'e8c9404f-97df-59ea-9c72-d1453f8fa7ba', 'arabic', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
