INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('33e67a12-2724-52c3-a780-1e4d271bb6e5', '9d321826-4676-581f-9584-cf2cd824a0fe', 'ما الفرق بين الاسم الجامد والاسم المشتقّ؟', '[{"id":"a","text":"الجامد يقبل التنوين والمشتقّ لا يقبله"},{"id":"b","text":"الجامد لا يُؤخذ من غيره، والمشتقّ مأخوذ من أصل ويتضمّن معنى الوصف أو الحدث"},{"id":"c","text":"الجامد يدلّ على الفعل والمشتقّ يدلّ على الزمان"},{"id":"d","text":"الجامد خاصّ بالأفعال والمشتقّ خاصّ بالأسماء"}]'::jsonb, 'b', 'الجامد اسم لا يُؤخذ من غيره كـ«رجل وشجرة»، أمّا المشتقّ فيُؤخذ من أصل (عادةً المصدر) ويتضمّن معنى الوصف أو الحدث.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0b5b52bc-a91a-544e-abef-2b7b7dca2ee6', '9d321826-4676-581f-9584-cf2cd824a0fe', 'أيٌّ من الأوزان التالية هو وزن اسم التفضيل للمذكّر؟', '[{"id":"a","text":"أَفعَل"},{"id":"b","text":"فَعِيل"},{"id":"c","text":"فَعَّال"},{"id":"d","text":"مِفعَال"}]'::jsonb, 'a', 'اسم التفضيل يأتي على وزن «أفعَل» للمذكّر و«فُعلى» للمؤنّث، كـ«أكبر وكُبرى» و«أحسن وحُسنى».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('25f6a249-6685-5882-a777-9d03f58c79bd', '9d321826-4676-581f-9584-cf2cd824a0fe', 'اسم الآلة «مِفتَاح» على أيّ وزن جاء؟', '[{"id":"a","text":"مِفعَل"},{"id":"b","text":"مِفعَلة"},{"id":"c","text":"مِفعَال"},{"id":"d","text":"فَعَّال"}]'::jsonb, 'c', '«مِفتاح» اسم آلة على وزن «مِفعَال»، وهو أحد الأوزان القياسية الثلاثة لأسماء الآلة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('479bac5b-730e-5483-89cf-b6090feb763b', '9d321826-4676-581f-9584-cf2cd824a0fe', 'اسم الفاعل من الفعل غير الثلاثي (كـ«دَرَّسَ») يُبنى بـ:', '[{"id":"a","text":"وزن فَاعِل"},{"id":"b","text":"وزن مَفعُول"},{"id":"c","text":"ضمّ أوّله وكسر ما قبل آخره"},{"id":"d","text":"ضمّ أوّله وفتح ما قبل آخره"}]'::jsonb, 'c', 'اسم الفاعل من غير الثلاثي يُبنى بضمّ أوّله وكسر ما قبل آخره، كـ«دَرَّسَ ← مُدَرِّس» و«استَعمَلَ ← مُستَعمِل».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('950ce284-e777-5ddd-ae69-f4caabf45dec', '9d321826-4676-581f-9584-cf2cd824a0fe', 'ما الفرق الدلالي بين اسم الفاعل والصفة المشبّهة؟', '[{"id":"a","text":"لا فرق بينهما في الدلالة"},{"id":"b","text":"اسم الفاعل يُبنى من الرباعي فقط، والصفة المشبّهة من الثلاثي"},{"id":"c","text":"اسم الفاعل يدلّ على صفة ثابتة دائمة، والصفة المشبّهة تدلّ على حدث مؤقّت"},{"id":"d","text":"اسم الفاعل يدلّ على حدث مؤقّت، والصفة المشبّهة تدلّ على صفة ثابتة في صاحبها"}]'::jsonb, 'd', 'اسم الفاعل يدلّ على من وقع منه الفعل في وقت محدّد، أمّا الصفة المشبّهة فتدلّ على صفة ثابتة راسخة في صاحبها، كـ«كريم وشجاع وحسن».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9b5c21ee-37e3-50d8-a7c5-ba6a75e2eb01', 'e8c9404f-97df-59ea-9c72-d1453f8fa7ba', 'arabic', 'تمرين: التعرّف على المشتقّات وأوزانها', 2, 75, 15, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('439a46cb-44b9-5308-8d2d-e66deb1fee1b', '9b5c21ee-37e3-50d8-a7c5-ba6a75e2eb01', 'ما وزن اسم الفاعل من الفعل الثلاثي «نَصَرَ»؟', '[{"id":"a","text":"مَفعُول (مَنصُور)"},{"id":"b","text":"فَاعِل (نَاصِر)"},{"id":"c","text":"مِفعَال (مِنصَار)"},{"id":"d","text":"فَعِيل (نَصِير)"}]'::jsonb, 'b', 'اسم الفاعل من الثلاثي يُصاغ قياسًا على وزن «فَاعِل»، فمن «نَصَرَ» نقول «نَاصِر» (من وقع منه النصر). أمّا «مَنصُور» فاسم مفعول (وزن مَفعُول)، و«نَصِير» صفة مشبّهة (فَعِيل)، و«مِنصَار» وزن غير مستعمل لاسم الفاعل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b1bab6b-e7bb-596b-83b3-c57f76830710', '9b5c21ee-37e3-50d8-a7c5-ba6a75e2eb01', 'أيّ الكلمات التالية اسم مفعول صحيح؟', '[{"id":"a","text":"مَكتُوب"},{"id":"b","text":"كَاتِب"},{"id":"c","text":"كَتِيب"},{"id":"d","text":"مِكتَاب"}]'::jsonb, 'a', 'اسم المفعول من الثلاثي يُصاغ على وزن «مَفعُول»، و«مَكتُوب» على هذا الوزن من «كَتَبَ» فهو يدلّ على ما وقع عليه فعل الكتابة. أمّا «كَاتِب» فاسم فاعل (فَاعِل)، و«مِكتَاب» اسم آلة (مِفعَال)، و«كَتِيب» ليس مشتقًّا قياسيًّا لاسم المفعول.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a57be27-7b78-5492-82bc-e73906a3416b', '9b5c21ee-37e3-50d8-a7c5-ba6a75e2eb01', 'ما وزن اسم التفضيل من الفعل «حَسُنَ»؟', '[{"id":"a","text":"أَفعَل (أَحسَن)"},{"id":"b","text":"مَفعُول (مَحسُون)"},{"id":"c","text":"فَاعِل (حَاسِن)"},{"id":"d","text":"فَعِيل (حَسِين)"}]'::jsonb, 'a', 'اسم التفضيل يُصاغ من الثلاثي على وزن «أَفعَل» للدلالة على أنّ شيئًا زاد على غيره في الصفة؛ فمن «حَسُنَ» نقول «أَحسَن» أي أزيد حُسنًا. أمّا «مَحسُون» فليس مستعملًا، و«حَاسِن» اسم فاعل، و«حَسِين» صفة مشبّهة — ولا يدلّ أيٌّ منها على التفضيل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d12af42-8ca0-5491-98cd-9573549b60f0', '9b5c21ee-37e3-50d8-a7c5-ba6a75e2eb01', 'ما نوع الكلمة «مُدَرِّس» في الجملة «المُدَرِّسُ شرحَ الدرسَ»؟', '[{"id":"a","text":"اسم مفعول من غير الثلاثي"},{"id":"b","text":"اسم فاعل من غير الثلاثي (دَرَّسَ)"},{"id":"c","text":"صيغة مبالغة"},{"id":"d","text":"اسم فاعل من الثلاثي"}]'::jsonb, 'b', 'اسم الفاعل من غير الثلاثي يُصاغ من مضارعه بإبدال حرف المضارعة ميمًا مضمومة وكسر ما قبل الآخر؛ فمن «دَرَّسَ ← يُدَرِّس» نقول «مُدَرِّس» بكسر الراء (ما قبل الآخر)، وهو هنا فاعل الفعل «شرحَ» (الذي درّس وشرح). ولو فُتح ما قبل آخره (مُدَرَّس) لصار اسم مفعول، فالكسرة هي التي عيّنته اسمَ فاعل لا اسمَ مفعول ولا صيغةَ مبالغة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1dae3eb0-f7f5-5e50-9fd4-46388fd6f95d', '9b5c21ee-37e3-50d8-a7c5-ba6a75e2eb01', 'أيّ الأوزان التالية يدلّ على صيغة مبالغة للكثرة والشدّة؟', '[{"id":"a","text":"فَاعِل (صَائِم)"},{"id":"b","text":"مَفعُول (مَصُوم)"},{"id":"c","text":"مَفعَل (مَصَام)"},{"id":"d","text":"فَعَّال (صَوَّام)"}]'::jsonb, 'd', 'صيغة المبالغة تدلّ على كثرة الفعل وشدّته، ومن أشهر أوزانها «فَعَّال»؛ فـ«صَوَّام» على هذا الوزن تدلّ على كثرة الصيام (لا مجرّد فاعله). أمّا «صَائِم» فاسم فاعل (فَاعِل) يدلّ على الفعل دون مبالغة، و«مَصُوم» و«مَصَام» ليسا من أوزان المبالغة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d3014313-a3b3-5e0f-be7b-750a2cedd9d9', '9b5c21ee-37e3-50d8-a7c5-ba6a75e2eb01', 'أيّ الكلمات التالية اسم آلة على وزن مِفعَال؟', '[{"id":"a","text":"مِبرَد"},{"id":"b","text":"مِفتَاح"},{"id":"c","text":"مِكنَسة"},{"id":"d","text":"مِقصَّ"}]'::jsonb, 'b', 'اسم الآلة يُصاغ على ثلاثة أوزان قياسية: مِفعَال ومِفعَل ومِفعَلة. و«مِفتَاح» على وزن «مِفعَال» (الميم زائدة والفاء-التاء-الحاء من جذر فَتَحَ)، فهو أداة الفتح. أمّا «مِبرَد» فعلى مِفعَل، و«مِكنَسة» على مِفعَلة، و«مِقصّ» على مِفعَل — فالمطابق لوزن مِفعَال هو «مِفتَاح» وحده.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('88a20df0-483f-51e9-b7a2-ca4a3ea0ddc2', 'e8c9404f-97df-59ea-9c72-d1453f8fa7ba', 'arabic', '⚔️ زعيم الفصل: المشتقّات وأوزانها الدقيقة', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6242b042-aeb4-54d4-b948-bd97235a8a5c', '88a20df0-483f-51e9-b7a2-ca4a3ea0ddc2', 'الكلمة «صَبُور» على أيّ وزن من أوزان صيغ المبالغة؟', '[{"id":"a","text":"فَعَّال"},{"id":"b","text":"مِفعَال"},{"id":"c","text":"فَعِيل"},{"id":"d","text":"فَعُول"}]'::jsonb, 'd', '«صَبُور» على وزن «فَعُول» (الصاد فاء والباء عين والراء لام من جذر صَبَرَ)، وهو من أوزان صيغة المبالغة الدالّة على شدّة الصبر وكثرته لا مجرّد حصوله. ولا يصحّ «فَعَّال» (وزنه صَبَّار وهو موجود لكنّه ليس صورة الكلمة هنا) ولا «مِفعَال» ولا «فَعِيل»، لأنّ بنية «صَبُور» تطابق فَعُول بعينه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad6d74ec-bdef-5b47-926d-d90644216455', '88a20df0-483f-51e9-b7a2-ca4a3ea0ddc2', 'أيّ الكلمات التالية اسم زمان أو مكان؟', '[{"id":"a","text":"مَجلِس"},{"id":"b","text":"جَالِس"},{"id":"c","text":"مَجلُوس"},{"id":"d","text":"جَلَّاس"}]'::jsonb, 'a', 'اسم الزمان والمكان من الثلاثي يُصاغ على «مَفعَل» أو «مَفعِل»؛ و«مَجلِس» على وزن «مَفعِل» (كُسرت عينه لأنّ مضارعه «يَجلِس» مكسور العين)، ويدلّ على مكان الجلوس. أمّا «جَالِس» فاسم فاعل، و«مَجلُوس» اسم مفعول، و«جَلَّاس» صيغة مبالغة — فلا يدلّ أيٌّ منها على المكان.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e0f1c35-7a2c-5d87-94c8-3a9c136d6243', '88a20df0-483f-51e9-b7a2-ca4a3ea0ddc2', 'الكلمة «مِكنَسة» على أيّ وزن من أوزان اسم الآلة؟', '[{"id":"a","text":"مِفعَلة"},{"id":"b","text":"مِفعَال"},{"id":"c","text":"مِفعَل"},{"id":"d","text":"فَعَّال"}]'::jsonb, 'a', '«مِكنَسة» على وزن «مِفعَلة» (الميم زائدة، والكاف-النون-السين من جذر كَنَسَ، ثمّ تاء التأنيث)، وهو أحد أوزان اسم الآلة القياسية الثلاثة (مِفعَال، مِفعَل، مِفعَلة) فهي أداة الكَنس. ولا يطابقها مِفعَال (مِكناس) ولا مِفعَل (مِكنَس) ولا فَعَّال، لأنّ ختمها بالتاء يُعيّن وزن مِفعَلة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a8cdd2d6-aaae-54bf-841a-cceeb408a7ed', '88a20df0-483f-51e9-b7a2-ca4a3ea0ddc2', 'في الجملة «المُستَعمَلُ بِعنايةٍ يدومُ طويلًا»، ما نوع كلمة «المُستَعمَل»؟', '[{"id":"a","text":"اسم فاعل من «استَعمَلَ»"},{"id":"b","text":"اسم مفعول من «استَعمَلَ» (سداسي)"},{"id":"c","text":"صفة مشبّهة"},{"id":"d","text":"اسم زمان"}]'::jsonb, 'b', 'اسم المفعول من غير الثلاثي يُصاغ من مضارعه بميم مضمومة مكان حرف المضارعة وفتح ما قبل الآخر؛ فمن «استَعمَلَ ← يُستَعمَل» نقول «مُستَعمَل» بفتح الميم الثانية (ما قبل الآخر)، فهو ما وقع عليه الاستعمال. ولو كُسر ما قبل الآخر (مُستَعمِل) لصار اسم فاعل (مَن يستعمل)، فالفتحة هي الفارق الحاسم هنا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c2c22e3f-3831-5855-a099-2e879c12395d', '88a20df0-483f-51e9-b7a2-ca4a3ea0ddc2', 'ما الفرق بين «كاتبٌ» و«كَرِيم» من حيث نوع المشتقّ؟', '[{"id":"a","text":"كلاهما اسم فاعل"},{"id":"b","text":"«كاتب» اسم فاعل (حدث مؤقّت)، «كريم» صفة مشبّهة (صفة ثابتة)"},{"id":"c","text":"«كاتب» صفة مشبّهة و«كريم» اسم فاعل"},{"id":"d","text":"كلاهما صفة مشبّهة"}]'::jsonb, 'b', '«كاتب» على وزن فَاعِل فهو اسم فاعل يدلّ على الحدث، أمّا «كَرِيم» على وزن فَعِيل فهو صفة مشبّهة تدلّ على الثبوت والديمومة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e03bd42b-389f-56b8-942e-9e75455368ac', '88a20df0-483f-51e9-b7a2-ca4a3ea0ddc2', 'في «قرأتُ كِتابًا مُثيرًا»، ما نوع «مُثِير»؟', '[{"id":"a","text":"اسم مفعول من الثلاثي"},{"id":"b","text":"اسم فاعل من غير الثلاثي (أَثَارَ)"},{"id":"c","text":"صيغة مبالغة"},{"id":"d","text":"صفة مشبّهة"}]'::jsonb, 'b', '«مُثِير» اسم فاعل من الفعل الرباعي المزيد «أَثَارَ ← يُثِير»، صيغ بميم مضمومة وكسر ما قبل الآخر (الياء)، فدلّ على ما يقوم بالإثارة (الكتاب المثير). ولو فُتح ما قبل آخره (مُثَار) لكان اسم مفعول، وليس صفة مشبّهة لأنّه يدلّ على حدث متجدّد لا صفة ثابتة، ولا صيغة مبالغة لانتفاء وزنها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('8f824bb5-eca9-5bc8-bffc-9f1396773f9d', 'e8c9404f-97df-59ea-9c72-d1453f8fa7ba', 'arabic', '👑 تحدّي النخبة: المشتقّات — مستوى المناظرة', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('77bcd686-ad6f-5612-9474-7815e9d94bec', '8f824bb5-eca9-5bc8-bffc-9f1396773f9d', 'في العبارة «المُستَخدِمُ الماهرُ يُنتِج عملًا مُستَخدَمًا بكفاءة»، كلمتا «مُستَخدِم» و«مُستَخدَم» مشتقّتان من الفعل السداسي «استَخدَمَ». ما الذي يُميَّز بينهما نحويًّا؟', '[{"id":"a","text":"«مُستَخدِم» اسم فاعل (كسر ما قبل الآخر)، و«مُستَخدَم» اسم مفعول (فتح ما قبل الآخر)"},{"id":"b","text":"كلتاهما اسم مفعول، والفرق في الإعراب فقط"},{"id":"c","text":"«مُستَخدِم» صفة مشبّهة، و«مُستَخدَم» اسم فاعل"},{"id":"d","text":"كلتاهما اسم فاعل لأنّ الفعل السداسي لا يبني اسم مفعول"}]'::jsonb, 'a', 'في المشتقّات من غير الثلاثي: اسم الفاعل يُبنى بضمّ أوله وكسر ما قبل آخره (مُستَخدِم)، أمّا اسم المفعول فيُبنى بضمّ أوله وفتح ما قبل آخره (مُستَخدَم). هذا الفرق الحركي الدقيق هو المعيار الوحيد للتمييز بينهما في الأفعال السداسية.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('288d4459-8206-5908-ba90-b2d1dd328b96', '8f824bb5-eca9-5bc8-bffc-9f1396773f9d', 'أيّ الكلمات التالية تنتمي إلى الصفة المشبّهة وليست صيغة مبالغة، مع تعليل الاختيار؟', '[{"id":"a","text":"غَيُور — لأنّه على وزن فَعُول"},{"id":"b","text":"حَذِر — لأنّه على وزن فَعِل"},{"id":"c","text":"عَلِيم — لأنّه على وزن فَعِيل"},{"id":"d","text":"حَسَن — لأنّه على وزن فَعَل"}]'::jsonb, 'd', '«حَسَن» على وزن فَعَل وهو من أوزان الصفة المشبّهة الدالّة على صفة ثابتة راسخة في صاحبها. أمّا «غَيُور» (فَعُول) و«عَلِيم» (فَعِيل) فهما من أوزان صيغ المبالغة المنصوص عليها. وأمّا «حَذِر» (فَعِل) فهو مشترك؛ يُعدّ في الغالب صيغة مبالغة لا صفة مشبّهة لدلالته على شدّة الحذر، في حين يدلّ «حَسَن» على الثبوت لا المبالغة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ae42f8db-d01a-5db9-a1ab-8c8d3b458e7f', '8f824bb5-eca9-5bc8-bffc-9f1396773f9d', 'أيّ الجمل التالية تحتوي على اسم مكان مبنيٍّ من فعل غير ثلاثي على القياس الصحيح؟', '[{"id":"a","text":"«التَّمرُّنُ في المَلعَبِ يُقوِّي الجسمَ» — مَلعَب: اسم مكان من «لَعِبَ» الثلاثي"},{"id":"b","text":"«ذهبَ المريضُ إلى المُستَشفى» — مُستَشفى: اسم مكان من «استَشفى» السداسي"},{"id":"c","text":"«فتحتُ المِفتاحَ» — مِفتاح: اسم مكان من «فَتَحَ»"},{"id":"d","text":"«جلستُ في المَجلُوسِ» — مَجلُوس: اسم مكان من «جَلَسَ»"}]'::jsonb, 'b', 'اسم الزمان والمكان من غير الثلاثي يُبنى كاسم المفعول تمامًا (ضمّ أوله وفتح ما قبل آخره)؛ فـ«مُستَشفى» هو اسم مكان قياسي من الفعل السداسي «استَشفى». أمّا «مَلعَب» فهو من الثلاثي. و«مِفتاح» هو اسم آلة لا اسم مكان. و«مَجلُوس» هو اسم مفعول، إذ يجب أن يكون «مَجلِس» (بكسر اللام) هو اسم المكان.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d5382bef-39dd-5adc-8879-68876f9b735d', '8f824bb5-eca9-5bc8-bffc-9f1396773f9d', 'أراد طالبٌ أن يصوغ اسم تفضيل مباشرًا من الفعل «عَرِجَ» (أي صار أعرج). أيّ الخيارات يصف الحكم الصحيح ويُعلّله؟', '[{"id":"a","text":"يجوز مباشرةً، فيُقال «أَعرَج» على وزن أَفعَل"},{"id":"b","text":"لا يجوز مباشرةً لأنّ دلالته على عيب جسدي، فيُستعاض عنه بـ«أشدّ عَرَجًا»"},{"id":"c","text":"لا يجوز لأنّ الفعل غير ثلاثي"},{"id":"d","text":"لا يجوز لأنّ الفعل منفيّ بطبعه"}]'::jsonb, 'b', 'من شروط بناء اسم التفضيل مباشرةً من الفعل أن لا تكون دلالته الأصلية على لون أو عيب جسدي. «عَرِجَ» يدلّ على العَرَج وهو عيب، فيمتنع قياسًا صياغةُ «أَعرَج» اسمَ تفضيل وإن وُجد «أَعرَج» صفةً مشبّهة بمعنى وصف صاحب العَرَج. والصواب: «أشدّ عَرَجًا» أو «أكثر عَرَجًا» بالتعويض بمصدر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6b3e3b6c-7412-506f-8742-a0e7615fe270', '8f824bb5-eca9-5bc8-bffc-9f1396773f9d', 'في قول الشاعر: «لَيسَ الكَرِيمُ الذي يُعطِي عَطِيَّتَهُ — عن الجَزاءِ، ولكنِ الوهّابُ مَن بَذَلا»، كلمة «الوهّاب» في البيت على أيّ وزن، وما نوعها؟', '[{"id":"a","text":"وزن مِفعَال، اسم آلة"},{"id":"b","text":"وزن فَعَّال، صيغة مبالغة من «وَهَبَ»"},{"id":"c","text":"وزن فَاعِل، اسم فاعل من «وَهَبَ»"},{"id":"d","text":"وزن فَعِيل، صفة مشبّهة"}]'::jsonb, 'b', '«الوهّاب» على وزن فَعَّال (الواو فاء الكلمة، والهاء عينها، والباء لامها)، وهو من أوزان صيغة المبالغة الدالّة على كثرة الوهب والعطاء. ومن هذا الوزن جاء اسم الله «الوهّاب» في القرآن الكريم. ولا ينبغي الخلط بينه وبين «واهب» (اسم فاعل على فَاعِل) الذي يدلّ على حدث مؤقّت لا مبالغة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c97c4a80-12d1-58cc-9aae-3663e3876290', '8f824bb5-eca9-5bc8-bffc-9f1396773f9d', 'طالبٌ يحلّل الجملة: «المُتَفَوِّقُ يَبلُغُ مَنزِلًا مُتَفَوَّقًا فيه». ادَّعى أنّ «مُتَفَوِّق» اسم مفعول و«مُتَفَوَّق» اسم فاعل. ما الحكم الصحيح ولماذا؟', '[{"id":"a","text":"الطالب مصيب؛ فكلا الكلمتين تبدآن بميم مضمومة فالفرق اعتباطي"},{"id":"b","text":"الطالب مخطئ؛ «مُتَفَوِّق» اسم فاعل (كسر ما قبل الآخر) و«مُتَفَوَّق» اسم مفعول (فتح ما قبل الآخر)، كلاهما من الخماسي «تَفَوَّقَ»"},{"id":"c","text":"الطالب مخطئ؛ «مُتَفَوِّق» صفة مشبّهة و«مُتَفَوَّق» اسم زمان"},{"id":"d","text":"الطالب مخطئ؛ «مُتَفَوِّق» و«مُتَفَوَّق» كلتاهما اسم فاعل لأنّ الخماسي لا يبني اسم مفعول"}]'::jsonb, 'b', 'القاعدة الذهبية في المشتقّات من غير الثلاثي: اسم الفاعل يُكسَر ما قبل آخره (مُتَفَوِّق ← كسرة على القاف)، واسم المفعول يُفتَح ما قبل آخره (مُتَفَوَّق ← فتحة على القاف). فالطالب عكس الحكمين. وكلتا الكلمتين مشتقّتان من الفعل الخماسي «تَفَوَّقَ»، وللخماسي والسداسي اسمُ مفعول قياسي.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9884a453-057b-5889-b6ea-db113219d2c2', 'e8c9404f-97df-59ea-9c72-d1453f8fa7ba', 'arabic', '📝 تدريب مراجعة: المشتقّات', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
