  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4fdf2d40-6c5f-54d7-9f80-33f78b29a966', '9884a453-057b-5889-b6ea-db113219d2c2', 'ما الفرق بين الاسم المشتقّ والاسم الجامد؟', '[{"id":"a","text":"المشتقّ مأخوذ من غيره ويدلّ على ذات ومعنى، والجامد لا يُؤخذ من غيره"},{"id":"b","text":"المشتقّ معرب والجامد مبنيّ"},{"id":"c","text":"المشتقّ اسم والجامد فعل"},{"id":"d","text":"لا فرق بينهما"}]'::jsonb, 'a', 'الاسم المشتقّ يُؤخذ من المصدر/الفعل ويدلّ على ذات اقترن بها معنى (كاتب، مكتوب)، أمّا الجامد فلا يُشتقّ من غيره (رجل، حجر). والقول إنّ الفرق إعراب أو نوع كلمة خطأ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5e5312fb-4836-55eb-a1f9-50e3899be301', '9884a453-057b-5889-b6ea-db113219d2c2', 'أيّ الكلمات التالية صيغة مبالغة؟', '[{"id":"a","text":"عالِم"},{"id":"b","text":"علّامة"},{"id":"c","text":"معلوم"},{"id":"d","text":"مَعلَم"}]'::jsonb, 'b', '«علّامة» على وزن «فعّالة» وهي من صيغ المبالغة الدالّة على كثرة العلم وشدّته. أمّا «عالِم» فاسم فاعل، و«معلوم» اسم مفعول، و«معلَم» اسم مكان.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('97aaf915-8a3a-5dcb-b8fa-66cece45dd8a', '9884a453-057b-5889-b6ea-db113219d2c2', 'ما اسم الفاعل من الفعل «نصرَ»؟', '[{"id":"a","text":"مَنصور"},{"id":"b","text":"ناصِر"},{"id":"c","text":"نَصير"},{"id":"d","text":"نَصّار"}]'::jsonb, 'b', 'اسم الفاعل من الثلاثي يُصاغ على وزن «فاعِل»، فمن «نصرَ» نقول «ناصِر» (من يقوم بالنصر). أمّا «منصور» فاسم مفعول، و«نصير» صفة مشبّهة، و«نصّار» صيغة مبالغة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56b18496-fce1-511f-9448-275b8ec60b71', '9884a453-057b-5889-b6ea-db113219d2c2', 'ما وزن اسم المفعول من الفعل الثلاثي «فهمَ»؟', '[{"id":"a","text":"فاهِم (فاعِل)"},{"id":"b","text":"مفهوم (مَفعول)"},{"id":"c","text":"فهيم (فعيل)"},{"id":"d","text":"مِفهام (مِفعال)"}]'::jsonb, 'b', 'اسم المفعول من الثلاثي يُصاغ على وزن «مَفعول»، فمن «فهمَ» نقول «مفهوم» (ما وقع عليه الفهم). أمّا «فاهم» فاسم فاعل، و«فهيم» صفة مشبّهة، و«مفهام» صيغة مبالغة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e581ff11-a60f-5345-8948-a8d609d16be8', '9884a453-057b-5889-b6ea-db113219d2c2', 'في «هذا الطريقُ مُعبَّدٌ»، ما نوع «مُعبَّد» والفارق بينه وبين «مُعبِّد»؟', '[{"id":"a","text":"اسم مفعول من «عبّدَ» بفتح ما قبل الآخر، و«مُعبِّد» اسم فاعل بكسره"},{"id":"b","text":"اسم فاعل بفتح ما قبل الآخر"},{"id":"c","text":"صفة مشبّهة لا فرق فيها"},{"id":"d","text":"صيغة مبالغة"}]'::jsonb, 'a', 'اسم المفعول من غير الثلاثي يُصاغ من المضارع بإبدال حرف المضارعة ميمًا مضمومة وفتح ما قبل الآخر: «يُعبِّد ← مُعبَّد» (ما وقع عليه التعبيد). ولو كُسر ما قبل الآخر «مُعبِّد» لصار اسم فاعل (من يُعبّد). فالفتحة والكسرة هما الفارق.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b95a7a3-b487-55c4-a8ac-ad7670ccd216', '9884a453-057b-5889-b6ea-db113219d2c2', 'في «مَوعِد» و«مِيزان» و«مَلعَب»، أيّ كلمة منها اسم آلة؟', '[{"id":"a","text":"مَوعِد (اسم زمان)"},{"id":"b","text":"مِيزان (اسم آلة على وزن مِفعال)"},{"id":"c","text":"مَلعَب (اسم مكان)"},{"id":"d","text":"جميعها أسماء آلة"}]'::jsonb, 'b', '«مِيزان» اسم آلة على وزن «مِفعال» (أصله مِوزان، أداة الوزن). أمّا «مَوعِد» فاسم زمان على «مَفعِل»، و«مَلعَب» اسم مكان على «مَفعَل»، فلا يدلّ أيّ منهما على آلة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('c6f8005e-d2ed-51e1-8639-7d081879e6ee', 'e8c9404f-97df-59ea-9c72-d1453f8fa7ba', 'arabic', '👑 تحدّي المناظرة ⭐⭐⭐⭐: المشتقّات — اسم فاعل ومفعول ومبالغة وتفضيل وآلة', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b328653-2f6c-5e09-a5bf-d5e03471a59c', 'c6f8005e-d2ed-51e1-8639-7d081879e6ee', 'أيّ الكلمات التالية اسمُ فاعل؟', '[{"id":"a","text":"كاتِب"},{"id":"b","text":"مكتوب"},{"id":"c","text":"مَكتَب"},{"id":"d","text":"كِتاب"}]'::jsonb, 'a', 'اسم الفاعل من الثلاثيّ على وزن «فاعِل»: «كاتِب» من «كتَبَ». أمّا «مكتوب» فاسم مفعول (مفعول)، و«مَكتَب» اسم مكان (مَفعَل)، و«كِتاب» اسم جامد. ✓ الخطأ الشائع: الخلط بين اسم الفاعل واسم المفعول لاشتراك الجذر.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('867db909-8bc3-52b8-83ef-74473c2c0db9', 'c6f8005e-d2ed-51e1-8639-7d081879e6ee', 'قال تلميذ: «كلمة (مَدرسة) اسمُ فاعل من (درَسَ)». ما الخطأ؟', '[{"id":"a","text":"«مَدرسة» اسم مكان على وزن «مَفعَلة»؛ واسم الفاعل من «درَسَ» هو «دارِس»"},{"id":"b","text":"لا خطأ، «مَدرسة» اسم فاعل"},{"id":"c","text":"«مَدرسة» اسم مفعول"},{"id":"d","text":"«مَدرسة» صيغة مبالغة"}]'::jsonb, 'a', '«مَدرسة» اسم مكان (موضع الدراسة) على وزن «مَفعَلة»، لا اسم فاعل؛ واسم الفاعل من الثلاثيّ «درَسَ» هو «دارِس» على وزن «فاعِل». (تمرين «صيد الخطأ».) الخطأ الشائع: عدّ كلّ مبدوءٍ بميمٍ اسمَ فاعل أو مفعول، وإهمال اسم المكان.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aff55ae3-08d9-5ad0-a5a7-decfdf993996', 'c6f8005e-d2ed-51e1-8639-7d081879e6ee', 'ما اسم المفعول من الفعل «أكرمَ»؟', '[{"id":"a","text":"مُكرَم (بفتح الراء)"},{"id":"b","text":"مُكرِم (بكسر الراء)"},{"id":"c","text":"كريم"},{"id":"d","text":"مكروم"}]'::jsonb, 'a', 'اسم المفعول من غير الثلاثيّ يُصاغ من المضارع بإبدال حرف المضارعة ميمًا مضمومة وفتح ما قبل الآخر: يُكرِم ← مُكرَم. ✓ الخطأ الشائع: كسر ما قبل الآخر فيصير اسم فاعل «مُكرِم»؛ الفتح لاسم المفعول والكسر لاسم الفاعل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a7bd88e4-a0cc-5e8a-9236-11d592a24435', 'c6f8005e-d2ed-51e1-8639-7d081879e6ee', 'أيّ الكلمات التالية صيغةُ مبالغة على وزن «فعّال»؟', '[{"id":"a","text":"غفّار"},{"id":"b","text":"غافِر (اسم فاعل)"},{"id":"c","text":"مغفور (اسم مفعول)"},{"id":"d","text":"مَغفِرة (مصدر)"}]'::jsonb, 'a', '«غفّار» صيغة مبالغة على وزن «فعّال» تدلّ على كثرة المغفرة. أمّا «غافِر» فاسم فاعل (فاعِل)، و«مغفور» اسم مفعول، و«مَغفِرة» مصدر ميميّ. ✓ الخطأ الشائع: عدّ «غافِر» مبالغةً؛ المبالغة تدلّ على الكثرة بأوزان مخصوصة (فعّال، مِفعال، فعول، فعيل، فَعِل).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ffda08f3-c6b1-5230-bec5-7c4019f67254', 'c6f8005e-d2ed-51e1-8639-7d081879e6ee', 'الفعل «احمرَّ» يدلّ على لون وهو غير ثلاثيّ، فلا يُصاغ منه اسم تفضيل مباشر. كيف يُعبَّر عن التفضيل منه؟', '[{"id":"a","text":"بذكر اسم تفضيل مساعد ثمّ مصدره تمييزًا: «أشدُّ احمرارًا»"},{"id":"b","text":"«أحمرُ» على وزن أفعل التفضيل"},{"id":"c","text":"«احمرَّ أكثرَ»"},{"id":"d","text":"لا سبيل إلى التفضيل منه إطلاقًا"}]'::jsonb, 'a', 'إذا كان الفعل غير ثلاثيّ أو دالًّا على لون أو عيب، يُتوصَّل إلى التفضيل بذكر اسم تفضيل مساعد مستوفٍ للشروط (أشدّ، أكثر…) ثمّ يؤتى بمصدر الفعل منصوبًا تمييزًا: «أشدُّ احمرارًا». ✓ الخطأ الشائع: صوغ «أحمر» على أنّه تفضيل، وهو صفة مشبّهة للّون لا اسم تفضيل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b2a17e7c-11f9-5722-8c6b-2045f4722468', 'c6f8005e-d2ed-51e1-8639-7d081879e6ee', 'ما نوع كلمة «مِفتاح»، وعلى أيّ وزن هي؟', '[{"id":"a","text":"اسم آلة، على وزن «مِفعال»"},{"id":"b","text":"اسم مكان، على وزن «مَفعال»"},{"id":"c","text":"اسم فاعل، على وزن «فاعِل»"},{"id":"d","text":"مصدر ميميّ، على وزن «مَفعِل»"}]'::jsonb, 'a', '«مِفتاح» اسم آلة (ما يُفتَح به) على وزن «مِفعال» بكسر الميم، وهو أحد أوزان اسم الآلة القياسية (مِفعال، مِفعَل، مِفعَلة). ✓ الخطأ الشائع: عدّه اسم مكان؛ اسم المكان يُفتَح ميمُه (مَفعَل/مَفعِل)، واسم الآلة تُكسَر ميمُه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('17b63a70-7310-5091-ad6c-4a8666f71c38', '3e834f6b-a6c4-5d1b-b962-887db2faa81f', 'arabic', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
