  ('cc89df13-4e9e-55bb-b7f1-ccd8f6c63420', '3e834f6b-a6c4-5d1b-b962-887db2faa81f', 'arabic', 'تمرين: التعرّف على الصور البيانية', 2, 75, 15, 'practice', 'admin', 1)
