  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('45a733d5-529d-5409-b11c-93aa401a4cd7', 'cc89df13-4e9e-55bb-b7f1-ccd8f6c63420', 'في قولنا «محمّدٌ كالأسدِ شجاعةً»، ما نوع هذا التشبيه؟', '[{"id":"a","text":"تشبيه بليغ حُذفت أداته ووجه شبهه"},{"id":"b","text":"تشبيه مجمَل حُذف منه المشبَّه"},{"id":"c","text":"استعارة تصريحية"},{"id":"d","text":"تشبيه مفصَّل (تامّ) ذُكرت فيه الأركان الأربعة"}]'::jsonb, 'd', 'المثال ذكر المشبَّه (محمّد) والمشبَّه به (الأسد) والأداة (الكاف) ووجه الشبه (شجاعةً)، فهو تشبيه مفصَّل (تامّ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fcf0bef8-e35f-53dc-b087-54a28da039e0', 'cc89df13-4e9e-55bb-b7f1-ccd8f6c63420', 'في قولنا «رأيتُ أسدًا يخطبُ في الناسِ»، ما نوع الصورة البيانية؟', '[{"id":"a","text":"استعارة مكنية"},{"id":"b","text":"كناية"},{"id":"c","text":"استعارة تصريحية"},{"id":"d","text":"تشبيه مجمَل"}]'::jsonb, 'c', 'حُذف المشبَّه (الرجل الشجاع) وصُرِّح بالمشبَّه به (أسدًا) في مكانه، وهذا هو تعريف الاستعارة التصريحية.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c5ccf1c6-a169-5fe9-912d-0b6d64e33fa8', 'cc89df13-4e9e-55bb-b7f1-ccd8f6c63420', 'في قولنا «نَثَرَتِ السماءُ دموعَها»، ما نوع الصورة البيانية؟', '[{"id":"a","text":"استعارة تصريحية"},{"id":"b","text":"استعارة مكنية"},{"id":"c","text":"تشبيه بليغ"},{"id":"d","text":"مجاز مرسل"}]'::jsonb, 'b', 'شُبِّهت السماء بإنسان باكٍ، وحُذف المشبَّه به (الإنسان) وأُبقيت لازمته (الدموع)، فهي استعارة مكنية.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a5616303-a323-5a19-9ecf-fae2d3da6cbd', 'cc89df13-4e9e-55bb-b7f1-ccd8f6c63420', 'ما المعنى الكنائي في «فلانٌ كثيرُ الرَّماد»؟', '[{"id":"a","text":"كريم مضياف يُوقد نار الضيافة كثيرًا"},{"id":"b","text":"يُحرق الأشياء كثيرًا"},{"id":"c","text":"يعيش في أرض جافّة"},{"id":"d","text":"يطبخ الطعام دائمًا"}]'::jsonb, 'a', '«كثير الرماد» كناية عن الكرم والضيافة؛ فكثرة الرماد تدلّ على كثرة إيقاد النار لإطعام الضيوف في العرف العربي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5b79674c-7665-5f70-9733-9c79ed31c961', 'cc89df13-4e9e-55bb-b7f1-ccd8f6c63420', 'في «قرأتُ المكتبةَ كلَّها»، ما نوع المجاز وما علاقته؟', '[{"id":"a","text":"استعارة تصريحية"},{"id":"b","text":"مجاز مرسل علاقته المحلّية (ذُكر المحلّ وأُريد ما فيه)"},{"id":"c","text":"مجاز مرسل علاقته الجزئية"},{"id":"d","text":"كناية عن الاجتهاد"}]'::jsonb, 'b', '«المكتبة» مكان (محلّ) ذُكر وأُريد ما فيه (الكتب)، فالعلاقة محلّية والصورة مجاز مرسل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3522d195-2f84-58de-8460-f0ba2295cbe1', '3e834f6b-a6c4-5d1b-b962-887db2faa81f', 'arabic', '⚔️ زعيم الفصل: تحليل الصور البيانية المعمَّقة', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d67381a-7f69-5d99-87e8-c790b777d680', '3522d195-2f84-58de-8460-f0ba2295cbe1', 'ما الفرق الجوهري بين الاستعارة التصريحية والاستعارة المكنية؟', '[{"id":"a","text":"في التصريحية تُذكر الأداة، وفي المكنية تُحذف"},{"id":"b","text":"التصريحية للأشياء والمكنية للأشخاص"},{"id":"c","text":"لا فرق بينهما في الجوهر"},{"id":"d","text":"في التصريحية يُحذف المشبَّه، وفي المكنية يُحذف المشبَّه به وتبقى لازمته"}]'::jsonb, 'd', 'الفرق الجوهري: في التصريحية يُحذف المشبَّه ويُصرَّح بالمشبَّه به. في المكنية يُحذف المشبَّه به وتُذكر إحدى لوازمه دليلًا عليه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6fd7760-828d-5211-88c6-57cb79283947', '3522d195-2f84-58de-8460-f0ba2295cbe1', 'أيّ الأمثلة التالية يمثّل تشبيهًا مجمَلًا؟', '[{"id":"a","text":"«الطالبُ نجمٌ» (حُذفت الأداة ووجه الشبه)"},{"id":"b","text":"«الطالبُ كالنجمِ لمعانًا» (ذُكرت جميع الأركان)"},{"id":"c","text":"«الطالبُ كالنجمِ» (حُذف وجه الشبه)"},{"id":"d","text":"«رأيتُ نجمًا يدرسُ» (استعارة تصريحية)"}]'::jsonb, 'c', 'التشبيه المجمَل هو الذي حُذف منه وجه الشبه فقط، وهذا ما يُمثّله «الطالبُ كالنجمِ» إذ ذُكرت الأداة ولم يُذكر وجه الشبه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e071be0c-d016-54c7-aee1-46d37285812e', '3522d195-2f84-58de-8460-f0ba2295cbe1', 'في قولنا «أَكَلَ القومُ المعركةَ»، ما نوع الصورة البيانية وما علاقتها؟', '[{"id":"a","text":"استعارة تصريحية"},{"id":"b","text":"مجاز مرسل علاقته المحلّية"},{"id":"c","text":"كناية عن الشجاعة"},{"id":"d","text":"مجاز مرسل علاقته السببيّة (السبب هو المعركة وأُريد المسبَّب وهو الغنيمة)"}]'::jsonb, 'd', 'أُريد بـ«المعركة» غنيمتها لا المعركة نفسها، فذُكر السبب (المعركة) وأُريد المسبَّب (الغنيمة)، وهذا مجاز مرسل علاقته السببيّة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4c04b152-8747-54b8-9b93-c77e782ce7e4', '3522d195-2f84-58de-8460-f0ba2295cbe1', 'في قولنا «حدَّثَتني المكتبةُ عن أبطالٍ خالدين»، ما نوع الصورة البيانية؟', '[{"id":"a","text":"استعارة تصريحية"},{"id":"b","text":"تشبيه بليغ"},{"id":"c","text":"استعارة مكنية (شُبِّهت المكتبة بإنسان يُحدِّث، وحُذف المشبَّه به وأُبقي فعله)"},{"id":"d","text":"مجاز مرسل علاقته المحلّية"}]'::jsonb, 'c', 'شُبِّهت المكتبة بإنسان يتحدّث، وحُذف المشبَّه به (الإنسان) وبقيت لازمته (فعل الحديث «حدَّثتني»)، فهي استعارة مكنية.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('26f345cc-822a-5d03-9784-e9e66ecd0be7', '3522d195-2f84-58de-8460-f0ba2295cbe1', 'في قولنا «أعطِ يدَكَ لأخيكَ»، ما نوع المجاز المرسل وما علاقته؟', '[{"id":"a","text":"مجاز مرسل علاقته الجزئية (ذُكر الجزء «اليد» وأُريد الكلّ «الشخص»)"},{"id":"b","text":"مجاز مرسل علاقته الكلّية"},{"id":"c","text":"كناية عن الصداقة"},{"id":"d","text":"استعارة مكنية"}]'::jsonb, 'a', 'ذُكر الجزء (اليد) وأُريد الكلّ (الشخص كاملًا بمساعدته)، وهذا مجاز مرسل علاقته الجزئية.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('238ef40f-969e-5949-8b7d-2206ce6c3b8c', '3522d195-2f84-58de-8460-f0ba2295cbe1', 'في قولنا «هو نؤومُ الضُّحى» عن امرأة مترفة، ما نوع الصورة البيانية وما المعنى الكنائي؟', '[{"id":"a","text":"استعارة تصريحية"},{"id":"b","text":"كناية عن الترف والدلال (لا تعمل مبكرًا لأنّها مخدومة)"},{"id":"c","text":"تشبيه مجمَل"},{"id":"d","text":"مجاز مرسل علاقته ما كان"}]'::jsonb, 'b', '«نؤوم الضحى» كناية عن الترف والدلال؛ المرأة المترفة المدلَّلة لا تضطرّ إلى الاستيقاظ مبكرًا للعمل، فنومها نهارًا دليلٌ على عيشها الرغيد.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('5de50223-ae07-51a5-bcd2-ed9e846ecda0', '3e834f6b-a6c4-5d1b-b962-887db2faa81f', 'arabic', '👑 تحدّي النخبة: الصور البيانية في نصوص أدبية', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba917376-9c77-516d-a1e0-b684f57ef04f', '5de50223-ae07-51a5-bcd2-ed9e846ecda0', 'في قوله تعالى: «وَاشْتَعَلَ الرَّأْسُ شَيْبًا» (مريم: 4)، ما نوع الصورة البيانية وما المحذوف فيها؟', '[{"id":"a","text":"استعارة مكنية؛ شُبِّه الشيبُ بالنار، وحُذف المشبَّه به (النار) وأُبقيت لازمته (فعل «اشتعل»)"},{"id":"b","text":"استعارة تصريحية؛ صُرِّح بالمشبَّه به (الشيب) وحُذف المشبَّه (الرأس)"},{"id":"c","text":"مجاز مرسل علاقته الجزئية؛ ذُكر الرأس وأُريد سائر الجسد"},{"id":"d","text":"تشبيه بليغ؛ الرأس مشبَّه والشيب مشبَّه به وحُذفت الأداة ووجه الشبه"}]'::jsonb, 'a', 'الفعل «اشتعل» من لوازم النار؛ فقد شُبِّه الشيبُ بالنار المشتعلة، وحُذف المشبَّه به (النار) وبقيت لازمته الدالّة عليه، وهو ما يُعرَّف بالاستعارة المكنية. أمّا الخيار (ب) فيعكس الأمر: في التصريحية يُحذف المشبَّه لا المشبَّه به.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d2c618c-74ff-58e9-882e-ec44096abaf9', '5de50223-ae07-51a5-bcd2-ed9e846ecda0', 'قال المتنبي: «أنا الغريقُ فما خوفي من البَلَلِ». ما نوع الصورة البيانية في «أنا الغريق»؟', '[{"id":"a","text":"تشبيه مجمَل؛ ذُكرت الأداة وحُذف وجه الشبه"},{"id":"b","text":"استعارة مكنية؛ حُذف المشبَّه به وبقيت لازمته"},{"id":"c","text":"استعارة تصريحية؛ شبَّه المتنبي نفسه بالغريق وحُذف المشبَّه (نفسُه) وصُرِّح بالمشبَّه به (الغريق)"},{"id":"d","text":"كناية عن الغرق في الهموم"}]'::jsonb, 'c', 'شبَّه المتنبي نفسه (وهو في أشدّ ما يكون من البلاء) بالغريق؛ فحُذف المشبَّه (نفسُه) وصُرِّح بالمشبَّه به (الغريق) مكانه في الكلام، وهذا هو حدّ الاستعارة التصريحية. لو كانت مكنية لذُكر هو (المشبَّه) وبقيت لازمة الغرق دون تصريح به.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a9a6133-f303-5e79-963c-f3152ee0bd73', '5de50223-ae07-51a5-bcd2-ed9e846ecda0', 'في قول الشاعر: «قرأتُ في عيونِهِ خوفًا لا يُقال»، أيّ تحليل يصفُ الصورة البيانية وصفًا دقيقًا؟', '[{"id":"a","text":"كناية عن الخوف الشديد؛ لأنّ العيون تكشف المخفيّ"},{"id":"b","text":"مجاز مرسل علاقته المحلّية؛ ذُكرت العيون (المحلّ) وأُريد ما تُعبّر عنه"},{"id":"c","text":"تشبيه بليغ؛ العيون مشبَّهة بالكتاب وحُذفت الأداة ووجه الشبه"},{"id":"d","text":"استعارة مكنية؛ شُبِّهت العيون بكتاب يُقرأ، وحُذف المشبَّه به (الكتاب) وأُبقيت لازمته (فعل «قرأ»)"}]'::jsonb, 'd', 'الفعل «قرأ» لازمٌ خاصّ بالكتاب؛ فالشاعر شبَّه عيون المحبوب بكتاب تُقرأ منه المشاعر، ثمّ حذف المشبَّه به (الكتاب) وأبقى لازمته (فعل القراءة) دليلًا عليه، فهذه استعارة مكنية. الخيار (ب) يُخطئ لأنّ المجاز المرسل المحلّي يستلزم ذِكر المكان إرادةً لما فيه (كـ«قرأتُ المكتبةَ» أي الكتبَ)، وليس هذا مقصود الشاعر هنا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('287f475d-858c-5f99-b7ef-4e335144dc42', '5de50223-ae07-51a5-bcd2-ed9e846ecda0', 'في قول الشاعر: «رَعَى الغيثُ الزرعَ حتّى أينَعَ»، ما الصورة البيانية ونوعها بدقّة؟', '[{"id":"a","text":"استعارة مكنية؛ شُبِّه الغيثُ براعٍ وحُذف المشبَّه به وأُبقي فعله (رعى)"},{"id":"b","text":"مجاز مرسل علاقته السببيّة؛ ذُكر السبب (الغيث) وأُريد المسبَّب (عمليّة الرعاية الحقيقية للزرع)"},{"id":"c","text":"تشبيه بليغ؛ الغيث مشبَّه والراعي مشبَّه به"},{"id":"d","text":"كناية عن الخصوبة والنماء"}]'::jsonb, 'a', '«رعى» فعلٌ لا يُسنَد حقيقةً إلّا إلى الراعي (إنسان أو حيوان)؛ فقد شُبِّه الغيثُ براعٍ يحنو على زرعه، وحُذف المشبَّه به (الراعي) وأُبقيت لازمته (رعى). هذا بالضبط تعريف الاستعارة المكنية. أمّا الخيار (ب) فمثال على المجاز المرسل السببي يكون في نحو «رعى الغيثُ الزرعَ» بمعنى أنّ الغيث هو السبب في نموّ الزرع لا في رعايته بالمعنى المجازي، وهو تأويل أقلّ دقّةً من الاستعارة المكنية هنا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('437ea3b1-90c3-57a6-8c00-7364a022bbfd', '5de50223-ae07-51a5-bcd2-ed9e846ecda0', 'قال الكاتب عن أستاذه: «إنّه طويلُ الباعِ في العلم، واسعُ الأفق في الفكر». ما نوع «طويل الباع»؟', '[{"id":"a","text":"مجاز مرسل علاقته الجزئية؛ ذُكر الجزء (الباع) وأُريد الكلّ (الشخص)"},{"id":"b","text":"تشبيه مجمَل؛ الأستاذ مشبَّه بالشيء الطويل وحُذف وجه الشبه"},{"id":"c","text":"كناية عن سعة العلم والمعرفة؛ طول الباع لازمٌ يُشير إلى الامتداد والشمول دون أن يُراد معناه الحقيقي حصرًا"},{"id":"d","text":"استعارة تصريحية؛ صُرِّح بالمشبَّه به (الباع) وحُذف المشبَّه"}]'::jsonb, 'c', '«طويل الباع» تعبيرٌ لا يُراد به طول الذراع حقيقةً، بل يُراد به لازم هذا المعنى وهو سعة العلم والتمكّن؛ فهي كناية عن المعرفة الواسعة. والفارق الدقيق عن الخيار (أ): المجاز المرسل الجزئي يستلزم أن يكون الجزء المذكور علاقتُه بالكلّ هي الجزئية المادّية (كـ«أعطِ يدَكَ» أي نفسَكَ)، بينما هنا «الباع» لا يُراد منه جزء الجسد بل يُراد لازمه المعنوي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b284118-a0be-5398-994d-e745a6c2f6f7', '5de50223-ae07-51a5-bcd2-ed9e846ecda0', 'قال تعالى: «إِنَّكَ مَيِّتٌ وَإِنَّهُم مَّيِّتُونَ» (الزمر: 30)، والمخاطَب والقوم لا يزالون أحياءً لحظةَ النزول. ما نوع الصورة البيانية في إطلاق «ميِّت» عليهم؟', '[{"id":"a","text":"استعارة تصريحية؛ حُذف المشبَّه (الفاني) وصُرِّح بالمشبَّه به (الميِّت)"},{"id":"b","text":"كناية عن قِصَر الأجل وقُرب الموت"},{"id":"c","text":"مجاز مرسل علاقته «ما يكون»؛ أُطلقت كلمة «ميِّت» على الحيّ لأنّه سيؤول إلى الموت"},{"id":"d","text":"تشبيه بليغ؛ المخاطَب مشبَّه بالميِّت وحُذفت الأداة ووجه الشبه"}]'::jsonb, 'c', 'المخاطَب حيٌّ وقتَ الخطاب، غير أنّ الآية أطلقت عليه «ميِّت» بناءً على ما سيؤول إليه من الموت الحتمي؛ وهذا هو المجاز المرسل بعلاقة «ما يكون» (أي اعتبار ما سيكون عليه الشيء مستقبلًا). وهو مجاز مرسل لا استعارة؛ لأنّ العلاقة ليست المشابهة بل علاقة المآل والمصير.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('aa501093-a4d6-59ad-b8b4-4c301729bee0', '3e834f6b-a6c4-5d1b-b962-887db2faa81f', 'arabic', '📝 تدريب مراجعة: الصور البيانية', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0812b5d9-dfae-56c3-9c5a-f4c50824c145', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'في «العلمُ كالنورِ»، ما نوع الصورة البيانية وما أركانها الظاهرة؟', '[{"id":"a","text":"تشبيه؛ المشبّه «العلم» والأداة «الكاف» والمشبّه به «النور»"},{"id":"b","text":"استعارة تصريحية"},{"id":"c","text":"كناية"},{"id":"d","text":"مجاز مرسل"}]'::jsonb, 'a', '«العلمُ كالنورِ» تشبيه ظهرت فيه ثلاثة أركان: المشبّه (العلم) وأداة التشبيه (الكاف) والمشبّه به (النور)، وحُذف وجه الشبه. وليس استعارة لأنّ ركني التشبيه مذكوران معًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6135265-8fab-5fab-8d9f-dcc520ad7205', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'ما الذي يميّز الكناية عن التشبيه والاستعارة؟', '[{"id":"a","text":"في الكناية يجوز إرادة المعنى الحقيقي والمجازي معًا مع قرينة غير مانعة"},{"id":"b","text":"الكناية لا تحتمل إلا المعنى المجازي فقط"},{"id":"c","text":"الكناية تشبيه حُذفت أداته"},{"id":"d","text":"الكناية لا قرينة فيها أصلًا"}]'::jsonb, 'a', 'الكناية لفظ أُريد به لازم معناه مع جواز إرادة المعنى الأصلي، فقرينتها غير مانعة من إرادة الحقيقة. وهذا يميّزها عن الاستعارة والمجاز اللذين قرينتهما مانعة من إرادة المعنى الحقيقي.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd08d376-035b-52d3-a455-c15ff532c7b3', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'في «رأيتُ أسدًا يخطبُ في الناسِ» (يُقصد رجل شجاع)، ما نوع الصورة؟', '[{"id":"a","text":"تشبيه بليغ"},{"id":"b","text":"استعارة تصريحية (صُرّح بالمشبّه به «أسد» وحُذف المشبّه «الرجل»)"},{"id":"c","text":"استعارة مكنية"},{"id":"d","text":"مجاز مرسل علاقته الجزئية"}]'::jsonb, 'b', 'حُذف المشبّه (الرجل الشجاع) وصُرّح بالمشبّه به (أسد)، والقرينة «يخطب في الناس» تمنع إرادة الأسد الحقيقي، فهي استعارة تصريحية. ولو ذُكر المشبّه وحُذف المشبّه به وبقيت لازمته لكانت مكنية.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b2f43973-aeb8-5406-9d81-64c3a1e15a7a', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'في «شربتُ ماءَ النهرِ» إذا أُريد أنّك شربت من ماء النهر، ما الذي يجعلها مجازًا مرسلًا لو قيل «شربتُ النهرَ»؟', '[{"id":"a","text":"علاقة المحلّية (ذُكر المحلّ «النهر» وأُريد الحالّ فيه «الماء»)"},{"id":"b","text":"علاقة السببية"},{"id":"c","text":"استعارة مكنية"},{"id":"d","text":"كناية عن العطش"}]'::jsonb, 'a', '«شربتُ النهرَ» مجاز مرسل علاقته المحلّية؛ ذُكر المحلّ (النهر) وأُريد الحالّ فيه (الماء)، إذ لا يُشرب النهر نفسه بل ما يحلّ فيه. والقرينة أنّ النهر لا يُشرب حقيقة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('82551a4c-a153-5822-9cd7-68dbfaae0803', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'في «طارَ الخبرُ في المدينةِ»، ما نوع الصورة البيانية؟', '[{"id":"a","text":"تشبيه بليغ"},{"id":"b","text":"استعارة مكنية (شُبّه الخبر بطائر، حُذف المشبّه به وأُبقيت لازمته «طار»)"},{"id":"c","text":"استعارة تصريحية"},{"id":"d","text":"كناية عن سرعة الانتشار"}]'::jsonb, 'b', 'شُبّه الخبر بطائر يطير، فحُذف المشبّه به (الطائر) وأُبقيت إحدى لوازمه وهي فعل «طارَ»، فهي استعارة مكنية. ولو صُرّح بالمشبّه به لكانت تصريحية، ولو احتملت المعنيين لكانت كناية.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c1ba727-e2c9-5ba8-a00b-373de04836f3', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'في «فلانٌ كثيرُ الرمادِ»، ما نوع الصورة والمعنى المقصود؟', '[{"id":"a","text":"كناية عن الكرم (كثرة الطبخ للضيوف فيكثر رماد الموقد)"},{"id":"b","text":"استعارة تصريحية عن البخل"},{"id":"c","text":"مجاز مرسل علاقته السببية"},{"id":"d","text":"تشبيه مفصّل"}]'::jsonb, 'a', '«كثير الرماد» كناية عن الكرم وكثرة الضيوف؛ فمن يُكثر إيقاد النار للطبخ والقِرى يكثر رماده، فالرماد لازمٌ يدلّ على الكرم. ويجوز إرادة المعنى الحقيقي (وجود رماد فعلًا) مع المجازي، وهذا ما يجعلها كناية لا استعارة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b0c4b1fe-f19f-5210-afdf-bcc3e30a23bb', '3e834f6b-a6c4-5d1b-b962-887db2faa81f', 'arabic', '👑 تحدّي المناظرة ⭐⭐⭐⭐: الصور البيانية — تشبيه واستعارة وكناية ومجاز', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('72484ffa-95fe-57dc-94ec-07b34656105d', 'b0c4b1fe-f19f-5210-afdf-bcc3e30a23bb', 'في قولنا: «العلمُ نورٌ»، ما نوع الصورة البيانية؟', '[{"id":"a","text":"تشبيه بليغ (حُذفت الأداة ووجه الشبه)"},{"id":"b","text":"استعارة مكنية"},{"id":"c","text":"كناية"},{"id":"d","text":"تشبيه مفصّل (ذُكرت الأداة ووجه الشبه)"}]'::jsonb, 'a', '«العلمُ نورٌ» شبّه العلم (مشبّه) بالنور (مشبّه به) وحُذفت الأداة ووجه الشبه، فصار تشبيهًا بليغًا (أبلغ صور التشبيه). ✓ الخطأ الشائع: عدّه استعارة؛ الاستعارة يُحذف فيها أحد الطرفين، وهنا الطرفان مذكوران معًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f2aa386-94f1-5bef-bb9a-ed1a4ba74cbb', 'b0c4b1fe-f19f-5210-afdf-bcc3e30a23bb', 'قال تلميذ: «في قولنا (محمّدٌ كالأسدِ) استعارةٌ تصريحية». ما الخطأ؟', '[{"id":"a","text":"هو تشبيه (ذُكر المشبّه والمشبّه به والأداة «الكاف»)؛ والاستعارة يُحذف فيها أحد الطرفين"},{"id":"b","text":"لا خطأ، هي استعارة تصريحية"},{"id":"c","text":"هي كناية عن الشجاعة"},{"id":"d","text":"هي مجاز مرسل"}]'::jsonb, 'a', '«محمّدٌ كالأسدِ» تشبيه صريح: فيه المشبّه (محمّد) والمشبّه به (الأسد) والأداة (الكاف). الاستعارة لا تكون إلا بحذف أحد الطرفين والاستغناء عن الأداة. (تمرين «صيد الخطأ».) الخطأ الشائع: الخلط بين التشبيه والاستعارة لوجود المعنى نفسه (الشجاعة).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb9407d0-7365-5feb-b4da-6219adad472e', 'b0c4b1fe-f19f-5210-afdf-bcc3e30a23bb', 'في قول الشاعر: «ابتسمَ الصباحُ»، ما نوع الصورة البيانية؟', '[{"id":"a","text":"استعارة مكنية (شُبّه الصباح بإنسان، وحُذف المشبّه به وبقي لازمه «ابتسم»)"},{"id":"b","text":"استعارة تصريحية"},{"id":"c","text":"تشبيه بليغ"},{"id":"d","text":"كناية عن الفرح"}]'::jsonb, 'a', 'شُبّه الصباح بإنسان يبتسم، ثمّ حُذف المشبّه به (الإنسان) ورُمز إليه بشيء من لوازمه (الابتسام)، فهي استعارة مكنية. ✓ الخطأ الشائع: عدّها تصريحية؛ التصريحية يُصرَّح فيها بالمشبّه به، وهنا هو محذوف مرموزٌ إليه بلازمه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b6e6741d-2ded-5268-8728-cd5886f9af14', 'b0c4b1fe-f19f-5210-afdf-bcc3e30a23bb', 'في قول القائل عن رجلٍ شجاع: «رأيتُ أسدًا يخطبُ في الناسِ»، ما نوع الصورة البيانية في «أسدًا»؟', '[{"id":"a","text":"استعارة تصريحية (صُرّح بالمشبّه به «أسد» وحُذف المشبّه «الرجل»)"},{"id":"b","text":"استعارة مكنية"},{"id":"c","text":"تشبيه بليغ"},{"id":"d","text":"مجاز مرسل"}]'::jsonb, 'a', 'أُريد بالرجل الشجاع «أسد»، فصُرّح بالمشبّه به (أسد) وحُذف المشبّه (الرجل)، والقرينة «يخطب في الناس» (والأسد لا يخطب)، فهي استعارة تصريحية. ✓ الخطأ الشائع: عدّها تشبيهًا؛ التشبيه يذكر الطرفين، وهنا حُذف المشبّه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('54bd1369-44e1-5ddf-8c1a-b7e13d9f758e', 'b0c4b1fe-f19f-5210-afdf-bcc3e30a23bb', 'في قولنا عن رجلٍ: «فلانٌ كثيرُ الرمادِ»، ما نوع الصورة البيانية؟', '[{"id":"a","text":"كناية عن صفة (الكرم)"},{"id":"b","text":"استعارة تصريحية"},{"id":"c","text":"تشبيه بليغ"},{"id":"d","text":"حقيقة لا مجاز فيها"}]'::jsonb, 'a', '«كثير الرماد» لا يُراد ظاهرها، بل يُلزَم منها كثرة الطبخ لإكرام الضيوف، فهي كناية عن صفة الكرم (مع جواز إرادة المعنى الحقيقيّ). ✓ الخطأ الشائع: عدّها استعارة؛ الكناية يصحّ فيها المعنى الحقيقيّ ويُنتقل منه إلى اللازم، بخلاف الاستعارة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1fffc457-b75d-5797-87e3-034b2400835e', 'b0c4b1fe-f19f-5210-afdf-bcc3e30a23bb', 'في قولنا: «شربتُ النهرَ»، ما الصورة البيانية وعلاقتها؟', '[{"id":"a","text":"مجاز مرسل، علاقته المحلّية (ذُكر المحلّ «النهر» وأُريد الحالّ فيه «الماء»)"},{"id":"b","text":"استعارة مكنية"},{"id":"c","text":"تشبيه بليغ"},{"id":"d","text":"كناية عن العطش"}]'::jsonb, 'a', 'لا يُشرَب النهر نفسه بل ماؤه، فأُطلق المحلّ (النهر) وأُريد الحالّ فيه (الماء)؛ فهي مجاز مرسل علاقته المحلّية. ✓ الخطأ الشائع: عدّها استعارة؛ الاستعارة علاقتها المشابهة دائمًا، والمجاز المرسل علاقته غير المشابهة (محلّية، سببية، جزئية…).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
