  ('7595fbd9-9810-5997-baee-2c9a13444cd5', '7b7b1804-7f76-50ee-8992-21af9c7b4c3f', 'arabic', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
