  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73fe3e5d-9ec9-53c4-b15d-cbcd045538d5', '6753802a-6e1f-52cc-b811-1c1ad11ea17b', 'في قوله تعالى: «تَضحَكُ وتَبكي»، ما المحسّن البديعي الموجود؟', '[{"id":"a","text":"طباق السلب"},{"id":"b","text":"جناس تامّ"},{"id":"c","text":"طباق الإيجاب"},{"id":"d","text":"سجع"}]'::jsonb, 'c', '«تضحك» و«تبكي» ضدّان مثبتان من جنس واحد (فعلان)، فالطباق بينهما طباق إيجاب لا سلب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ea35b652-fa14-5064-802d-cd8b293ed244', '6753802a-6e1f-52cc-b811-1c1ad11ea17b', 'في المثل: «مَن طلبَ العُلا سَهِرَ اللَّيالي، وسَلكَ سبيلَ الأهوالِ، ونظرَ في عواقب الأحوالِ»، ما المحسّن البديعي اللفظي البارز؟', '[{"id":"a","text":"السجع"},{"id":"b","text":"الجناس التامّ"},{"id":"c","text":"ردّ العجز على الصدر"},{"id":"d","text":"الطباق"}]'::jsonb, 'a', 'الفواصل «اللَّيالي / الأهوالِ / الأحوالِ» تتوافق في الحرف الأخير، وهذا هو السجع الذي يمنح الكلام إيقاعًا موسيقيًّا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('610f5d92-d7d9-5805-9f50-d2a06b5d1478', '6753802a-6e1f-52cc-b811-1c1ad11ea17b', 'في قوله: «يعلمون ولا يعلمون»، ما نوع الطباق؟', '[{"id":"a","text":"طباق الإيجاب"},{"id":"b","text":"مقابلة"},{"id":"c","text":"تورية"},{"id":"d","text":"طباق السلب"}]'::jsonb, 'd', 'طباق السلب هو ما يتقابل فيه الفعل مع نفيه بحرف النفي، وهنا «يعلمون» قُوبلت بـ«لا يعلمون».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6db77f00-123b-58e4-87c1-8a8ef4581c6c', '6753802a-6e1f-52cc-b811-1c1ad11ea17b', 'قال الشاعر: «ما اصفرّت الوردة إلا حياءً من خدّك». ما المحسّن البديعي في هذا البيت؟', '[{"id":"a","text":"حسن التعليل"},{"id":"b","text":"التورية"},{"id":"c","text":"المقابلة"},{"id":"d","text":"الجناس الناقص"}]'::jsonb, 'a', 'الشاعر أنكر العلّة الحقيقية لاصفرار الوردة (طبيعتها) ونسبها إلى علّة أدبيّة طريفة وهي الحياء من جمال خدّ الحبيبة، وهذا هو حسن التعليل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2e4e4de-475b-5016-bb8d-45038f68f059', '6753802a-6e1f-52cc-b811-1c1ad11ea17b', 'في قوله تعالى: «وَيَوْمَ تَقُومُ السَّاعَةُ يُقْسِمُ الْمُجْرِمُونَ مَا لَبِثُوا غَيْرَ سَاعَةٍ»، ما نوع الجناس بين الساعتَين؟', '[{"id":"a","text":"جناس ناقص"},{"id":"b","text":"طباق سلب"},{"id":"c","text":"سجع"},{"id":"d","text":"جناس تامّ"}]'::jsonb, 'd', '«الساعة» بمعنى القيامة و«ساعة» بمعنى الوقت متّفقتان تمامًا في الحروف (نوعًا وعددًا وترتيبًا وهيئةً) مع اختلاف المعنى، فهو جناس تامّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e26f9754-dd15-52a1-a0ae-1226bc817aaa', '6753802a-6e1f-52cc-b811-1c1ad11ea17b', 'في قوله: «أعطى واتّقى وصدّق بالحسنى فسيُيسَّر لليسرى؛ وبخل واستغنى وكذّب بالحسنى فسيُيسَّر للعسرى»، ما المحسّن البديعي؟', '[{"id":"a","text":"الطباق"},{"id":"b","text":"التورية"},{"id":"c","text":"ردّ العجز على الصدر"},{"id":"d","text":"المقابلة"}]'::jsonb, 'd', 'جُمعت ثلاثة معانٍ (أعطى/اتّقى/صدّق) وقُوبلت بثلاثة معانٍ مضادّة (بخل/استغنى/كذّب) بنفس الترتيب، وهذا هو المقابلة لا الطباق الذي يكتفي بضدّين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a065a310-799f-5641-8171-6ce5aac1f3bb', '7b7b1804-7f76-50ee-8992-21af9c7b4c3f', 'arabic', '⚔️ زعيم الفصل: البديع المتقدّم', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
