INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d03dd70-5eb0-5ef5-9f74-9759f486be0a', 'a065a310-799f-5641-8171-6ce5aac1f3bb', 'ما الفرق الجوهري بين الطباق والمقابلة؟', '[{"id":"a","text":"الطباق لفظيّ والمقابلة معنويّة"},{"id":"b","text":"الطباق ضدّان في سياق واحد، والمقابلة سلسلة من الضدود في جملتين متوازيتين"},{"id":"c","text":"الطباق خاصّ بالشعر والمقابلة خاصّة بالنثر"},{"id":"d","text":"المقابلة ضدّان فقط والطباق ثلاثة فأكثر"}]'::jsonb, 'b', 'الطباق يجمع بين ضدّين فقط في السياق ذاته، أمّا المقابلة فتجمع معنيَين أو أكثر ثمّ تقابلها بمعانٍ مضادّة بنفس الترتيب في جملتين أو أكثر متوازيتين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f28a9693-8061-502f-9c8c-71f25af43d50', 'a065a310-799f-5641-8171-6ce5aac1f3bb', 'ما الأثر البلاغي المميّز لحسن التعليل؟', '[{"id":"a","text":"يُضفي شاعريّة وطرافة باختراع علّة أدبيّة بدلًا من العلّة الحقيقيّة"},{"id":"b","text":"يُقوّي المعنى بالتكرار اللفظي"},{"id":"c","text":"يُبرز التضادّ ويمنح الكلام قوّة"},{"id":"d","text":"يُحدث إيقاعًا موسيقيًّا بتوافق الفواصل"}]'::jsonb, 'a', 'حسن التعليل يتميّز بأنّ الأديب يُنكر العلّة الحقيقيّة ويخترع لها علّة أدبيّة طريفة، فيُضفي على الأسلوب شاعريّة وعمقًا؛ وهذا يختلف عن الطباق (تضادّ المعنى) والسجع (التوافق الصوتي) والتكرار.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eeaddb53-ec7a-5fea-ac77-a8c7996f7aa5', 'a065a310-799f-5641-8171-6ce5aac1f3bb', 'قال الشاعر: «نَحنُ قَومٌ لا تُقبَّلُ قِبلَتُنا». ما المحسّن البديعي في كلمة «قِبلَتُنا»؟', '[{"id":"a","text":"جناس تامّ بين قِبلَة وتُقبَّل"},{"id":"b","text":"طباق إيجاب"},{"id":"c","text":"تورية؛ القريب جهة الصلاة والبعيد المقصود التقبيل"},{"id":"d","text":"حسن تعليل"}]'::jsonb, 'c', 'كلمة «قِبلَتُنا» لها معنيان: قريب ظاهر هو جهة الصلاة، وبعيد خفيّ هو المقصود وهو التقبيل والحبّ. الجناس يشترط لفظَين منفصلَين لا لفظًا واحدًا ذا وجهَين، فالصحيح أنّه تورية.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55ad1fdd-76b3-506e-b629-98dc6aca5fe7', 'a065a310-799f-5641-8171-6ce5aac1f3bb', 'في «بَيْنَ النَّضيرِ والنَّضَرِ» (النضير: الشجر المزهر / النضَر: الذهب)، ما نوع الجناس؟', '[{"id":"a","text":"جناس تامّ لتشابه اللفظَين"},{"id":"b","text":"سجع لاتّحاد الفاصلتَين"},{"id":"c","text":"ردّ العجز على الصدر"},{"id":"d","text":"جناس ناقص لاختلاف عدد الحروف"}]'::jsonb, 'd', '«النَّضير» أربعة أحرف و«النَّضَر» ثلاثة أحرف، فاللفظان مختلفان في العدد، وهذا ما يجعل الجناس ناقصًا لا تامًّا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2337961d-e4da-5142-9381-9181c30129c5', 'a065a310-799f-5641-8171-6ce5aac1f3bb', 'قال أبو تمّام: «السَّيفُ أَصدَقُ أَنبَاءً مِنَ الكُتُبِ * في حَدِّهِ الحَدُّ بَينَ الجِدِّ واللَّعِبِ». ما المحسّن في «حَدِّهِ / الحَدُّ»؟', '[{"id":"a","text":"جناس ناقص لاختلاف الهيئة الإعرابية"},{"id":"b","text":"طباق إيجاب بين الجدّ واللعب"},{"id":"c","text":"سجع بين الكتب واللعب"},{"id":"d","text":"تورية في كلمة الكتب"}]'::jsonb, 'a', '«حدِّه» (حدّ السيف: شفرته) و«الحدُّ» (الحدّ بين شيئين: الفاصل) متّفقان في الحروف ومختلفان في الحركات، فهو جناس ناقص. أمّا «الجدّ/اللعب» فطباق صحيح لكنّ السؤال يسأل عن «حدِّهِ/الحدُّ» تحديدًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('8f9f6853-09ce-5205-88ba-7ff93e158a13', '7b7b1804-7f76-50ee-8992-21af9c7b4c3f', 'arabic', '👑 تحدّي النخبة: دقائق البديع', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fe234a7-678a-5eb2-8e3c-efacbb228ee1', '8f9f6853-09ce-5205-88ba-7ff93e158a13', 'قال الشاعر المتنبّي: «سَلِي إن جَهِلتِ النَّاسَ عَنَّا وعَنهُمُ * فَلَيسَ سَواءً عَالِمٌ وجَهولُ». حدّد المحسّن البديعي بين «عَالِمٌ» و«جَهولُ»، ثمّ بيّن علاقته بـ«جَهِلتِ» في صدر البيت.', '[{"id":"a","text":"طباق إيجاب بين «عالم» و«جهول»؛ وتشكّل «جهلتِ» مع «عالم» جناسًا اشتقاقيًّا يُعمّق دلالة التقابل"},{"id":"b","text":"طباق سلب؛ لأنّ «جهول» يعني «لا عالم» فهو نفيٌ للعلم"},{"id":"c","text":"مقابلة؛ لأنّ البيت يحتوي معنيَين متقابلَين في جملتَين"},{"id":"d","text":"تورية؛ إذ تحمل «جهول» معنيَين: الجاهل والجموح"}]'::jsonb, 'a', '«عالم» و«جهول» ضدّان مستقلّان من جنس واحد (صفتان)، فهو طباق إيجاب لا سلب. وطباق السلب يشترط أن يكون أحد الطرفَين نفيًا صريحًا للآخر (يعلمون/لا يعلمون)، أمّا «جهول» فلفظٌ مستقلّ لا نفيٌ صرفيّ. والملاحظة الدقيقة: «جَهِلتِ» في الصدر و«عالم/جهول» في العجز تشكّل شبكةً من الاشتقاق تُضفي على البيت وحدةً دلاليّة تجعل التقابل أشدّ تأثيرًا — وهذا ما يُفرّق الطالبَ المتميّز.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('194baa77-9e1b-5b00-83a5-92cd64613c6b', '8f9f6853-09ce-5205-88ba-7ff93e158a13', 'قال ابن المعتزّ: «فأَضحَت مَسرَّتُها حُزنَها * وصَارَ نَعيمُها بُؤسَها». ما المحسّن البديعي في هذا النصّ، وما الذي يُفرّقه عن الطباق البسيط؟', '[{"id":"a","text":"طباق إيجاب مزدوج؛ لأنّ في كلّ شطر ضدَّين مستقلَّين"},{"id":"b","text":"مقابلة رباعية؛ قُوبلت «المسرّة/النعيم» بـ«الحزن/البؤس» بنفس الترتيب في شطرَين متوازيَين، وهذا أشمل من الطباق البسيط"},{"id":"c","text":"سجع؛ لأنّ «حزنها» و«بؤسها» يتوافقان في اللاحقة «ها»"},{"id":"d","text":"حسن تعليل؛ لأنّ الشاعر يعلّل المسرّة بالحزن"}]'::jsonb, 'b', 'المقابلة هنا رباعية: (مسرّة ↔ حزن) و(نعيم ↔ بؤس) في شطرَين متوازيَين — أي أنّ العنصرَين الأوّلَين قُوبلا بعنصرَين مضادَّين بنفس الترتيب. هذا أعمق من الطباق البسيط الذي يقتصر على ضدَّين في موضع واحد. أمّا السجع فيستلزم توافق الحرف الأخير من الفاصلتَين لا توافق اللاحقة الصرفيّة، وتوافق «ها» الضمير لا يُعدّ سجعًا حقيقيًّا. وليس في النصّ ادّعاء علّة أدبيّة فيُستبعد حسن التعليل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7af9174d-76ea-5122-8d96-f5257a287e69', '8f9f6853-09ce-5205-88ba-7ff93e158a13', 'قال الشاعر: «وَفِي اللَّيلِ إذ يَدجُو لَكَ البَدرُ طالِعًا * كأنّكَ شَمسٌ والظَّلامُ يَغِيبُ». أراد طالبٌ أن يقول إنّ «البدر/الشمس» طباق، فردّه أستاذه. لماذا الردّ صحيح؟', '[{"id":"a","text":"لأنّ «البدر» و«الشمس» متشابهان في الإضاءة لا متضادّان، فلا طباق بينهما؛ الطباق الحقيقي هو بين «يدجو» (يظلم) و«يغيب» الظلام (يزول)"},{"id":"b","text":"لأنّ الطباق لا يقع في الأسماء بل في الأفعال فقط"},{"id":"c","text":"لأنّ الطباق يشترط أن يكون اللفظان في الجملة ذاتها لا في جملتَين"},{"id":"d","text":"لأنّ البيت يتضمّن تشبيهًا فلا يجتمع مع الطباق"}]'::jsonb, 'a', 'الطباق يشترط التضادّ الحقيقيّ في المعنى، و«البدر» و«الشمس» كلاهما مصدرا نور؛ لا تضادّ بينهما. التضادّ الفعلي في البيت هو بين «يَدجُو» (يشتدّ الظلام) و«يَغِيب» الظلام، أي بين ظلمة الليل وزوالها — وهذا هو موضع الطباق الصحيح. أمّا القول بأنّ الطباق لا يكون في الأسماء فخطأ بلاغيّ، وأنّه لا يجتمع مع التشبيه فغير صحيح، ولا اشتراط وحدة الجملة مطلق.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d0c6bd9-b411-59be-bcaa-bfeae9d2dd86', '8f9f6853-09ce-5205-88ba-7ff93e158a13', 'قال الشاعر: «وَلَستُ أُبالِي بَعدَ إدراكِيَ العُلا * أَقَصَّرَ يَومِي أَم أَطالَ بِهِ الأَمَدُ». حدّد المحسّن البديعي بين «أقصر» و«أطال»، ثمّ بيّن نوعه الدقيق.', '[{"id":"a","text":"جناس ناقص؛ لأنّ «أقصر» و«أطال» يشتركان في بعض الحروف"},{"id":"b","text":"طباق إيجاب؛ «أقصر» فعل ماضٍ بمعنى صار قصيرًا، و«أطال» فعل ماضٍ بمعنى صار طويلًا، وهما ضدّان من جنس واحد (فعلان)"},{"id":"c","text":"طباق سلب؛ لأنّ «أقصر» يعني في الأصل «لم يُطِل»"},{"id":"d","text":"مقابلة؛ لأنّ البيت يتضمّن جملتَين متوازيتَين"}]'::jsonb, 'b', '«أقصَر» بمعنى صار اليوم قصيرًا، و«أطال» بمعنى امتدّ الأمد — فعلان متضادّان مستقلّا المعنى من جنس واحد (فعلان)، فهو طباق إيجاب. لا يصحّ أن يُقال طباق سلب لأنّ «أقصر» ليس نفيًا صريحًا لـ«أطال»؛ فهو لفظ مستقلّ لا يحمل أداة نفي. والجناس يستلزم تشابهًا لفظيًّا لا تضادّ المعنى. والمقابلة تستلزم تعدّد عناصر التقابل في صفَّين متوازيَين، وهو غير متحقّق هنا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('028b413b-674d-580f-ba80-168434ce72f4', '8f9f6853-09ce-5205-88ba-7ff93e158a13', 'قال شاعرٌ مادحًا: «يا مَن يَرى عِمادَ الثَّرى وجودَهُ * وتَغرِفُ الأَنهارُ مِن بَحرِهِ النَّدى». ما المحسّن البديعي في كلمة «بَحرِهِ»، ولماذا؟', '[{"id":"a","text":"استعارة مكنيّة؛ شبّه جوده بالبحر فحذف المشبَّه به"},{"id":"b","text":"تورية؛ «البحر» له معنى قريب هو المسمّى الجغرافيّ، والمعنى البعيد المقصود هو الكرم الغزير الذي تستقي منه الأنهار"},{"id":"c","text":"سجع؛ لأنّ «وجوده» و«الندى» يتناسبان في المعنى"},{"id":"d","text":"جناس ناقص بين «البحر» و«النَّدى» لاشتراكهما في معنى الماء"}]'::jsonb, 'b', '«البحر» هنا تورية: معناه القريب الظاهر هو البحر الجغرافيّ المائيّ، والمعنى البعيد الخفيّ المقصود هو الممدوح ذو الكرم الغزير الذي تنهل الأنهار (= الناس المستعطون) من ندى عطائه. علامة التورية: قوله «تَغرِف الأنهار» قرينةٌ تُوجّه للمعنى البعيد في سياق المدح، بينما اللفظ وحده يُوهم المعنى الحسّي. أمّا القول بأنّه استعارة فصحيح من زاوية علم البيان، لكنّ السؤال عن المحسّن البديعي، والاستعارة ليست من البديع. والجناس لا يقوم على اشتراك المعنى بل على تشابه اللفظ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9652ddf0-c6ef-5001-8e38-305dee743468', '8f9f6853-09ce-5205-88ba-7ff93e158a13', 'قال الكاتب: «الصَّبرُ جَمِيلٌ والشَّكوَى قَبِيحَةٌ؛ فَلا تَبِع الجَمِيلَ بِالقَبِيحِ». حدّد المحسّن الأبرز، مع التفريق الدقيق بين ما هو طباق وما هو ردّ عجز على صدر.', '[{"id":"a","text":"طباق إيجاب فقط؛ بين «جميل» و«قبيحة»"},{"id":"b","text":"ردّ العجز على الصدر فقط؛ لأنّ «الجميل» و«القبيح» في الجملة الثانية يردّان لفظَي الصدر"},{"id":"c","text":"الأسلوب يجمع بين الطباق (صبر/شكوى وجميل/قبيح) وردّ العجز على الصدر (أُعيد «الجميل» و«القبيح» في الجملة الثانية بعينهما)، وهما محسّنان متكاملان لا متنافيان"},{"id":"d","text":"سجع؛ لأنّ الجملتَين تنتهيان بكلمتَين تشتركان في القافية"}]'::jsonb, 'c', 'النصّ يحمل محسّنَين في آنٍ واحد لا يتنافيان: أوّلًا، طباق الإيجاب بين «جميل» و«قبيحة» وبين «الصبر» و«الشكوى» (ضدّان في المعنى). ثانيًا، ردّ العجز على الصدر: ذُكر «الجميل» و«القبيح» في الجملة الأولى (الصدر) ثمّ أُعيد اللفظان بعينهما في الجملة الثانية (العجز)، فتحقّق الانسجام الدائري. المقارنة الدقيقة: الطباق محسّن معنويّ يقوم على التضادّ، وردّ العجز محسّن لفظيّ يقوم على إعادة اللفظ ذاته أو مشتقّه في نهاية الكلام — وقد يجتمعان في النصّ الواحد كما هنا. السجع يستلزم توافق الحرف الأخير بين فاصلتَين وهو غير صريح هنا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('6bd805b6-4e0d-5090-8ee6-b404efda387e', '7b7b1804-7f76-50ee-8992-21af9c7b4c3f', 'arabic', '📝 تدريب مراجعة: المحسّنات البديعية', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3970baac-fc14-5724-9717-2109015dfae5', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'في «يُحبّون الخيرَ ويكرهون الشرَّ»، ما المحسّن البديعي؟', '[{"id":"a","text":"طباق (بين يحبّون/يكرهون وبين الخير/الشرّ)"},{"id":"b","text":"جناس تامّ"},{"id":"c","text":"سجع"},{"id":"d","text":"تورية"}]'::jsonb, 'a', 'الطباق هو الجمع بين الضدّين في الكلام، وهنا تضادّ بين «يحبّون» و«يكرهون» وبين «الخير» و«الشرّ»، فهو طباق. وليس جناسًا لأنّ الجناس تشابه لفظَين لا تضادّ معنيَين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d5f9363b-b4fc-5722-8af1-0616f56c6519', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'في «الأرواحُ جنودٌ مجنّدةٌ»، ما نوع السجع المتحقّق إن وافقته فاصلة أخرى مثل «مؤلّفةٌ»؟', '[{"id":"a","text":"محسّن لفظيّ هو السجع (توافق الفاصلتين في الحرف الأخير)"},{"id":"b","text":"طباق معنوي"},{"id":"c","text":"تورية"},{"id":"d","text":"حسن تعليل"}]'::jsonb, 'a', 'السجع توافق الفاصلتين (آخر كلمتين في جملتين) في الحرف الأخير، مثل «مجنّدة» و«مؤلّفة»، وهو محسّن لفظيّ يُحدث إيقاعًا موسيقيًّا. وليس طباقًا (لا تضادّ) ولا تورية (لا معنى خفيّ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eb4e03f7-7616-5e15-932a-3a71c55f4cc8', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'ما الفرق بين المحسّنات المعنوية والمحسّنات اللفظية؟', '[{"id":"a","text":"المعنوية تُجمّل المعنى، واللفظية تُجمّل اللفظ والجرس الصوتي"},{"id":"b","text":"المعنوية في الشعر واللفظية في النثر"},{"id":"c","text":"المعنوية قديمة واللفظية حديثة"},{"id":"d","text":"لا فرق بينهما"}]'::jsonb, 'a', 'المحسّنات المعنوية (كالطباق والمقابلة والتورية) يكون التحسين فيها راجعًا إلى المعنى أوّلًا، أمّا اللفظية (كالجناس والسجع) فالتحسين فيها راجع إلى اللفظ والجرس الصوتي. وليس التقسيم على أساس الشعر والنثر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c215dbfb-fad8-5345-a87c-a51c0def0a4e', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'في «الصومُ جُنّةٌ»، إذا أُريد بـ«جُنّة» الوقاية والترس معًا، ما المحسّن؟', '[{"id":"a","text":"طباق"},{"id":"b","text":"تورية (لها معنى قريب وبعيد مقصود)"},{"id":"c","text":"سجع"},{"id":"d","text":"مقابلة"}]'::jsonb, 'b', 'التورية ذكر لفظ له معنيان: قريب ظاهر غير مراد وبعيد خفيّ مراد. «جُنّة» معناها القريب الترس/الدرع والبعيد المراد الوقاية من النار، فهي تورية. وليست طباقًا لانتفاء التضادّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4eabcd80-07f2-5750-979b-c1f94d8667e9', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'في «ذهبتُ إلى البنكِ فجلستُ على البنكِ» (الأوّل: المصرف، الثاني: المقعد)، ما نوع الجناس؟', '[{"id":"a","text":"جناس ناقص لاختلاف الحركات"},{"id":"b","text":"جناس تامّ (اتّفاق اللفظين في كلّ شيء واختلاف المعنى)"},{"id":"c","text":"طباق"},{"id":"d","text":"تورية"}]'::jsonb, 'b', 'الجناس التامّ هو اتّفاق اللفظين في نوع الحروف وعددها وهيئتها وترتيبها مع اختلاف المعنى. «البنك» الأولى (المصرف) و«البنك» الثانية (المقعد) متّفقتان تمامًا في اللفظ مختلفتان في المعنى، فهو جناس تامّ لا ناقص.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd0765db-a6d0-5ab1-971c-9132ca6df5ed', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'قال الشاعر يصف سبب صفرة الذهب: «لم تصفرَّ الشمسُ عند الغروبِ إلّا لفراقِ النهارِ». ما المحسّن البديعي؟', '[{"id":"a","text":"حسن تعليل (علّة أدبيّة طريفة مخترعة بدل العلّة الحقيقيّة)"},{"id":"b","text":"طباق إيجاب"},{"id":"c","text":"جناس ناقص"},{"id":"d","text":"مقابلة"}]'::jsonb, 'a', 'حسن التعليل أن يُنكر الأديب العلّة الحقيقيّة لأمر ويخترع له علّة أدبيّة طريفة مناسبة لغرضه. فصفرة الشمس عند الغروب علّتها العلميّة معروفة، لكنّ الشاعر علّلها بالحزن لفراق النهار، وهذه علّة أدبيّة جميلة لا حقيقيّة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9e13b73f-d755-50bb-975e-13684909ecc6', '7b7b1804-7f76-50ee-8992-21af9c7b4c3f', 'arabic', '👑 تحدّي المناظرة ⭐⭐⭐⭐: المحسّنات البديعية — طباق ومقابلة وجناس وسجع', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2318e09d-ae8e-5ae0-a7c2-dbdde524ca1a', '9e13b73f-d755-50bb-975e-13684909ecc6', 'في قوله تعالى: «وَأَنَّهُ هُوَ أَضْحَكَ وَأَبْكَى» (النجم: 43)، ما المحسّن البديعيّ بين «أضحك» و«أبكى»؟', '[{"id":"a","text":"طباق (بين ضدّين: أضحك / أبكى)"},{"id":"b","text":"جناس"},{"id":"c","text":"سجع"},{"id":"d","text":"مقابلة"}]'::jsonb, 'a', '«أضحك» و«أبكى» لفظان متضادّان في المعنى جُمع بينهما، وهذا هو الطباق (الجمع بين الشيء وضدّه). ✓ الخطأ الشائع: عدّه جناسًا؛ الجناس تشابهٌ في اللفظ، والطباق تضادٌّ في المعنى.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a335f743-cfb4-5256-9917-162982b1d83b', '9e13b73f-d755-50bb-975e-13684909ecc6', 'قال تلميذ: «في قوله تعالى (وَتَحْسَبُهُمْ أَيْقَاظًا وَهُمْ رُقُودٌ) جناسٌ». ما الخطأ؟', '[{"id":"a","text":"بل هو طباق بين «أيقاظًا» و«رقودٌ» (ضدّان)؛ والجناس تشابهٌ لفظيّ لا تضادٌّ معنويّ"},{"id":"b","text":"لا خطأ، هو جناس"},{"id":"c","text":"هو سجع"},{"id":"d","text":"هو مقابلة بين جملتين"}]'::jsonb, 'a', '«أيقاظًا» و«رقودٌ» متضادّان في المعنى (يقظة / نوم) جُمع بينهما، فهو طباق. أمّا الجناس فتشابهٌ في اللفظ لا في التضادّ. (تمرين «صيد الخطأ».) الخطأ الشائع: الخلط بين الطباق (تضادّ المعنى) والجناس (تشابه اللفظ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb64e410-7a26-5b93-a55b-79b887a6c588', '9e13b73f-d755-50bb-975e-13684909ecc6', 'في قوله تعالى: «فَلْيَضْحَكُوا قَلِيلًا وَلْيَبْكُوا كَثِيرًا» (التوبة: 82)، ما المحسّن البديعيّ؟', '[{"id":"a","text":"مقابلة (يضحكوا قليلًا ↔ يبكوا كثيرًا: معنيان متقابلان بأطرافهما)"},{"id":"b","text":"طباق واحد فقط"},{"id":"c","text":"جناس تامّ"},{"id":"d","text":"سجع"}]'::jsonb, 'a', 'قُوبِل معنى كامل بمعنى مضادّ له طرفًا طرفًا: (يضحكوا) يقابله (يبكوا)، و(قليلًا) يقابله (كثيرًا)؛ وهذا هو المقابلة (وهي أوسع من الطباق الذي يكون بين لفظين مفردين). ✓ الخطأ الشائع: عدّها طباقًا؛ الطباق بين ضدّين مفردين، والمقابلة بين معنيين (أو أكثر) متقابلين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b666eeb-5e5d-59c6-b79d-2943bbe21370', '9e13b73f-d755-50bb-975e-13684909ecc6', 'في قولنا: «صلّيتُ المغربَ في المغربِ»، ما نوع الجناس بين «المغرب» و«المغرب»؟', '[{"id":"a","text":"جناس تامّ (اتّفاق اللفظين في الحروف واختلاف المعنى: الصلاة / البلد)"},{"id":"b","text":"جناس ناقص"},{"id":"c","text":"طباق"},{"id":"d","text":"سجع"}]'::jsonb, 'a', 'تطابق اللفظان «المغرب» (صلاة) و«المغرب» (بلد) في نوع الحروف وعددها وترتيبها وضبطها مع اختلاف المعنى، فهو جناس تامّ. ✓ الخطأ الشائع: عدّه ناقصًا؛ الناقص يختلف فيه اللفظان في عدد الحروف أو نوعها أو ترتيبها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e02a2e8f-a9d2-5c66-82a7-7caab84e3031', '9e13b73f-d755-50bb-975e-13684909ecc6', 'في قول الحكيم: «الحُرُّ إذا وعدَ وَفَى، وإذا أعانَ كَفَى»، ما المحسّن البديعيّ في «وَفَى» و«كَفَى»؟', '[{"id":"a","text":"سجع (توافق الفاصلتين في الحرف الأخير)"},{"id":"b","text":"جناس تامّ"},{"id":"c","text":"طباق"},{"id":"d","text":"مقابلة"}]'::jsonb, 'a', 'توافقت الفاصلتان «وَفَى» و«كَفَى» في الحرف الأخير (والوزن)، وهذا هو السجع (تماثل أواخر الجُمل أو الفقرات في النثر). ✓ الخطأ الشائع: عدّه جناسًا؛ الجناس تشابه الكلمتين نفسهما، والسجع توافق أواخر الجمل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55da204b-e8ba-5309-8ddf-0e3905456a84', '9e13b73f-d755-50bb-975e-13684909ecc6', 'في قول أبي تمّام: «يَمُدُّونَ مِن أَيدٍ عَواصٍ عَواصِمِ»، ما نوع الجناس بين «عَواصٍ» و«عَواصِمِ»؟', '[{"id":"a","text":"جناس ناقص (اختلاف اللفظين في حرفٍ: زيادة الميم في «عواصم»)"},{"id":"b","text":"جناس تامّ"},{"id":"c","text":"طباق"},{"id":"d","text":"سجع"}]'::jsonb, 'a', '«عَواصٍ» (ضاربات بالسيف) و«عَواصِم» (مانعات حامية) لفظان متقاربان اختلفا في عدد الحروف (زيادة الميم)، فهو جناس ناقص. ✓ الخطأ الشائع: عدّه تامًّا؛ التامّ يتطابق فيه اللفظان تطابقًا كاملًا في الحروف.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

