  ('6e30792d-1678-5b7d-9c70-1fee544bc2b3', '376034b3-0a7a-5092-af54-e7ac20a7bdde', 'arabic', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
