INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e02be7c-b9ad-58cf-93a7-0d5a91d41a55', '34dc7379-306e-55c9-8d9f-af1b31da72a3', 'اقرأ: «في صباح يوم الاثنين خرج سامي من بيته مبكّرًا. وبينما كان يسير إلى المدرسة، سمع صوت طفل يبكي في الحديقة. اقترب منه وعرف أنّه تاه عن أهله، فأوصله إلى الشرطة التي أعادته إلى والديه. وعاد سامي إلى مدرسته مطمئنًّا.» ما نمط هذا النصّ؟', '[{"id":"a","text":"وصفي"},{"id":"b","text":"حجاجي"},{"id":"c","text":"سردي"},{"id":"d","text":"تفسيري"}]'::jsonb, 'c', 'النصّ يحكي أحداثًا متسلسلة زمنيًّا (خرج — سمع — اقترب — أوصله — عاد) بشخصيات ومكان وزمان، وهذه هي مؤشّرات النمط السردي.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a8f0e40f-27fe-59d6-9241-c7d0f18ab7dd', '34dc7379-306e-55c9-8d9f-af1b31da72a3', 'أيّ الروابط التالية يُعبّر عن النتيجة؟', '[{"id":"a","text":"وبالتالي"},{"id":"b","text":"بينما"},{"id":"c","text":"رغم ذلك"},{"id":"d","text":"قبل أن"}]'::jsonb, 'a', '«وبالتالي» رابط نتيجة يُشير إلى أنّ ما يليه نتيجة لما سبقه. «بينما» رابط زمني، «رغم ذلك» رابط تعارض، «قبل أن» رابط زمني سابق.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('89552c3a-1abd-53e1-96ea-853dbdb1fcab', '34dc7379-306e-55c9-8d9f-af1b31da72a3', 'في النصّ السردي، ما المكوّن الذي يُخلّ بالاستقرار ويُطلق الأحداث؟', '[{"id":"a","text":"الوضع الأوّلي"},{"id":"b","text":"النهاية"},{"id":"c","text":"الحلّ"},{"id":"d","text":"عنصر التحويل أو العقدة"}]'::jsonb, 'd', 'عنصر التحويل (العقدة) هو الحدث الطارئ الذي يُكسر الاستقرار الأوّلي ويجعل الشخصية في أزمة، وهو المحرّك الحقيقي للحبكة السردية.', 3)
