  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('946a41a6-32d0-59f6-9678-e3dfb5c48f29', '34dc7379-306e-55c9-8d9f-af1b31da72a3', 'اقرأ: «يرى كثيرون أنّ الرياضة وقت ضائع. بيد أنّ الأبحاث تُثبت أنّها تُحسّن التحصيل الدراسي، لأنّها تُنشّط الدماغ وتُقلّل التوتّر. فضلًا عن ذلك، تُعزّز روح الفريق. وعليه، ينبغي تشجيع الطلاب على ممارستها.» ما نمط هذا النصّ؟', '[{"id":"a","text":"سردي"},{"id":"b","text":"حجاجي"},{"id":"c","text":"وصفي"},{"id":"d","text":"تفسيري"}]'::jsonb, 'b', 'النصّ يطرح رأيًا (الرياضة مفيدة) ويدافع عنه بحجج (الأبحاث، تنشيط الدماغ، روح الفريق) وروابط سببية ونتيجة (لأنّ — فضلًا — وعليه)، وينتهي بدعوة إلى موقف، وهذه كلّها مؤشّرات النمط الحجاجي.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fdd16948-ea98-5eee-b741-5ce9736bf1d5', '34dc7379-306e-55c9-8d9f-af1b31da72a3', 'أيّ العناصر التالية ليس من مؤشّرات النمط الوصفي؟', '[{"id":"a","text":"كثرة الصفات والنعوت"},{"id":"b","text":"التفاصيل الحسّيّة (الألوان والأشكال)"},{"id":"c","text":"روابط زمنية كـ«ثمّ» و«بعد ذلك»"},{"id":"d","text":"أفعال «يبدو» و«يُشبه»"}]'::jsonb, 'c', 'الروابط الزمنية «ثمّ، بعد ذلك» من مؤشّرات النمط السردي الذي يتتبّع الأحداث عبر الزمن، وليست مؤشّرات الوصف الذي يُركّز على رسم الصورة الثابتة بالصفات والتفاصيل الحسّيّة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b6bc5687-b269-5c23-9167-1f2eb88b3243', '34dc7379-306e-55c9-8d9f-af1b31da72a3', 'ما الفرق الجوهري بين النمط التفسيري والنمط الحجاجي؟', '[{"id":"a","text":"التفسيري خاصّ بالعلوم والحجاجي خاصّ بالأدب"},{"id":"b","text":"التفسيري يستخدم الصفات والحجاجي يستخدم الأفعال"},{"id":"c","text":"لا فرق بينهما، فكلاهما يستخدم الحجج"},{"id":"d","text":"التفسيري يشرح كيفيّة حدوث شيء دون الدفاع عن رأي، والحجاجي يدافع عن موقف بالأدلّة"}]'::jsonb, 'd', 'النمط التفسيري يهدف إلى إيضاح طريقة عمل شيء أو شرح ظاهرة (كيف؟ لماذا؟) دون الدفاع عن موقف شخصي. أمّا الحجاجي فيصدر عن رأي صريح للكاتب ويسعى إلى إقناع القارئ به بالحجج والشواهد.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('e4350b8e-f690-5db8-9d83-2ca3732612fb', '376034b3-0a7a-5092-af54-e7ac20a7bdde', 'arabic', '⚔️ زعيم الفصل: الإنتاج الكتابي المتقدّم', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8ce46f30-1a80-5d10-ba39-b70922189cd6', 'e4350b8e-f690-5db8-9d83-2ca3732612fb', 'اقرأ المقطع: «كانت القرية تنعم بالهدوء (1). حتّى جاءت عاصفة اقتلعت الأشجار وهدمت بعض البيوت (2). هبّ الرجال لإغاثة المتضرّرين وبنوا ما تهدّم (3). وبعد أسبوع عاد الناس إلى حياتهم الطبيعية (4).» حدّد المكوّن الموافق للرقم (2).', '[{"id":"a","text":"الوضع الأوّلي"},{"id":"b","text":"عنصر التحويل / العقدة"},{"id":"c","text":"الحلّ"},{"id":"d","text":"النهاية / الوضع النهائي"}]'::jsonb, 'b', 'الجملة الثانية تصف الحدث الطارئ (العاصفة) الذي أخلّ بالاستقرار الأوّلي (الهدوء). هذا بالضبط هو عنصر التحويل أو العقدة الذي يُطلق مسار الأحداث.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7842ab0b-4b7c-52de-935b-3e93d3e15bb0', 'e4350b8e-f690-5db8-9d83-2ca3732612fb', 'أيّ الروابط يُناسب تمامًا ملء الفراغ في: «يُعاني الطلاب من ضغط الامتحانات؛ ___ تنتشر ظاهرة القلق في أوساطهم.»', '[{"id":"a","text":"بينما"},{"id":"b","text":"قبل أن"},{"id":"c","text":"رغم ذلك"},{"id":"d","text":"ومن ثمّ"}]'::jsonb, 'd', 'العلاقة بين الجملتين هي علاقة سبب (ضغط الامتحانات) ونتيجة (انتشار القلق). «ومن ثمّ» رابط نتيجة يُعبّر عن هذه العلاقة بدقّة. «بينما» للتزامن والتعارض، «قبل أن» للسبق الزمني، «رغم ذلك» للتنازل والتعارض.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('853dcace-e711-5fcf-9dc1-b7886bbb5967', 'e4350b8e-f690-5db8-9d83-2ca3732612fb', 'اقرأ: «تُحضَّر الهريسة بطحن الفلفل الأحمر المجفّف مع الثوم والكمّون والكزبرة. تُضاف كمّية من الزيت وتُعجن المكوّنات جيّدًا. ثمّ تُحفظ في مرطبانات محكمة الإغلاق.» ما نمط هذا النصّ؟', '[{"id":"a","text":"سردي"},{"id":"b","text":"تفسيري/إيعازي"},{"id":"c","text":"حجاجي"},{"id":"d","text":"وصفي"}]'::jsonb, 'b', 'النصّ يُعطي تعليمات لصنع الهريسة بأفعال مضارع إجرائية (تُحضَّر، تُضاف، تُعجن، تُحفظ) وترتيب تسلسلي (ثمّ)، وهذه هي مؤشّرات النمط التفسيري/الإيعازي. ليس سرديًّا لأنّه لا يحكي أحداثًا، ولا حجاجيًّا لأنّه لا يدافع عن رأي.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('707f82ca-cc76-5aee-8ed6-b8cfeceeaff8', 'e4350b8e-f690-5db8-9d83-2ca3732612fb', 'في نصّ حجاجي يدافع عن أهمّية القراءة، أيّ الجمل التالية تُمثّل الأطروحة؟', '[{"id":"a","text":"تُشير الإحصاءات إلى أنّ القارئ يمتلك ثروة لغوية أوسع"},{"id":"b","text":"قرأ علي عشرين كتابًا في السنة الماضية"},{"id":"c","text":"القراءة نشاط ذهني يشمل فكّ الرموز وبناء المعنى"},{"id":"d","text":"القراءة ضرورة لا رفاهية، وينبغي تشجيعها في المدارس"}]'::jsonb, 'd', 'الأطروحة هي الرأي الصريح الذي يدافع عنه الكاتب ويسعى لإقناع القارئ به. الجملة (أ) تُعبّر عن موقف واضح (القراءة ضرورة) وتدعو إلى فعل (تشجيعها). الجملة (ب) حجّة/شاهد، (ج) مثال سردي، (د) تعريف تفسيري.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('17b87af9-a45d-5d1e-b394-0f69d15c4f68', 'e4350b8e-f690-5db8-9d83-2ca3732612fb', 'ما الترتيب الصحيح لمكوّنات النصّ السردي؟', '[{"id":"a","text":"العقدة ← الوضع الأوّلي ← التحوّلات ← النهاية ← الحلّ"},{"id":"b","text":"التحوّلات ← الوضع الأوّلي ← العقدة ← الحلّ ← النهاية"},{"id":"c","text":"الحلّ ← الوضع الأوّلي ← العقدة ← التحوّلات ← النهاية"},{"id":"d","text":"الوضع الأوّلي ← العقدة ← التحوّلات ← الحلّ ← الوضع النهائي"}]'::jsonb, 'd', 'النصّ السردي يبدأ بتقديم الوضع المستقرّ (الوضع الأوّلي) ثمّ تطرأ العقدة فتُحرّك الأحداث (التحوّلات) حتّى تُحسم بالحلّ وتستقرّ في وضع نهائي جديد. هذا الترتيب المنطقي هو ما يجعل الحبكة مفهومة ومتماسكة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('34f29785-e946-591d-8ba0-dc2773a51a71', '376034b3-0a7a-5092-af54-e7ac20a7bdde', 'arabic', '👑 تحدّي النخبة: فنّ تمييز الأنماط والروابط', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d0dea70f-f06f-5511-9464-33bbc9f7f185', '34f29785-e946-591d-8ba0-dc2773a51a71', 'اقرأ المقطع الآتي بعناية: «وجد عليّ في صفحات التاريخ دليلًا دامغًا على أنّ الأمم التي أهملت لغتها الأمّ سقطت حضاريًّا. لأنّ اللغة ليست أداةً للتواصل وحسب، بل هي الذاكرة الجماعية للشعوب. وقد أثبت المؤرّخ ابن خلدون أنّ اندثار لسان الأمّة يسبق اندثار هويّتها.» أيّ نمط يُمثّله هذا المقطع، مع ذكر المؤشّر الأوّل الحاسم؟', '[{"id":"a","text":"سردي؛ لأنّ الفعل الماضي «وجد» يدلّ على حدث في الزمن"},{"id":"b","text":"حجاجي؛ لأنّ الكاتب يُدافع عن رأي (اللغة ركيزة الحضارة) بحجّة سببية وشاهد موثَّق"},{"id":"c","text":"تفسيري؛ لأنّه يشرح معنى اللغة ووظيفتها بأسلوب تعريفي"},{"id":"d","text":"وصفي؛ لأنّ الكاتب يُقدّم تفاصيل دقيقة عن دور اللغة في الحضارة"}]'::jsonb, 'b', 'رغم وجود فعل ماضٍ (وجد) وتفاصيل تفسيرية، فإنّ البنية الكلّية حجاجية لا سردية ولا تفسيرية: ثمّة أطروحة صريحة (إهمال اللغة يُسقط الأمم)، ورابط سببي «لأنّ» يُقدّم برهانًا، وشاهد موثَّق بنسبته إلى ابن خلدون. قاعدة المناظرة: حين يخدم الوصف أو السرد داخل النصّ برهنةً على رأي، يظلّ النمط الغالب حجاجيًّا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a121bb5-371b-5b61-b555-233f1e38c6ff', '34f29785-e946-591d-8ba0-dc2773a51a71', 'حدّد الوظيفة الدقيقة للرابط «بيد أنّ» في الجملة: «يرى المتشائمون أنّ الأمل وهمٌ لا طائل من ورائه؛ بيد أنّ التجربة الإنسانية عبر القرون تُثبت العكس.»', '[{"id":"a","text":"رابط إضافة يُضيف حجّة جديدة تدعم الفكرة السابقة"},{"id":"b","text":"رابط تعارض وتنازل يُدحض الرأي المعارض ويُؤسّس للأطروحة الأصلية"},{"id":"c","text":"رابط نتيجة يستخلص خلاصة منطقية من المقدّمة"},{"id":"d","text":"رابط سببي يُبيّن علّة التشاؤم عند المتشائمين"}]'::jsonb, 'b', '«بيد أنّ» من روابط التعارض والتنازل (في مصافّ: غير أنّ، إلا أنّ، في حين أنّ). وظيفتها هنا مزدوجة: أوّلًا تمنح الرأي المعارض (التشاؤم) حضورًا مشروعًا (تنازل)، ثمّ تعكس مساره مباشرةً بالأطروحة المضادّة (تعارض). هذه التقنية هي جوهر المناقشة الحجاجية الناضجة، وتمييزها عن روابط الإضافة أو النتيجة معيار أساسي في المناظرة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bc79be7e-39e6-5e0c-a24c-1066fee0d780', '34f29785-e946-591d-8ba0-dc2773a51a71', 'انظر إلى هذا المقطع من فقرة حجاجية: «[أ] لا ريب أنّ التعليم الرقمي بات ضرورةً عصرية. [ب] فالطالب الذي يمتلك أدوات التعلّم الإلكتروني يستطيع الوصول إلى آلاف المصادر في لحظات. [ج] وقد أشارت دراسة اليونسكو (2023) إلى أنّ الفجوة الرقمية تُعمّق التفاوت بين الأجيال. [د] لذلك ينبغي دمج التكنولوجيا في مناهج التعليم الأساسي.» ما الوظيفة البنيوية للجملة [ج]؟', '[{"id":"a","text":"أطروحة؛ إذ تُعبّر عن الرأي العامّ الذي تدافع عنه الفقرة"},{"id":"b","text":"مثال سردي؛ إذ تروي واقعة عن طالب بعينه"},{"id":"c","text":"شاهد موثَّق؛ إذ تستند إلى مرجع علمي موثوق لتدعيم الحجّة"},{"id":"d","text":"استنتاج؛ إذ تختم الفقرة بخلاصة تُعيد تأكيد الأطروحة"}]'::jsonb, 'c', 'الجملة [أ] هي الأطروحة (رأي صريح)، [ب] هي الحجّة بمثال (الطالب النموذجي)، [ج] تستشهد بدراسة اليونسكو وهو مرجع علمي دولي موثَّق فهي الشاهد، و[د] تبدأ بـ«لذلك» رابط استنتاج فهي الاستنتاج. تمييز الشاهد (إحصاء أو اقتباس موثَّق) عن المثال (واقعة فردية) عن الحجّة (برهان منطقي) مهارة جوهرية في المناظرة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ee7dbbc4-cada-55a3-ac6c-dad27fbd89f0', '34f29785-e946-591d-8ba0-dc2773a51a71', 'اقرأ: «تُطلّ المدينة العتيقة من خلف أسوارها الصمّاء كشيخ حكيم يحمل أسرار القرون. تتعانق أزقّتها الضيّقة المُعبَّقة بروائح الياسمين والبخور. وتشهد جدرانها المُطلاة بالأزرق والأبيض على حضارة متجذّرة لا تموت.» ثمّ: «غير أنّ هذا الإرث في خطر حقيقي؛ إذ تتهدّده العشوائية العمرانية والإهمال. لذلك يجب على الدولة أن تُشرّع قوانين صارمة لصون هذا الموروث.» ما النمط المهيمن على المقطعَين معًا؟', '[{"id":"a","text":"حجاجي؛ لأنّ الوصف في المقطع الأوّل يخدم برهنة دعوى الحماية في المقطع الثاني"},{"id":"b","text":"وصفي؛ لأنّ المقطع الأوّل يُهيمن بتفاصيله الحسّية والصور البيانية"},{"id":"c","text":"تفسيري؛ لأنّ الكاتب يشرح أسباب تدهور المدينة العتيقة"},{"id":"d","text":"سردي؛ لأنّ المقطع يستحضر ماضي المدينة وتاريخها عبر الأزمنة"}]'::jsonb, 'a', 'هذا سؤال النمط المُركَّب وهو من أصعب أسئلة المناظرة: المقطع الأوّل وصفيٌّ في أسلوبه لكنّه وُظِّف خدمةً لغرض إقناعي أشمل. المقطع الثاني يكشف الأطروحة الحقيقية (الإرث مهدَّد ← يجب التشريع) بروابط سببية «إذ» واستنتاجية «لذلك». حين يكون الوصف أو السرد أداةً للإقناع لا غاية بذاتها، فالنمط الغالب حجاجي. هذا التمييز هو ما يُفرّق بين إجابة المتوسّط وإجابة النخبة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('17ba0bb8-b0dd-575c-a38c-d4d0b1366c3a', '34f29785-e946-591d-8ba0-dc2773a51a71', 'أيٌّ من الجمل الآتية لا تؤدّي وظيفة رابط الاستنتاج، بل تؤدّي وظيفة رابط السببية؟', '[{"id":"a","text":"«خلاصة القول، إنّ المطالعة المنتظمة تُرسّخ الفهم العميق.»"},{"id":"b","text":"«وهكذا يتّضح أنّ الحوار الحضاري هو مفتاح التعايش.»"},{"id":"c","text":"«ونستنتج من كلّ ما سبق أنّ الحرّية والمسؤولية وجهان لعملة واحدة.»"},{"id":"d","text":"«نظرًا لتراجع مستوى القراءة، باتت الأمّة تعاني من فقر معرفي حادّ.»"}]'::jsonb, 'd', '«نظرًا لـ» رابط سببي يُعبّر عن العلّة أو السبب (تراجع القراءة هو سبب الفقر المعرفي). أمّا «خلاصة القول» و«وهكذا يتّضح» و«ونستنتج من كلّ ما سبق» فجميعها روابط استنتاج تُغلق الحجاج وتُجمل خلاصته. الخلط بين السببية والاستنتاج خطأ شائع في امتحانات المناظرة؛ السببية تُقدّم العلّة أمام النتيجة، والاستنتاج يأتي في الخاتمة يلخّص ما سبق.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('feffa2f6-8284-5318-996d-93099808e433', '34f29785-e946-591d-8ba0-dc2773a51a71', 'في مقطع حجاجي عن ضرورة الرياضة المدرسية، أيّ العناصر الآتية يُصنَّف «حجّة منطقية» لا «شاهدًا» ولا «مثالًا»؟', '[{"id":"a","text":"«أثبتت منظّمة الصحّة العالمية أنّ ممارسة الرياضة ثلاث مرّات أسبوعيًّا تُخفّض معدّل القلق بنسبة 40٪.»"},{"id":"b","text":"«عندما شارك طلاب مدرسة النخبة في دوري كرة القدم، تحسّنت نتائجهم الدراسية بشكل ملحوظ.»"},{"id":"c","text":"«الجسم السليم يمنح العقل طاقةً للتركيز، وبالتالي فإنّ الرياضة تُحسّن الأداء الذهني مباشرةً.»"},{"id":"d","text":"«قال الفيلسوف أفلاطون: لا تُعلّموا أبناءكم بالقسر، بل بالرياضة واللعب.»"}]'::jsonb, 'c', 'العنصر (أ) شاهد: إحصاء موثَّق منسوب لمرجع علمي معترف به. العنصر (ب) مثال: واقعة بعينها تخصّ مدرسة محدّدة وطلابًا حقيقيين. العنصر (د) شاهد: اقتباس موثَّق منسوب لشخصية مرجعية. أمّا (ج) فهو حجّة منطقية: استنتاج عقلاني عامّ مبنيٌّ على علاقة سببية مباشرة (الجسم السليم ← طاقة التركيز ← أداء ذهني أفضل)، دون الاستناد إلى رقم أو مرجع أو واقعة فردية. تمييز الحجّة المنطقية عن الشاهد والمثال معيار تمييزي في مناظرة التاسعة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('98d559bd-9f33-534c-89dd-a98ce3a9d74a', '376034b3-0a7a-5092-af54-e7ac20a7bdde', 'arabic', '📝 تدريب مراجعة: الإنتاج الكتابي وأنماط النصوص', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3792f490-0f40-5aa1-a384-774f23b81e7f', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'اقرأ: «كان الصبيُّ يلعب في الحديقة، فسقط فجأةً وجرح ركبتَه، فأسرعت أمّه لإسعافه.» ما نمط هذا النصّ؟', '[{"id":"a","text":"وصفي"},{"id":"b","text":"سردي (يحكي أحداثًا متتابعة في الزمن)"},{"id":"c","text":"حجاجي"},{"id":"d","text":"تفسيري"}]'::jsonb, 'b', 'النصّ يحكي أحداثًا متتابعة (لعب فسقط فأسرعت) بأفعال ماضية وروابط زمنية (فجأةً)، وهذه مؤشّرات النمط السردي. وليس وصفيًّا لأنّه لا يرسم صورة ثابتة، ولا حجاجيًّا لأنّه لا يدافع عن رأي.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('15900e74-d067-5d1f-b45d-c06fa90dbfda', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'اقرأ: «كانت الغرفةُ واسعةً، جدرانُها بيضاء، وفي وسطها طاولةٌ خشبيّةٌ تحيط بها أربعة كراسٍ.» ما نمط هذا النصّ؟', '[{"id":"a","text":"سردي"},{"id":"b","text":"وصفي (يرسم صورة حسّية ثابتة)"},{"id":"c","text":"حجاجي"},{"id":"d","text":"تفسيري إيعازي"}]'::jsonb, 'b', 'النصّ يرسم صورة حسّية ثابتة للغرفة بذكر الأبعاد والألوان والمواضع، وهذه مؤشّرات النمط الوصفي. وليس سرديًّا لخلوّه من تتابع الأحداث، ولا تفسيريًّا لأنّه لا يقدّم تعليمات.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8c0bcabb-4e0f-57d3-a358-4c3d438871b8', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'في النصّ الحجاجي، ما وظيفة «الحجّة»؟', '[{"id":"a","text":"تقديم الشخصيات والزمان والمكان"},{"id":"b","text":"دعم الأطروحة وإقناع القارئ بصحّتها"},{"id":"c","text":"رسم صورة حسّية للمشهد"},{"id":"d","text":"سرد الأحداث بالترتيب"}]'::jsonb, 'b', 'الحجّة في النصّ الحجاجي هي الدليل أو البرهان الذي يُساق لدعم الأطروحة وإقناع القارئ بصحّتها. أمّا تقديم الشخصيات فمن السرد، ورسم الصورة من الوصف.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('452145e3-2edb-50cf-bc2c-f7bec9fe4f48', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'أيّ الروابط يناسب الدلالة على نتيجة في الفراغ: «درس الطالبُ بجدّ، ___ نجح بتفوّق.»', '[{"id":"a","text":"لكنْ"},{"id":"b","text":"فـ (لذلك)"},{"id":"c","text":"رغم أنّ"},{"id":"d","text":"بينما"}]'::jsonb, 'b', 'العلاقة بين الجملتين سبب (الدراسة بجدّ) ونتيجة (النجاح)، والرابط «فـ/لذلك» يفيد النتيجة. أمّا «لكنْ» و«رغم أنّ» فللاستدراك والتعارض، و«بينما» للتزامن، وكلّها لا تناسب علاقة السبب والنتيجة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b4ec7ae5-43cb-54ac-bbfd-4993026c736b', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'في بناء الفقرة الحجاجية، ما الترتيب المنطقي الأمثل لعناصرها؟', '[{"id":"a","text":"المثال ← الحجّة ← الأطروحة ← الخاتمة"},{"id":"b","text":"الأطروحة ← الحجّة ← المثال الداعم ← الاستنتاج"},{"id":"c","text":"الاستنتاج ← الأطروحة ← الحجّة ← المثال"},{"id":"d","text":"الحجّة ← المثال ← الأطروحة ← الاستنتاج"}]'::jsonb, 'b', 'تبدأ الفقرة الحجاجية بعرض الأطروحة (الرأي)، ثمّ تُساق الحجّة الداعمة لها، ثمّ يُضرب المثال الذي يجسّد الحجّة، وتُختم بالاستنتاج الذي يؤكّد الأطروحة. هذا الترتيب يضمن تماسك الإقناع ووضوحه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3057429d-27db-552a-a8c1-1b7af01317aa', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'اقرأ: «ينبغي التقليل من استعمال السيّارات في المدن؛ فهي مصدرٌ رئيسٌ لتلوّث الهواء. وقد أثبتت دراساتٌ أنّ المدن الخالية من الازدحام أقلّ تلوّثًا.» ميّز الأطروحة من الحجّة.', '[{"id":"a","text":"الأطروحة: «ينبغي التقليل من استعمال السيّارات»، والحجّة: «فهي مصدر رئيس للتلوّث»"},{"id":"b","text":"الأطروحة: «أثبتت دراسات…»، والحجّة: «ينبغي التقليل…»"},{"id":"c","text":"لا توجد أطروحة في النصّ"},{"id":"d","text":"النصّ كلّه حجّة واحدة بلا أطروحة"}]'::jsonb, 'a', 'الأطروحة هي الرأي الذي يدافع عنه الكاتب: «ينبغي التقليل من استعمال السيّارات». والحجّة هي الدليل الداعم: «فهي مصدر رئيس للتلوّث» المعزَّز بالشاهد الإحصائي «أثبتت دراسات». فالشاهد ليس أطروحة بل تعزيز للحجّة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0b3f9bcd-ed29-529d-92b6-129da07d080c', '376034b3-0a7a-5092-af54-e7ac20a7bdde', 'arabic', '👑 تحدّي المناظرة ⭐⭐⭐⭐: الإنتاج الكتابي — أنماط النصوص والروابط والحجاج', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('82cc4be0-09db-554b-8a60-aa824f76f00e', '0b3f9bcd-ed29-529d-92b6-129da07d080c', 'نصٌّ يصوّر مكانًا بذكر تفاصيله الحسّية (الألوان والأصوات والأشكال) دون أحداث متتابعة. ما نمطه؟', '[{"id":"a","text":"وصفيّ"},{"id":"b","text":"سرديّ"},{"id":"c","text":"حجاجيّ"},{"id":"d","text":"تفسيريّ (إيعازيّ)"}]'::jsonb, 'a', 'تصوير المكان بتفاصيله الحسّية دون تسلسل زمنيّ للأحداث سِمةُ النمط الوصفيّ. ✓ الخطأ الشائع: عدّه سرديًّا؛ السرد يقوم على أحداث متتابعة زمنيًّا، أمّا الوصف فيرسم صورة ثابتة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('245f49af-f2ee-559a-bf1f-5eadd8d10d3a', '0b3f9bcd-ed29-529d-92b6-129da07d080c', 'قال تلميذ: «النصّ الذي يحكي أحداثًا متتابعة زمنيًّا نمطُه وصفيّ». ما الخطأ؟', '[{"id":"a","text":"بل نمطه سرديّ؛ فتتابع الأحداث زمنيًّا سمةُ السرد، والوصف يرسم صورةً ثابتة"},{"id":"b","text":"لا خطأ، الأحداث المتتابعة وصفيّة"},{"id":"c","text":"نمطه حجاجيّ"},{"id":"d","text":"نمطه تفسيريّ"}]'::jsonb, 'a', 'تتابع الأحداث في الزمن (ثمّ، بعد ذلك، فـ…) خاصّيةُ النمط السرديّ، بينما الوصف يصوّر مكانًا أو شخصًا تصويرًا ثابتًا بالتفاصيل الحسّية. (تمرين «صيد الخطأ».) الخطأ الشائع: الخلط بين السرد (أحداث/زمن) والوصف (صورة/تفاصيل).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d90c3969-85a9-5b31-a473-3fca0230fb30', '0b3f9bcd-ed29-529d-92b6-129da07d080c', 'أيّ مجموعة من الروابط تفيد الاستنتاج (استخلاص نتيجة ممّا سبق)؟', '[{"id":"a","text":"إذن ؛ ومن ثمّ ؛ وبذلك"},{"id":"b","text":"لأنّ ؛ بسبب ؛ إذ"},{"id":"c","text":"لكنّ ؛ غير أنّ ؛ بيد أنّ"},{"id":"d","text":"مثل ؛ كـ ؛ كأنّ"}]'::jsonb, 'a', '«إذن، ومن ثمّ، وبذلك» روابط استنتاج تُقدّم نتيجةً مستخلصة. أمّا «لأنّ/بسبب» فروابط سبب، و«لكنّ/بيد أنّ» روابط استدراك وتعارض، و«مثل/كأنّ» أدوات تشبيه. ✓ الخطأ الشائع: الخلط بين رابط الاستنتاج ورابط السبب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('807a2fdb-c1b6-5be0-a009-e140511253d8', '0b3f9bcd-ed29-529d-92b6-129da07d080c', 'ما العناصر الأساسية لبنية الفقرة الحجاجية؟', '[{"id":"a","text":"أطروحة (رأي) + حجج + أمثلة داعمة + استنتاج"},{"id":"b","text":"بداية + عقدة + حلّ"},{"id":"c","text":"زمان + مكان + شخصيات + أحداث"},{"id":"d","text":"تفاصيل حسّية متسلسلة (لون، صوت، شكل)"}]'::jsonb, 'a', 'الفقرة الحجاجية تعرض أطروحةً (رأيًا) ثمّ تدعمها بحجج وأمثلة وتنتهي باستنتاج يؤكّد الرأي. أمّا «بداية/عقدة/حلّ» فبنية النصّ السرديّ، و«زمان/مكان/شخصيات» عناصر السرد، والتفاصيل الحسّية سمةُ الوصف. ✓ الخطأ الشائع: الخلط بين بنية الحجاج وبنية السرد.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d422033-25f9-5831-8d58-bd51cda6f667', '0b3f9bcd-ed29-529d-92b6-129da07d080c', 'لدعم رأيٍ في فقرة حجاجية، استشهد الكاتب بقول عالِمٍ مختصّ. ما نوع هذه الحجّة؟', '[{"id":"a","text":"حجّة السلطة (المرجعية): الاستناد إلى رأي خبير أو نصّ موثوق"},{"id":"b","text":"حجّة بالمثال الواقعيّ"},{"id":"c","text":"حجّة بالمقارنة"},{"id":"d","text":"حجّة بالنتائج المترتّبة"}]'::jsonb, 'a', 'الاستشهاد بقول خبير أو نصّ موثوق لدعم الرأي هو حجّة السلطة (المرجعية). وتختلف عن الحجّة بالمثال (شاهد واقعيّ) وبالمقارنة (قياس على مشابه) وبالنتائج (بيان ما يترتّب على الأمر). ✓ الخطأ الشائع: عدّ كلّ دعمٍ «مثالًا»، وإهمال نوع الحجّة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7fba350e-3739-575a-ba2c-d592366d7112', '0b3f9bcd-ed29-529d-92b6-129da07d080c', 'في النصّ: «زارَ الطالبُ المكتبةَ، فاستعارَ منها كتابًا»، إلامَ يعود الضمير في «منها» (وهو من أدوات اتّساق النصّ)؟', '[{"id":"a","text":"إلى «المكتبة»"},{"id":"b","text":"إلى «الطالب»"},{"id":"c","text":"إلى «الكتاب»"},{"id":"d","text":"إلى «الزيارة»"}]'::jsonb, 'a', 'الضمير «ها» في «منها» يُحيل على «المكتبة» (فالاستعارة تكون من المكتبة)، وهذه الإحالة الضميرية من وسائل اتّساق النصّ وترابطه. ✓ الخطأ الشائع: إرجاع الضمير إلى أقرب اسم لفظًا دون مراعاة المعنى (الطالب لا يُستعار منه).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('31dee382-2d7f-508c-8398-79fd2adb9a64', '77ace903-23f8-5a38-8bfe-4fbb1b0369fa', 'arabic', 'اختبار فهم المقروء', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24421999-8a09-50c1-83a6-0a1a7846d004', '31dee382-2d7f-508c-8398-79fd2adb9a64', 'اقرأ النصّ التالي:

«العملُ شرفٌ للإنسان وصونٌ لكرامته؛ فبه يكسب قوته بعزّة، ويُغني نفسه عن مذلّة السؤال، ويسهم في بناء وطنه. وما الكسلُ إلّا بابٌ إلى المهانة والحاجة.»

ما الفكرة العامة للنصّ؟', '[{"id":"a","text":"العملُ مصدرٌ لكرامة الإنسان وعزّته، والكسلُ سبيلٌ إلى المهانة"},{"id":"b","text":"الإنسانُ يكسب قوته من العمل اليوميّ"},{"id":"c","text":"الكسلُ بابٌ إلى الحاجة فحسب"},{"id":"d","text":"بناءُ الوطن واجبٌ على كلّ مواطن"}]'::jsonb, 'a', 'الفكرة العامة جملةٌ جامعة تلمّ شتات النصّ: فهو يُمجّد العمل بوصفه شرفًا وكرامةً، ويذمّ الكسل بوصفه مهانة، فالخيار (a) يجمع الطرفين. أمّا (b) و(c) فتفصيلان جزئيّان وردا في سطر واحد، و(d) إشارةٌ عابرة لا تمثّل محور النصّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d041f3e-3e64-5303-9117-c65c1895a794', '31dee382-2d7f-508c-8398-79fd2adb9a64', 'اقرأ النصّ التالي:

«كانت السماءُ صافيةً زرقاءَ، تتدلّى منها خيوطُ الشمس الذهبيّة على حقولٍ خضراءَ ممتدّة. تتمايل السنابلُ مع النسيم في رقصةٍ هادئة، وتفوح من الأرض رائحةُ التراب النديّ.»

ما نمط هذا النصّ؟', '[{"id":"a","text":"وصفيّ: يرسم صورةً حسّية لمشهد طبيعيّ"},{"id":"b","text":"سرديّ: يحكي أحداثًا متسلسلة"},{"id":"c","text":"حجاجيّ: يدافع عن جمال الطبيعة"},{"id":"d","text":"تفسيريّ: يشرح ظاهرة طبيعية"}]'::jsonb, 'a', 'النصّ يكدّس النعوت (صافية، زرقاء، خضراء، الذهبية) ويخاطب الحواسّ (البصر والشمّ) ليرسم لوحةً ثابتة؛ وهذا هو النمط الوصفيّ. لا أحداث متسلسلة فيه (b)، ولا أطروحة يدافع عنها (c)، ولا شرح لظاهرة علميّة (d).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9de33181-3076-5a72-8537-089771d94937', '31dee382-2d7f-508c-8398-79fd2adb9a64', 'اقرأ النصّ التالي:

«تسعى المرأةُ اليوم إلى موقعها في الحياة العامّة؛ غير أنّ بعض العقبات لا تزال تعترض طريقها.»

ما العلاقة التي يُحدثها الرابط «غير أنّ» بين الجملتين؟', '[{"id":"a","text":"علاقة استدراك ومعارضة"},{"id":"b","text":"علاقة سبب وتعليل"},{"id":"c","text":"علاقة إضافة وتراكم"},{"id":"d","text":"علاقة تمثيل وتوضيح"}]'::jsonb, 'a', '«غير أنّ» أداةُ استدراكٍ تُعارض ما قبلها: فبعد إثبات سعي المرأة، تستدرك بوجود عقبات، فتُحدث تقابلًا بين الطموح والواقع. وليست أداة تعليل كـ«لأنّ» (b)، ولا إضافة كـ«كذلك» (c)، ولا تمثيل كـ«مثلًا» (d).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5acac469-595a-5aef-a1d5-ed0cf50a01f0', '31dee382-2d7f-508c-8398-79fd2adb9a64', 'اقرأ النصّ التالي:

«ها هي ذي قريتي القديمة! كم اشتقتُ إلى أزقّتها الضيّقة، وإلى صوت جدّي وهو يروي حكاياه تحت شجرة التين العتيقة. أيّامٌ ذهبت ولن تعود، فمتى يعود ذلك الزمن الجميل؟»

ما النبرة الغالبة على النصّ؟', '[{"id":"a","text":"الحنين إلى الماضي والأسى على انقضائه"},{"id":"b","text":"السخرية من حياة القرية البسيطة"},{"id":"c","text":"الفخر بانتمائه إلى قريته"},{"id":"d","text":"الغضب من تغيّر معالم القرية"}]'::jsonb, 'a', 'أفعالُ الشوق («اشتقتُ») وأسلوبا التعجّب («كم اشتقتُ») والاستفهام التحسّريّ («متى يعود؟») ووصفُ الأيّام بأنّها «ذهبت ولن تعود» كلّها قرائنُ تكشف نبرة الحنين والأسى. أمّا السخرية (b) فلا أثر لها، والفخر (c) موقفٌ مختلف، والغضب (d) لم يُذكر تغيُّرٌ يستثيره.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b020123c-82ba-5d33-92f1-b80edf21627a', '31dee382-2d7f-508c-8398-79fd2adb9a64', 'اقرأ النصّ التالي:

«دخل الرجلُ متثاقلًا، يجرّ قدميه، ويُلقي نظراتٍ زائغة، ثمّ جلس في ركنٍ بعيد ولم ينطق ببنت شفة طوال السهرة.»

ماذا نستنتج عن حال الرجل ممّا لم يُصرَّح به مباشرة؟', '[{"id":"a","text":"أنّه كان مضطربًا أو منزعجًا يتجنّب الآخرين"},{"id":"b","text":"أنّه كان مسرورًا بلقاء الحاضرين"},{"id":"c","text":"أنّه كان متعبًا من السفر فقط"},{"id":"d","text":"أنّه جاء ليُلقي خطابًا في السهرة"}]'::jsonb, 'a', 'لم يقل الكاتب صراحةً إنّ الرجل منزعج، لكنّ القرائن (التثاقل، النظرات الزائغة، الجلوس في ركنٍ بعيد، الصمت التامّ) توحي باضطرابه وانعزاله؛ وهذه قراءةٌ بين السطور مدعومة بالنصّ. أمّا السرور (b) فيناقض القرائن، والتعب من السفر (c) إسقاطٌ لم يُذكر، و(d) يناقض صمته.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('725f4292-1bcc-52a5-b299-b38004316d10', '31dee382-2d7f-508c-8398-79fd2adb9a64', 'اقرأ النصّ التالي:

«ساد القاعةَ صمتٌ عميق، فلمّا صعد العازفُ إلى المنصّة وأمسك بوتر آلته، انسابت النغماتُ كنهرٍ رقراق، فسحرت القلوب وأطربت الأسماع.»

ما معنى كلمة «انسابت» في سياق النصّ؟', '[{"id":"a","text":"تدفّقت وجرت في انسيابٍ ليّن"},{"id":"b","text":"انقطعت فجأةً"},{"id":"c","text":"اشتدّت وعلت بقوّة"},{"id":"d","text":"تبعثرت وتفرّقت"}]'::jsonb, 'a', 'السياق (النغمات شُبّهت بـ«نهرٍ رقراق» وأطربت الأسماع) يحدّد أنّ «انسابت» تعني تدفّقت في ليونةٍ وسلاسة. والمعاني الأخرى تناقض السياق: «انقطعت» (b) يضادّ استمرار العزف، و«اشتدّت بقوّة» (c) لا يلائم صورة الرقّة، و«تبعثرت» (d) يناقض الانسجام الموصوف.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b8a1dfa-a272-5c77-b248-36edebc235e6', '31dee382-2d7f-508c-8398-79fd2adb9a64', 'اقرأ النصّ التالي:

«إنّ التفاعل بين الثقافات إثراءٌ للإنسانية لا تهديدٌ لها؛ فالأمم التي انفتحت على غيرها أخذت وأعطت، فازدهرت حضارتها، في حين أنّ الأمم المنغلقة ذبلت وتخلّفت. فلا نموّ بلا انفتاحٍ واعٍ.»

ما الأطروحة التي يدافع عنها الكاتب؟', '[{"id":"a","text":"التفاعلُ بين الثقافات يُثري الإنسانية ويُحقّق النموّ"},{"id":"b","text":"الأممُ المنغلقة هي وحدها التي تحافظ على هويّتها"},{"id":"c","text":"التفاعلُ بين الثقافات تهديدٌ خطير للهويّات"},{"id":"d","text":"الحضارةُ تزدهر بالأخذ من الآخرين دون عطاء"}]'::jsonb, 'a', 'الأطروحة هي الموقف الذي يدافع عنه الكاتب، وقد صرّح به في المطلع («إثراءٌ لا تهديد») وأكّده في الخاتمة («لا نموّ بلا انفتاح»). الخياران (b) و(c) يناقضان موقفه تمامًا، و(d) يحرّف قوله «أخذت وأعطت» إلى أخذٍ بلا عطاء.', 7)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('090cdaba-f4f0-53b7-93d9-f9a7c40a7698', '31dee382-2d7f-508c-8398-79fd2adb9a64', 'اقرأ النصّ التالي:

«تُعدّ التغيّرات المناخيّة من أخطر شواغل العالم المعاصر؛ إذ يرتفع معدّل حرارة الأرض بسبب انبعاثات الغازات، فتذوب الجليديّات ويرتفع منسوب البحار، ممّا يُهدّد المدن الساحليّة بالغرق.»

ما العلاقة المنطقيّة التي تربط أجزاء النصّ ويبرزها الرابطان «بسبب» و«ممّا»؟', '[{"id":"a","text":"سلسلةٌ من السبب والنتيجة (تعليلٌ يتبعه استنتاج)"},{"id":"b","text":"مقارنةٌ بين رأيين متعارضين"},{"id":"c","text":"تعدادٌ لأمثلةٍ متساوية لا رابط بينها"},{"id":"d","text":"استدراكٌ يُبطل ما سبقه"}]'::jsonb, 'a', '«بسبب» رابط تعليلٍ يُرجع ارتفاع الحرارة إلى الانبعاثات، و«ممّا» رابط نتيجةٍ يستخلص تهديد المدن؛ فالنصّ سلسلةٌ سببيّة متتابعة (سبب ← نتيجة ← نتيجة). وليس مقارنةً بين رأيين (b)، ولا تعدادًا مفكَّكًا (c)، ولا استدراكًا يُبطل ما قبله (d).', 8)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('206036c9-5046-5b14-b8e4-183e4a2a9d03', '77ace903-23f8-5a38-8bfe-4fbb1b0369fa', 'arabic', 'تمرين 1 — فهم المقروء: الفكرة والنمط والروابط', 2, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('023ec536-3799-5d6d-9a7a-43b37e79fde5', '206036c9-5046-5b14-b8e4-183e4a2a9d03', 'اقرأ النصّ التالي:

«للفنّ رسالةٌ نبيلة؛ فهو يُهذّب الذوق، ويُرهف الإحساس، ويُقرّب بين الشعوب على اختلاف ألسنتها. فاللوحةُ الجميلة والنغمةُ الصادقة تتجاوزان حدود اللغة لتُخاطبا القلب مباشرة.»

ما الفكرة العامة للنصّ؟', '[{"id":"a","text":"الفنُّ رسالةٌ نبيلة تُهذّب الإنسان وتُقرّب بين الشعوب"},{"id":"b","text":"اللوحةُ الجميلة تُخاطب القلب"},{"id":"c","text":"اختلافُ ألسنة الشعوب عائقٌ أمام التواصل"},{"id":"d","text":"النغمةُ الصادقة أجمل من اللوحة"}]'::jsonb, 'a', 'الفكرة العامة جملةٌ جامعة تشمل النصّ كلّه: نُبل رسالة الفنّ وأثره في الإنسان والشعوب، وهو ما يلخّصه (a). أمّا (b) فمثالٌ جزئيّ، و(c) يحرّف المعنى إذ يجعل الاختلاف عائقًا والنصّ يقول العكس، و(d) مقارنةٌ لم يعقدها النصّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aab8251a-0c78-5e25-82ff-11bb4a0db203', '206036c9-5046-5b14-b8e4-183e4a2a9d03', 'اقرأ النصّ التالي:

«استيقظتُ باكرًا، فلبستُ ثيابي، ثمّ تناولتُ فطوري على عجل، وخرجتُ مسرعًا إلى المدرسة قبل أن يدقّ الجرس.»

ما نمط هذا النصّ؟', '[{"id":"a","text":"سرديّ: يحكي سلسلةً من الأحداث المتتابعة"},{"id":"b","text":"وصفيّ: يرسم صورةً لمكان"},{"id":"c","text":"حجاجيّ: يدافع عن أهمّية الاستيقاظ المبكّر"},{"id":"d","text":"تفسيريّ: يشرح فائدة الفطور"}]'::jsonb, 'a', 'النصّ يسرد أفعالًا متتالية يربطها الزمن (استيقظتُ، فلبستُ، ثمّ تناولتُ، خرجتُ) عبر روابط زمنيّة (الفاء، ثمّ)؛ وهذا هو النمط السرديّ. لا وصف لمكان (b)، ولا أطروحة يدافع عنها (c)، ولا شرح لظاهرة (d).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d1288f6-902f-5cf1-b091-4db39f5bd42e', '206036c9-5046-5b14-b8e4-183e4a2a9d03', 'اقرأ النصّ التالي:

«اجتهد التلميذُ طوال العام، لذلك نجح بتفوّق في الامتحان.»

ما العلاقة التي يُحدثها الرابط «لذلك» بين الجملتين؟', '[{"id":"a","text":"علاقة نتيجة (النجاح ثمرةُ الاجتهاد)"},{"id":"b","text":"علاقة معارضة بين الاجتهاد والنجاح"},{"id":"c","text":"علاقة تمثيل بمثالٍ على الاجتهاد"},{"id":"d","text":"علاقة زمنيّة محضة لا أكثر"}]'::jsonb, 'a', '«لذلك» رابط نتيجةٍ يستخلص النجاح من الاجتهاد السابق، فهو يربط سببًا بنتيجته. وليس معارضةً كـ«لكنْ» (b)، ولا تمثيلًا كـ«مثلًا» (c)؛ وهو وإن تضمّن تتابعًا زمنيًّا فإنّ وظيفته الأساس استخلاص النتيجة لا مجرّد الترتيب الزمنيّ (d).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b114e93-4c1d-5138-9780-6733aedb8683', '206036c9-5046-5b14-b8e4-183e4a2a9d03', 'اقرأ النصّ التالي:

«وقفت المرأةُ شامخةً في مقرّ عملها، تُدير شؤونه بحكمةٍ واقتدار، لا يُثنيها عن واجبها تعبٌ ولا تُضعف عزيمتها صعوبة.»

ما النبرة الغالبة في النصّ تجاه المرأة؟', '[{"id":"a","text":"الإعجاب والتقدير بقوّتها واقتدارها"},{"id":"b","text":"الشفقة على ما تعانيه من تعب"},{"id":"c","text":"السخرية من طموحها"},{"id":"d","text":"الحياد التامّ بلا أيّ موقف"}]'::jsonb, 'a', 'المفردات المشحونة بالمدح (شامخة، بحكمة واقتدار، لا يُثنيها تعب) تكشف نبرة الإعجاب والتقدير. أمّا الشفقة (b) فينقضها أنّ النصّ يبرز قوّتها لا ضعفها، والسخرية (c) لا أثر لها، والحياد (d) يناقض الألفاظ التقييميّة الواضحة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('33ec9c7a-123e-578b-93c8-9b7eb1402064', '206036c9-5046-5b14-b8e4-183e4a2a9d03', 'اقرأ النصّ التالي:

«أطلّ القمرُ بدرًا منيرًا، فغمر السهلَ بضوءٍ فضّيّ ساطع، حتّى بدت الأشجارُ كأنّها أشباحٌ تتراءى من بعيد.»

ما معنى كلمة «غمر» في سياق النصّ؟', '[{"id":"a","text":"ملأ وغطّى بالكامل"},{"id":"b","text":"أغرق في الماء"},{"id":"c","text":"أخفى وحجب"},{"id":"d","text":"أحرق وأتلف"}]'::jsonb, 'a', 'السياق (القمر يغمر السهل بالضوء) يحدّد أنّ «غمر» تعني ملأ المكان بالنور وعمّه. ومع أنّ «غمر» قد تعني في معجمٍ ما الإغراق بالماء (b)، فإنّ السياق ينفيه؛ وكذلك «أخفى» (c) يناقض الإنارة، و«أحرق» (d) لا يلائم لطف ضوء القمر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0bd2fb57-2673-5892-8c95-f3e2bb1afea7', '206036c9-5046-5b14-b8e4-183e4a2a9d03', 'اقرأ النصّ التالي:

«نظر الأبُ إلى نتيجة ابنه، فلم يقل شيئًا، لكنّه ربّت على كتفه بلطف وابتسم ابتسامةً عريضة قبل أن يُعدّ له طبقه المفضّل.»

ماذا نستنتج عن شعور الأب ممّا لم يُصرَّح به؟', '[{"id":"a","text":"أنّه راضٍ وفخورٌ بابنه"},{"id":"b","text":"أنّه غاضبٌ من نتيجة ابنه"},{"id":"c","text":"أنّه لا يكترث لأمر ابنه"},{"id":"d","text":"أنّه حزينٌ على رسوب ابنه"}]'::jsonb, 'a', 'لم يُصرّح الكاتب بشعور الأب، لكنّ القرائن (التربيت بلطف، الابتسامة العريضة، إعداد الطبق المفضّل) توحي بالرضا والفخر؛ وهذه قراءةٌ بين السطور مدعومة بالنصّ. والغضب (b) والحزن (d) يناقضان الابتسامة، وعدم الاكتراث (c) يناقض اهتمامه الظاهر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b645b9d7-e9d1-563f-a836-0104be43edba', '77ace903-23f8-5a38-8bfe-4fbb1b0369fa', 'arabic', 'تمرين 2 — الإنتاج الكتابي: التصميم والحجاج', 2, 50, 10, 'practice', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b387fd0-cd1f-5da3-8878-451c582822e9', 'b645b9d7-e9d1-563f-a836-0104be43edba', 'اقرأ التعليمة التالية:

«اكتب فقرةً تدافع فيها عن أهمّية العمل في حياة الإنسان.»

أيّ الجمل التالية أصلحُ لتكون أطروحةً (موقفًا) تنطلق منها فقرتك؟', '[{"id":"a","text":"العملُ ركيزةٌ أساسيّة لكرامة الإنسان وتقدّم المجتمع"},{"id":"b","text":"ذهبتُ صباحًا إلى عملي مشيًا على الأقدام"},{"id":"c","text":"ما أجملَ منظرَ العمّال في الحقول!"},{"id":"d","text":"كم ساعةً يعمل الموظّفُ في اليوم؟"}]'::jsonb, 'a', 'الأطروحة موقفٌ عامّ قابلٌ للدفاع عنه بالحجج، و(a) يحمل موقفًا واضحًا (العمل ركيزة الكرامة والتقدّم). أمّا (b) فسردُ واقعةٍ شخصيّة لا موقف فيها، و(c) جملةٌ وصفيّة انفعاليّة لا أطروحة، و(d) سؤالٌ لا يصلح موقفًا يُدافَع عنه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d3f18195-f6fc-5570-9bf8-b167f7df1649', 'b645b9d7-e9d1-563f-a836-0104be43edba', 'اقرأ الفقرة التالية وحدّد الجملة المفتاحية فيها:

«(1) فالقراءةُ تُوسّع المدارك وتُثري اللغة. (2) القراءةُ غذاءُ العقل ومفتاحُ المعرفة. (3) ومن قرأ كثيرًا اتّسعت ثقافته وتحسّن أسلوبه.»

ما الجملة المفتاحية التي تُعلن الفكرة الرئيسة؟', '[{"id":"a","text":"الجملة (2): القراءةُ غذاءُ العقل ومفتاحُ المعرفة"},{"id":"b","text":"الجملة (1): فالقراءةُ تُوسّع المدارك وتُثري اللغة"},{"id":"c","text":"الجملة (3): ومن قرأ كثيرًا اتّسعت ثقافته"},{"id":"d","text":"لا توجد جملة مفتاحية في الفقرة"}]'::jsonb, 'a', 'الجملة المفتاحية هي العبارة العامّة الجامعة التي تتفرّع عنها بقيّة الجمل، وهي الجملة (2) التي تُعرّف القراءة تعريفًا شاملًا. أمّا (1) فحجّةٌ تشرح فائدةً جزئيّة، و(3) مثالٌ/نتيجة تُجسّد الفكرة، وكلاهما يخدم الجملة المفتاحية لا يحلّ محلّها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db4aa8a1-6403-5afd-bf9d-babca5012363', 'b645b9d7-e9d1-563f-a836-0104be43edba', 'اقرأ ما يلي ثمّ ميّز الحجّة من المثال:

«التطوّعُ يُنمّي روحَ التضامن في المجتمع، فكثيرٌ من الشباب الذين يساعدون المسنّين تطوّعًا صاروا أكثر إحساسًا بالمسؤولية تجاه غيرهم.»

أيّ العبارتين تمثّل الحجّة (الفكرة العقليّة)؟', '[{"id":"a","text":"«التطوّعُ يُنمّي روحَ التضامن في المجتمع»"},{"id":"b","text":"«شبابٌ يساعدون المسنّين تطوّعًا»"},{"id":"c","text":"كلتا العبارتين مثالٌ لا حجّة"},{"id":"d","text":"كلتا العبارتين حجّةٌ لا مثال"}]'::jsonb, 'a', 'الحجّة فكرةٌ عقليّة عامّة تُبرّر الموقف، وهي هنا «التطوّع يُنمّي روح التضامن». أمّا «الشباب الذين يساعدون المسنّين» فمثالٌ جزئيّ محسوس يُجسّد الحجّة ويبرهن عليها. فالخياران (c) و(d) خطأ لأنّهما يخلطان بين النوعين المختلفين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65b3a3f6-31ff-5a7d-8efb-e6406e971cf7', 'b645b9d7-e9d1-563f-a836-0104be43edba', 'أردتَ الانتقال في إنتاجك من حجّةٍ أولى إلى حجّةٍ ثانية تُضاف إليها. أيّ رابطٍ هو الأنسب؟', '[{"id":"a","text":"علاوةً على ذلك"},{"id":"b","text":"غير أنّ"},{"id":"c","text":"لأنّ"},{"id":"d","text":"في الختام"}]'::jsonb, 'a', 'إضافةُ حجّةٍ جديدة إلى سابقتها تقتضي رابط إضافةٍ مثل «علاوةً على ذلك». أمّا «غير أنّ» (b) فللاستدراك والمعارضة لا الإضافة، و«لأنّ» (c) للتعليل، و«في الختام» (d) يُؤذن بالخاتمة لا بإضافة حجّة في صلب العرض.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7b6c5dc8-ead3-553b-b4bb-52e69f6c7f5b', 'b645b9d7-e9d1-563f-a836-0104be43edba', 'رُتّبت جملُ فقرةٍ ترتيبًا مضطربًا:

(1) ومن ثمّ صارت الهواتفُ الذكيّة جزءًا لا يتجزّأ من حياتنا.
(2) غيّرت التكنولوجيا الحديثة نمطَ حياتنا تغييرًا جذريًّا.
(3) فهي تُمكّننا من التواصل والعمل والتعلّم في أيّ وقت.

ما الترتيب المنطقيّ السليم للفقرة؟', '[{"id":"a","text":"2 ← 3 ← 1"},{"id":"b","text":"1 ← 2 ← 3"},{"id":"c","text":"3 ← 1 ← 2"},{"id":"d","text":"2 ← 1 ← 3"}]'::jsonb, 'a', 'الفقرة المتماسكة تبدأ بالجملة المفتاحية العامّة (2: التكنولوجيا غيّرت حياتنا)، ثمّ الحجّة/التفصيل (3: فهي تُمكّننا…)، ثمّ النتيجة المستخلصة (1: ومن ثمّ صارت الهواتف…). والروابط ترشدنا: الفاء في (3) تستأنف التعليل، و«ومن ثمّ» في (1) يستلزم سابقًا يُستنتج منه، فلا يصحّ أن يتصدّرا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5afd770e-d6f6-572e-bffd-130d9d188500', 'b645b9d7-e9d1-563f-a836-0104be43edba', 'اقرأ التعليمة:

«اكتب خاتمةً لموضوعٍ عالجتَ فيه دور الفنون في تقريب الثقافات.»

أيّ الجمل التالية أنسبُ خاتمةً متماسكة؟', '[{"id":"a","text":"وخلاصةُ القول إنّ الفنون جسرٌ يصل بين الشعوب، فحريٌّ بنا أن نرعاها ونشجّعها"},{"id":"b","text":"وأوّلُ ما ينبغي قوله إنّ للفنون أنواعًا كثيرة سنعدّدها فيما يلي"},{"id":"c","text":"أمّا الرياضةُ فلها أيضًا دورٌ كبير في حياة الشعوب"},{"id":"d","text":"في الصباح ذهبتُ إلى المتحف ورأيت لوحاتٍ جميلة"}]'::jsonb, 'a', 'الخاتمة المتماسكة تُلخّص الموقف وتفتح أفقًا، وهو ما يفعله (a) برابط الخلاصة («وخلاصةُ القول») واستنتاجٍ منسجم مع الموضوع. أمّا (b) فمطلعٌ يُمهّد لا خاتمة، و(c) يُقحم موضوعًا جديدًا (الرياضة) فيكسر الانسجام، و(d) سردٌ جزئيّ لا صلة له بختم الموضوع الحجاجيّ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('e3ab459c-7cc9-579f-81a8-def4cf3d7483', '77ace903-23f8-5a38-8bfe-4fbb1b0369fa', 'arabic', '⚔️ زعيم الفصل: تحليل النصّ المركّب', 3, 120, 30, 'boss', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65eb526c-31d4-5dda-9f8d-eeb7f4d9c997', 'e3ab459c-7cc9-579f-81a8-def4cf3d7483', 'اقرأ النصّ التالي:

«ليست الحرّيةُ فوضى تُطلق العنانَ للأهواء، بل هي مسؤوليّةٌ تقترن بالوعي؛ فحرّيةُ المرء تنتهي حيث تبدأ حرّيةُ غيره. ومن ظنّ الحرّية انفلاتًا فقد أساء فهمها.»

ما الأطروحة التي يدافع عنها الكاتب؟', '[{"id":"a","text":"الحرّيةُ مسؤوليّةٌ واعية محدودةٌ بحرّية الآخرين، لا فوضى وانفلات"},{"id":"b","text":"الحرّيةُ فوضى تُطلق العنان للأهواء"},{"id":"c","text":"ينبغي تقييدُ الحرّيات إلى أبعد حدّ"},{"id":"d","text":"لا قيمةَ للحرّية في حياة الإنسان"}]'::jsonb, 'a', 'يبني الكاتب أطروحته على النفي والإثبات: «ليست فوضى… بل مسؤوليّة»، ويحدّها بحرّية الغير. فـ(a) يطابق موقفه. أمّا (b) فهو الرأي الذي يدحضه الكاتب صراحةً، و(c) مبالغةٌ لم يقل بها (هو يضبط لا يُقيّد إلى أقصى حدّ)، و(d) يناقض تثمينه للحرّية.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f78570a5-1972-56ca-be72-c46c634ed1db', 'e3ab459c-7cc9-579f-81a8-def4cf3d7483', 'اقرأ النصّ التالي:

«تقدّمت العلومُ تقدّمًا مذهلًا، فأطالت الأعمارَ وقهرت كثيرًا من الأمراض؛ غير أنّ هذا التقدّم نفسه أنتج أسلحةً قادرةً على إفناء البشريّة. فالعلمُ سلاحٌ ذو حدّين.»

ما النبرة التي تُهيمن على موقف الكاتب من العلم؟', '[{"id":"a","text":"نبرةٌ متوازنة تجمع الإعجاب والتحذير معًا"},{"id":"b","text":"إعجابٌ مطلقٌ بلا أيّ تحفّظ"},{"id":"c","text":"رفضٌ تامّ للعلم وإدانةٌ له"},{"id":"d","text":"سخريةٌ من إنجازات العلم"}]'::jsonb, 'a', 'النصّ يُثني على منجزات العلم (إطالة الأعمار، قهر الأمراض) ثمّ يُحذّر من مخاطره (أسلحة الإفناء) عبر الاستدراك «غير أنّ»، ويختم بحكمٍ متوازن «سلاح ذو حدّين»؛ فالنبرة مزيجٌ من الإعجاب والتحذير (a). فلا هو إعجابٌ مطلق (b)، ولا رفضٌ تامّ (c)، ولا سخرية (d).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83fac81d-cbb1-5d89-9ea8-566907ccab4c', 'e3ab459c-7cc9-579f-81a8-def4cf3d7483', 'اقرأ النصّ التالي:

«ما زال بعضُهم يحصر دورَ المرأة في البيت، متجاهلًا أنّها أثبتت جدارتها في كلّ ميدان. أوَليست الطبيبةُ والمهندسةُ والقاضيةُ دليلًا ساطعًا على ذلك؟»

ما دلالة أسلوب الاستفهام في «أوَليست… دليلًا ساطعًا؟»', '[{"id":"a","text":"استفهامٌ إنكاريّ يُثبت قدرة المرأة ويُفنّد رأي المخالف"},{"id":"b","text":"استفهامٌ حقيقيّ يطلب الكاتبُ به معلومةً يجهلها"},{"id":"c","text":"استفهامٌ يُعبّر عن شكّ الكاتب في قدرة المرأة"},{"id":"d","text":"استفهامٌ للتمنّي والرجاء"}]'::jsonb, 'a', 'الاستفهام هنا إنكاريٌّ خرج عن معناه الحقيقيّ إلى التقرير والإثبات: الكاتب لا يسأل سؤالًا يجهل جوابه (b) بل يُؤكّد جدارة المرأة ويردّ على من يحصر دورها. ولا يدلّ على شكّه (c) فهو مقتنع بموقفه، ولا على تمنٍّ (d). والقرينة: ذكرُ نماذج «دليلًا ساطعًا».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ef8f74e-1819-556e-9c79-0b367114ffc2', 'e3ab459c-7cc9-579f-81a8-def4cf3d7483', 'اقرأ النصّ التالي:

«انتشر الفقرُ في أحياءٍ كثيرة، بيدَ أنّ الجمعيّات الخيريّة لم تَدَّخر وسعًا في التخفيف منه.»

ما العلاقة المنطقيّة التي يُحدثها الرابط «بيدَ أنّ»؟', '[{"id":"a","text":"استدراكٌ يُعارض ما قد يُتوقّع من الجملة الأولى"},{"id":"b","text":"تعليلٌ يُبيّن سبب انتشار الفقر"},{"id":"c","text":"نتيجةٌ مترتّبة على انتشار الفقر"},{"id":"d","text":"إضافةٌ لمعلومةٍ مماثلة"}]'::jsonb, 'a', '«بيدَ أنّ» من أدوات الاستدراك، مرادفةٌ لـ«لكنْ» و«غير أنّ»؛ فهي تُعارض ما قد يُفهم من انتشار الفقر (وهو الاستسلام له) بإبراز جهد الجمعيّات. وليست تعليلًا (b) ولا نتيجة (c)، ولا إضافةً لمعلومةٍ في الاتّجاه نفسه (d) بل تقابلٌ بين واقعٍ سلبيّ وجهدٍ إيجابيّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('70938c3e-b5b3-5f96-bbf5-c603613c8e9d', 'e3ab459c-7cc9-579f-81a8-def4cf3d7483', 'اقرأ النصّ التالي:

«وقف الشاعرُ يُنشد قصيدته، فهزّت كلماتُه النفوسَ، وأرسلت في القلوب قشعريرةً، حتّى ذرفت العيونُ دمعًا لم يستطع أحدٌ كتمانه.»

ماذا نستنتج عن أثر القصيدة في الجمهور؟', '[{"id":"a","text":"أنّ القصيدة بلغت من التأثير حدًّا أبكى الحاضرين تأثّرًا"},{"id":"b","text":"أنّ الجمهور مَلَّ القصيدة وانصرف عنها"},{"id":"c","text":"أنّ القصيدة كانت باردةً لم تُحرّك مشاعر أحد"},{"id":"d","text":"أنّ الشاعر أخفق في إلقاء قصيدته"}]'::jsonb, 'a', 'القرائن (هزّت النفوس، قشعريرة في القلوب، دمعٌ لم يُكتم) تستلزم بالاستنتاج أنّ القصيدة بلغت تأثيرًا عميقًا أبكى الحاضرين. فالخياران (b) و(c) يناقضان قوّة الأثر الموصوف، و(d) يناقض نجاح الإلقاء الذي تشهد به ردّةُ فعل الجمهور.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('54ab3126-2fb8-5e1d-9ce8-16f5d0eae663', 'e3ab459c-7cc9-579f-81a8-def4cf3d7483', 'اقرأ النصّ التالي:

«في زمنٍ تتسارع فيه التحوّلات، لم يَعُد الانكفاءُ على الذات خيارًا ممكنًا؛ فالتفاعلُ مع ثقافات العالم ضرورةٌ يفرضها العصر.»

ما الفكرة العامة للنصّ؟', '[{"id":"a","text":"التفاعلُ مع الثقافات الأخرى ضرورةٌ يفرضها عصرُ التحوّلات المتسارعة"},{"id":"b","text":"التحوّلاتُ في العالم تتسارع يومًا بعد يوم"},{"id":"c","text":"الانكفاءُ على الذات خيارٌ آمنٌ وممكن"},{"id":"d","text":"ثقافاتُ العالم متشابهةٌ لا فرق بينها"}]'::jsonb, 'a', 'الفكرة العامة تجمع موضوع النصّ وموقف الكاتب: ضرورة التفاعل الثقافيّ في زمن التحوّلات، وهو ما يصوغه (a). أمّا (b) فمعطًى تمهيديّ جزئيّ لا الفكرة المحورية، و(c) يناقض النصّ صراحةً («لم يَعُد… خيارًا ممكنًا»)، و(d) ادّعاءٌ لم يَرِد في النصّ أصلًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('8d7b07eb-7025-5d92-a33d-73107fbb46d4', '77ace903-23f8-5a38-8bfe-4fbb1b0369fa', 'arabic', '👑 تحدّي النخبة: دقائق الفهم والإنتاج', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3c07ad41-b34b-5494-b348-ce375c50306b', '8d7b07eb-7025-5d92-a33d-73107fbb46d4', 'اقرأ النصّ التالي:

«قد يظنّ ظانٌّ أنّ التكنولوجيا قرّبت بين الناس، والحقُّ أنّها قرّبت البعيدَ وأبعدت القريب؛ فكم من أسرةٍ يجلس أفرادها في غرفةٍ واحدة، كلٌّ غارقٌ في شاشته، لا يبادل جليسَه كلمة.»

ما المفارقة (التناقض الظاهريّ) التي يبنيها الكاتب موقفَه عليها؟', '[{"id":"a","text":"التكنولوجيا تَصِل البعيدَ مكانيًّا وتُباعد القريبَ وجدانيًّا في آنٍ واحد"},{"id":"b","text":"التكنولوجيا قرّبت جميعَ الناس بعضهم من بعض دون استثناء"},{"id":"c","text":"أفرادُ الأسرة الواحدة لا يملكون هواتف ذكيّة"},{"id":"d","text":"التكنولوجيا لا أثر لها البتّة في العلاقات الإنسانية"}]'::jsonb, 'a', 'المفارقة جوهرُ موقف الكاتب: «قرّبت البعيدَ وأبعدت القريب»، أي وصلٌ مكانيّ مع قطيعةٍ وجدانيّة، يُجسّدها مثالُ الأسرة الصامتة. أمّا (b) فهو الظنّ الذي يدحضه الكاتب («قد يظنّ ظانٌّ… والحقُّ…»)، و(c) يناقض «غارقٌ في شاشته»، و(d) يناقض إقراره بأثرها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6c604a10-8ef5-5c77-a18e-536e6867a03f', '8d7b07eb-7025-5d92-a33d-73107fbb46d4', 'اقرأ النصّ التالي:

«يا له من زمنٍ غريب! نُكثر فيه من الأصدقاء على الشاشات، ونُقلّ من الأصدقاء في الواقع؛ نملك ألفَ وسيلةٍ للتواصل، ونشكو مع ذلك من وحشةٍ لم تعرفها الأجيالُ السابقة.»

ما النبرة التي يُوظّفها الكاتب، وما القرينة الدالّة عليها؟', '[{"id":"a","text":"نبرةُ تحسّرٍ ونقدٍ ساخرٍ مرّ، يدلّ عليها التعجّب والمقابلة بين الكثرة الظاهرة والوحشة الباطنة"},{"id":"b","text":"نبرةُ فرحٍ واحتفاءٍ بكثرة وسائل التواصل، يدلّ عليها أسلوب التعجّب"},{"id":"c","text":"نبرةُ حيادٍ علميّ موضوعيّ خالٍ من المشاعر"},{"id":"d","text":"نبرةُ دعوةٍ مباشرة إلى ترك وسائل التواصل نهائيًّا"}]'::jsonb, 'a', 'أسلوبُ التعجّب «يا له من زمنٍ غريب!» والمقابلاتُ المتتالية (نُكثر/نُقلّ، ألفُ وسيلة/وحشة) تكشف تحسّرًا ونقدًا ساخرًا مرًّا، لا فرحًا (b) الذي تنقضه «الوحشة» و«غريب». وليست النبرة حياديّة (c) لشحنتها العاطفية، ولا دعوةً صريحة للترك (d) فالنصّ نقدٌ تأمّليّ لا أمرٌ مباشر.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24c447b0-8b0f-5774-94c3-90ca63b738d4', '8d7b07eb-7025-5d92-a33d-73107fbb46d4', 'اقرأ النصّ التالي:

«إنّ مَن يَعُدّ الفنونَ ترفًا زائدًا واهمٌ؛ ذلك أنّ الأمم تُقاس بآثارها الفنّية كما تُقاس بإنجازاتها العلميّة، فحضارةٌ بلا فنٍّ جسدٌ بلا روح.»

ما وظيفة الرابط «ذلك أنّ» في بناء حجاج النصّ؟', '[{"id":"a","text":"يُقدّم تعليلًا يُبرّر الحكم السابق (تخطئة من يعدّ الفنّ ترفًا)"},{"id":"b","text":"يُقدّم استدراكًا يُعارض الحكم السابق"},{"id":"c","text":"يُقدّم مثالًا جزئيًّا لا حجّةً عقليّة"},{"id":"d","text":"يُقدّم نتيجةً نهائيّة تُختم بها الفقرة"}]'::jsonb, 'a', '«ذلك أنّ» رابط تعليلٍ يُسوّغ الحكم المتقدّم (أنّ مَن يعدّ الفنّ ترفًا واهم) بحجّةٍ عقليّة: قياسُ الأمم بآثارها الفنّية. فهو ليس استدراكًا معارِضًا (b)، وما بعده حجّةٌ عقليّة عامّة لا مجرّد مثال (c)، وموقعه في صلب التعليل لا في الختام، فالتشبيه «جسدٌ بلا روح» هو الذي يُجمل النتيجة لا «ذلك أنّ» (d).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f4977c68-caef-59ac-9275-0db26f9c3edc', '8d7b07eb-7025-5d92-a33d-73107fbb46d4', 'رُتّبت جملُ فقرةٍ حجاجيّة ترتيبًا مضطربًا:

(1) فلولا العملُ ما قام عمرانٌ ولا تقدّمت أمّة.
(2) العملُ أساسُ نهضة الأمم وسبيلُها إلى الرقيّ.
(3) ولنا في الدول المتقدّمة خيرُ دليل، إذ بلغت ما بلغته بسواعد أبنائها المكدودة.
(4) ومن ثمّ كان واجبًا على كلّ فردٍ أن يتقن عمله ويُخلص فيه.

ما الترتيب المنطقيّ الأسلم لفقرةٍ متماسكة؟', '[{"id":"a","text":"2 ← 1 ← 3 ← 4"},{"id":"b","text":"1 ← 2 ← 3 ← 4"},{"id":"c","text":"3 ← 2 ← 1 ← 4"},{"id":"d","text":"2 ← 4 ← 1 ← 3"}]'::jsonb, 'a', 'تبدأ الفقرة بالجملة المفتاحية العامّة (2: العمل أساس النهضة)، ثمّ الحجّة العقليّة المعلَّلة (1: فلولا العمل ما قام عمران)، ثمّ المثال الواقعيّ الداعم (3: الدول المتقدّمة دليل)، ثمّ النتيجة المستخلصة (4: ومن ثمّ كان واجبًا…). والروابط ترشد: الفاء التعليليّة في (1)، وضمير «ولنا… دليل» في (3) يستلزم سابقًا، و«ومن ثمّ» في (4) لا يصحّ إلّا خاتمةً.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c9f10d4a-58fa-59b5-9ab0-53476edadd0c', '8d7b07eb-7025-5d92-a33d-73107fbb46d4', 'اقرأ النصّ التالي:

«ابتسم العجوزُ ابتسامةً باهتة وهو ينظر إلى الكرسيّ الفارغ المقابل، ثمّ صبّ فنجانَيْ قهوةٍ كعادته، وجلس يحدّق في الفراغ طويلًا قبل أن يُبعد الفنجان الثاني جانبًا.»

ما الذي يُلمّح إليه النصّ دون تصريح؟', '[{"id":"a","text":"أنّ العجوز يعاني وحدةً وفقدانَ رفيقٍ اعتاد مشاركته القهوة"},{"id":"b","text":"أنّ العجوز ينتظر ضيفًا سيصل بعد قليل"},{"id":"c","text":"أنّ العجوز سعيدٌ بصحبةٍ كثيرة حوله"},{"id":"d","text":"أنّ العجوز لا يحبّ شرب القهوة"}]'::jsonb, 'a', 'القرائن (الكرسيّ الفارغ، صبّ فنجانَيْن «كعادته» ثمّ إبعاد الثاني، التحديق في الفراغ، الابتسامة الباهتة) تتضافر لتُلمّح إلى فقدِ رفيقٍ اعتاد مشاركته القهوة وما خلّفه من وحدة. والانتظار (b) يناقض إبعاده للفنجان، والسعادة بصحبة (c) تناقض «الفراغ» و«الباهتة»، و(d) ينقضه إعداده للقهوة كعادته.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5f151584-537f-598b-acc3-18094cd51066', '8d7b07eb-7025-5d92-a33d-73107fbb46d4', 'اقرأ النصّ التالي:

«غمرتْه السعادةُ حين عاد إلى مسقط رأسه، فقد وجد القريةَ كما تركها: عيونُها لا تزال نديّة، وأهلُها على عهدهم كرماء.»

ما معنى «عيونها» في هذا السياق؟', '[{"id":"a","text":"ينابيعُها وأنهارها (مصادر الماء)"},{"id":"b","text":"أعينُ أهلها الباصرة"},{"id":"c","text":"جواسيسُها ومخبروها"},{"id":"d","text":"أعيانُها ووجهاؤها"}]'::jsonb, 'a', 'للكلمة «عين» معانٍ متعدّدة، والسياق هو الحاسم: وصفُ العيون بأنّها «نديّة» وذكرها في سياق القرية ومائها يحدّد أنّ المراد الينابيع ومصادر الماء. فالباصرة (b) لا تُوصف بـ«نديّة» بهذا المعنى، والجواسيس (c) لا يلائمون سياق الحنين، والأعيان/الوجهاء (d) عُطفوا عليهم «أهلها كرماء» فلا يصحّ تكرارهم.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('927a2f33-fd56-55ea-8670-ca52b5620cd4', '77ace903-23f8-5a38-8bfe-4fbb1b0369fa', 'arabic', '📝 تدريب مراجعة: فهم المقروء والإنتاج الكتابي', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('873faa1d-0154-5f54-8fd4-cf0adb64c0ae', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«ليس الذكاءُ وحده مفتاحَ النجاح، فكم من ذكيٍّ قعد به كسلُه، وكم من متواضعِ الذكاء بلغ القمّةَ بمثابرته. فالمثابرةُ هي السرّ الحقيقيّ.»

ما الفكرة العامة للنصّ؟', '[{"id":"a","text":"المثابرةُ أهمّ من الذكاء وحده في تحقيق النجاح"},{"id":"b","text":"الذكاءُ وحده كافٍ لبلوغ النجاح"},{"id":"c","text":"الكسلُ صفةٌ ملازمةٌ للأذكياء"},{"id":"d","text":"النجاحُ أمرٌ مستحيلٌ على الجميع"}]'::jsonb, 'a', 'يبني الكاتب فكرته على النفي والإثبات: «ليس الذكاء وحده… فالمثابرة هي السرّ»، فالفكرة العامة أنّ المثابرة أهمّ من الذكاء المجرّد (a). أمّا (b) فهو ما ينفيه النصّ صراحةً، و(c) تعميمٌ لم يقصده الكاتب، و(d) يناقض دعوة النصّ للنجاح بالمثابرة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eed55d8d-ef88-572c-bd0c-330279bfeb8a', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«كلّما ازداد الإنسانُ علمًا، ازداد تواضعًا؛ فالعالمُ الحقّ يدرك أنّ ما جهله أكثرُ ممّا علمه.»

ماذا نستنتج عن العلاقة بين العلم والتواضع؟', '[{"id":"a","text":"أنّ العلمَ الحقيقيّ يلازمه التواضعُ لا الغرور"},{"id":"b","text":"أنّ العلمَ يورث صاحبَه الكِبرَ والغرور"},{"id":"c","text":"أنّ التواضعَ صفةُ الجهلاء وحدهم"},{"id":"d","text":"أنّه لا علاقةَ بين العلم والأخلاق"}]'::jsonb, 'a', 'القرائن («كلّما ازداد علمًا ازداد تواضعًا»، «يدرك أنّ ما جهله أكثر») تستلزم بالاستنتاج أنّ العلم الحقّ يلازمه التواضع (a). فالخيار (b) يناقض النصّ صراحةً، و(c) عكسُ ما يقرّره، و(d) ينفي علاقةً يثبتها النصّ بوضوح.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('13b67a9f-04b6-55fa-a7ae-244c4f3cfbd7', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«أمّا البيئةُ فقد عانت طويلًا من جشع الإنسان، حتّى تلوّثت أنهارُها واسودّت سماؤها؛ بيدَ أنّ وعيًا جديدًا بدأ يلوح في الأفق.»

ما العلاقة المنطقية التي يحدثها الرابط «بيدَ أنّ»؟', '[{"id":"a","text":"استدراكٌ يُعارض ما قد يُتوقّع من اليأس بإبراز بارقة أمل"},{"id":"b","text":"تعليلٌ يُبيّن سبب تلوّث الأنهار"},{"id":"c","text":"نتيجةٌ مترتّبة على جشع الإنسان"},{"id":"d","text":"إضافةٌ لمعطًى في الاتّجاه نفسه"}]'::jsonb, 'a', '«بيدَ أنّ» أداة استدراك مرادفة لـ«لكنْ» و«غير أنّ»؛ فهي تُعارض ما قد يُفهم من الجملة الأولى (اليأس من حال البيئة) بإبراز معطًى مضادّ (الوعي الجديد). فليست تعليلًا (b) ولا نتيجة (c)، ولا إضافةً في الاتّجاه نفسه (d) بل تقابلٌ بين سلبٍ وإيجاب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b21430b6-8f91-5146-94fe-92e958a31485', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«يظنّ بعضُهم أنّ المالَ يصنع السعادة، أفرأيتَ غنيًّا تنعّم بالمال وحُرم راحةَ البال؟»

ما دلالة الاستفهام في «أفرأيتَ غنيًّا…؟»', '[{"id":"a","text":"استفهامٌ إنكاريّ يُفنّد زعم أنّ المال يصنع السعادة"},{"id":"b","text":"استفهامٌ حقيقيّ يطلب الكاتبُ به معلومةً يجهلها"},{"id":"c","text":"استفهامٌ للتمنّي"},{"id":"d","text":"استفهامٌ يدلّ على اقتناع الكاتب بأنّ المال يصنع السعادة"}]'::jsonb, 'a', 'الاستفهام هنا إنكاريّ خرج إلى معنى النفي والتفنيد: الكاتب لا يستفهم عن مجهول (b) بل يردّ على من يربط السعادة بالمال مستشهدًا بالغنيّ المحروم من راحة البال. فلا تمنّي فيه (c)، ولا اقتناع بنقيض موقفه (d)؛ والقرينة سياق الردّ على «بعضهم».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('931ce467-7f02-5fda-a7bb-835a5c71fa5b', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«وقف المعلّمُ بين تلاميذه كالأبِ الحاني، يبثّ فيهم العلمَ والقيمَ، ويغرس في نفوسهم حبَّ الوطن.»

ما النبرة المهيمنة على موقف الكاتب من المعلّم؟', '[{"id":"a","text":"نبرةٌ مفعمةٌ بالتقدير والإجلال"},{"id":"b","text":"نبرةٌ ساخرةٌ من دور المعلّم"},{"id":"c","text":"نبرةٌ حياديّةٌ خاليةٌ من العاطفة"},{"id":"d","text":"نبرةُ نقدٍ وإدانة"}]'::jsonb, 'a', 'الألفاظ الموحية («كالأب الحاني»، «يبثّ العلم والقيم»، «يغرس حبّ الوطن») تكشف عاطفة إعجابٍ وتقديرٍ للمعلّم، فالنبرة مفعمةٌ بالتقدير والإجلال (a). فلا سخرية (b)، ولا حياد عاطفيّ مع هذه الصور (c)، ولا نقدٌ ولا إدانة (d).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f1eaa9c5-94d5-5c82-b3db-2e7cab9e4df3', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«التطوّعُ ليس فضلًا يُتكرَّم به، بل واجبٌ إنسانيّ؛ فالمجتمعُ القويّ هو الذي يتكاتف أبناؤه. ألا ترى أنّ الأممَ المتقدّمة تُعلي من شأن العمل التطوّعيّ؟»

ما الأطروحة التي يدافع عنها الكاتب؟', '[{"id":"a","text":"التطوّعُ واجبٌ إنسانيّ يقوم عليه المجتمعُ القويّ المتكاتف"},{"id":"b","text":"التطوّعُ مجرّدُ فضلٍ يتكرّم به القادرون"},{"id":"c","text":"العملُ التطوّعيّ ظاهرةٌ غربيّةٌ لا تناسبنا"},{"id":"d","text":"الأممُ المتقدّمة لا تهتمّ بالتطوّع"}]'::jsonb, 'a', 'يصوغ الكاتب أطروحته بالنفي والإثبات: «ليس فضلًا… بل واجب إنسانيّ»، ويعزّزها بالحجّة (تكاتف المجتمع) والشاهد (الأمم المتقدّمة)، فالأطروحة (a). أمّا (b) فهو الرأي الذي يدحضه، و(c) ادّعاءٌ يناقض استشهاده الإيجابيّ، و(d) عكسُ ما ورد في النصّ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('6ea1b722-dab1-57a4-af05-9275fc58e66c', '77ace903-23f8-5a38-8bfe-4fbb1b0369fa', 'arabic', '👑 تحدّي المناظرة ⭐⭐⭐⭐: فهم المقروء — فكرة واستنتاج ونمط ودلالة', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a454137f-b0f7-56d4-aae7-aec5e5325e83', '6ea1b722-dab1-57a4-af05-9275fc58e66c', 'اقرأ: «القراءةُ غذاءُ العقلِ؛ بها يتّسع فكرُ الإنسانِ وتنمو معارفُه، ومَن هجرها ذبل عقلُه وضاقت آفاقُه». ما الفكرة العامّة للنصّ؟', '[{"id":"a","text":"أهمّية القراءة في تنمية العقل واتّساع الفكر"},{"id":"b","text":"صعوبة القراءة على كثير من الناس"},{"id":"c","text":"أنواع الكتب ومجالاتها"},{"id":"d","text":"فضل الطعام على صحّة الجسم"}]'::jsonb, 'a', 'يدور النصّ كلّه حول أثر القراءة في نموّ العقل واتّساع الفكر (ومقابلُه ذبولُ عقلِ من يهجرها)، فهذه فكرته العامّة. ✓ الخطأ الشائع: التقاط لفظة جزئية («غذاء»، «الطعام») وبناء الفكرة عليها بدل استخلاص المعنى الكلّيّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6586838d-a308-5b05-b657-92ea300ad2be', '6ea1b722-dab1-57a4-af05-9275fc58e66c', 'اقرأ: «لم يكن الطالبُ كسولًا، بل كان يجتهدُ في صمتٍ دون أن يُظهرَ ذلك». قال قارئ: «الطالب كسولٌ». ما الخطأ؟', '[{"id":"a","text":"النصّ ينفي الكسل صراحةً («لم يكن كسولًا») ويُثبت الاجتهاد؛ فالقارئ أهمل أداة النفي"},{"id":"b","text":"لا خطأ، الطالب كسول فعلًا"},{"id":"c","text":"النصّ لم يذكر شيئًا عن اجتهاده"},{"id":"d","text":"النصّ يؤكّد أنّ الطالب يتظاهر بالاجتهاد"}]'::jsonb, 'a', 'بدأ النصّ بأداة النفي «لم يكن كسولًا»، ثمّ أضرب بـ«بل» ليُثبت الاجتهاد في صمت؛ فالفهم الصحيح عكس ما قال القارئ الذي أهمل النفي والإضراب. (تمرين «صيد الخطأ».) الخطأ الشائع: القفز إلى نتيجة تناقض صريح النصّ بإغفال أدوات النفي والاستدراك.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc737dc6-8c28-5285-9bf1-764910158795', '6ea1b722-dab1-57a4-af05-9275fc58e66c', 'اقرأ: «ما زال يبتسمُ للمارّةِ ويوزّع خبزَه على الجائعينَ رغمَ فقرِه». ماذا نستنتج عن هذا الرجل؟', '[{"id":"a","text":"أنّه كريمٌ طيّب القلب رغم حاجته"},{"id":"b","text":"أنّه بخيلٌ يخفي ماله"},{"id":"c","text":"أنّه غنيّ يتباهى بعطائه"},{"id":"d","text":"أنّه حزينٌ نادمٌ على فقره"}]'::jsonb, 'a', 'الابتسامُ للناس وتوزيعُ خبزه على الجائعين «رغم فقره» قرائنُ تدلّ على الكرم وطيبة القلب مع ضيق الحال؛ وهذا استنتاجٌ ضمنيّ لا تصريحيّ. ✓ الخطأ الشائع: مخالفة قرائن النصّ (فالعطاء ينفي البخل، و«رغم فقره» ينفي الغنى).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d4c21a20-540e-5f92-a82e-2de0aaa8723e', '6ea1b722-dab1-57a4-af05-9275fc58e66c', 'اقرأ: «إنّ مَن يعدّ الرياضةَ مضيعةً للوقتِ مخطئٌ؛ فهي تقوّي الجسمَ وتصفّي الذهنَ وتُعلّم روحَ الفريقِ». ما نمط النصّ وغرض الكاتب؟', '[{"id":"a","text":"حجاجيّ ؛ إقناع القارئ بأهمّية الرياضة بالحجج"},{"id":"b","text":"سرديّ ؛ حكاية قصّة رياضيّ"},{"id":"c","text":"وصفيّ ؛ تصوير ملعبٍ رياضيّ"},{"id":"d","text":"تفسيريّ ؛ شرح قواعد لعبة"}]'::jsonb, 'a', 'يعرض الكاتب رأيًا (تخطئة من يستهين بالرياضة) ثمّ يدعمه بحجج (تقوية الجسم، تصفية الذهن، روح الفريق)، فالنمط حجاجيّ وغرضه الإقناع. ✓ الخطأ الشائع: الحكم بالنمط من موضوع النصّ (الرياضة) لا من طريقة عرضه (حجج ورأي).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('628541c0-2a8e-5605-90cb-e10b49ccdc02', '6ea1b722-dab1-57a4-af05-9275fc58e66c', 'اقرأ: «كان الرجلُ جَلْدًا لا تلينُ له قناةٌ أمام الشدائدِ». ما معنى «جَلْدًا» في هذا السياق؟', '[{"id":"a","text":"صبورًا قويًّا صلبًا"},{"id":"b","text":"ضعيفًا سريع الانكسار"},{"id":"c","text":"جاهلًا قليل العلم"},{"id":"d","text":"كسولًا متقاعسًا"}]'::jsonb, 'a', 'قرينة «لا تلين له قناةٌ أمام الشدائد» تدلّ على الصلابة والصبر، فـ«جَلْدًا» هنا معناها قويًّا صبورًا. ✓ الخطأ الشائع: تحديد معنى الكلمة دون الاستعانة بقرائن السياق التي تكشفه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f1b9ad9-f308-5658-9fd3-b026d80e177c', '6ea1b722-dab1-57a4-af05-9275fc58e66c', 'اقرأ: «رحمَ اللهُ زمنًا كانت فيه الكلمةُ عهدًا لا يُخلَف، والجارُ سندًا لا يُخذَل». أيّ قيمةٍ يدعو إليها الكاتب؟', '[{"id":"a","text":"الوفاء بالعهد والتكافل بين الناس"},{"id":"b","text":"حبّ المال وجمعه"},{"id":"c","text":"الاعتزال وترك الناس"},{"id":"d","text":"التفاخر بالأنساب"}]'::jsonb, 'a', 'تحسّرُ الكاتب على زمنٍ كانت فيه الكلمة عهدًا لا يُخلَف والجار سندًا لا يُخذَل دعوةٌ ضمنيّة إلى قيمتَي الوفاء بالعهد والتكافل الاجتماعيّ. ✓ الخطأ الشائع: إغفال المعنى الضمنيّ للحنين (التحسّر على القيمة = الدعوة إليها).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('4804d03e-a906-5c55-b91c-f7e5ea6184a6', '25883c0e-2e60-52b4-ad9e-de3ffce1e9d8', 'arabic', 'سبر تمهيديّ: بنية اختبار العربية', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('130eefd4-7342-5f39-868e-36722389f6a4', '4804d03e-a906-5c55-b91c-f7e5ea6184a6', 'اقرأ النصّ:

«العملُ عمادُ الحياة وسرُّ تقدّم الأمم؛ فبه تُعمَّر الأرض، وتُبنى المصانع، وتُصان كرامةُ الإنسان عن ذلّ السؤال. وما تأخّرت أمّةٌ إلّا حين ركن أبناؤها إلى الكسل.»

ما الفكرة العامة للنصّ؟', '[{"id":"a","text":"العملُ أساسُ عمران الحياة وتقدّم الأمم وصونِ كرامة الإنسان"},{"id":"b","text":"العاملُ يكسب قوته كلّ يوم"},{"id":"c","text":"المصانعُ تُبنى بسواعد العمّال"},{"id":"d","text":"الكسلُ صفةٌ ذميمة في بعض الناس"}]'::jsonb, 'a', 'الفكرة العامة جملةٌ جامعة تلمّ شتات النصّ: تمجيدُ العمل بوصفه عماد الحياة وسبب التقدّم وصون الكرامة، وهو ما يصوغه (a). أمّا (b) و(c) فتفصيلان جزئيّان وردا في سطر، و(d) إشارةٌ عابرة في الخاتمة لا محور النصّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('66fc77f0-edac-50ef-9df9-ebac33a09a29', '4804d03e-a906-5c55-b91c-f7e5ea6184a6', 'اقرأ النصّ:

«أثبتت المرأةُ التونسيّة جدارتها في كلّ ميدان؛ فهي الطبيبةُ والمهندسةُ والمعلّمةُ، وهي ركيزةُ الأسرة وعمادُ المجتمع.»

ما نمط هذا النصّ؟', '[{"id":"a","text":"حجاجيّ: يدافع عن أطروحة جدارة المرأة بالحجج"},{"id":"b","text":"سرديّ: يحكي أحداثًا متسلسلة"},{"id":"c","text":"وصفيّ: يرسم صورةً حسّية لمشهد"},{"id":"d","text":"تفسيريّ: يشرح ظاهرةً علميّة بالأرقام"}]'::jsonb, 'a', 'النصّ يطرح أطروحةً («أثبتت المرأة جدارتها») ويدعمها بأدلّةٍ (الطبيبة، المهندسة، المعلّمة) ليُقنع القارئ؛ وهذا هو النمط الحجاجيّ. فلا أحداث متسلسلة (b)، ولا تكديس نعوتٍ لمشهد حسّيّ (c)، ولا شرح ظاهرةٍ بالأرقام (d).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('72218b38-01d2-5165-9d7b-ea4599a32855', '4804d03e-a906-5c55-b91c-f7e5ea6184a6', 'اقرأ النصّ:

«جاء الربيعُ، فاخضرّت الحقولُ، وتفتّحت الأزهارُ.»

ما إعراب كلمة «الربيعُ»؟', '[{"id":"a","text":"فاعل مرفوع وعلامة رفعه الضمّة"},{"id":"b","text":"مفعول به منصوب بالفتحة"},{"id":"c","text":"مبتدأ مرفوع بالضمّة"},{"id":"d","text":"مضاف إليه مجرور بالكسرة"}]'::jsonb, 'a', '«الربيعُ» هو مَن وقع منه فعلُ المجيء «جاء»، فهو فاعل مرفوع وعلامة رفعه الضمّة الظاهرة. وليس مفعولًا به (b) لأنّ الفعل لازم لم يقع على شيء، وليس مبتدأ (c) لأنّ الجملة فعليّة بدأت بفعل، وليس مضافًا إليه (d) إذ لم يسبقه مضاف.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cbbe2f0d-c671-5175-8384-8aad7fdece97', '4804d03e-a906-5c55-b91c-f7e5ea6184a6', 'اقرأ النصّ:

«إنّ الفنونَ غذاءُ الروح؛ فالموسيقى تُهذّب الوجدان، والرسمُ يصقل الذوق، والشعرُ يُرهف الإحساس.»

ما اسم «إنّ» في الجملة وما حكمه؟', '[{"id":"a","text":"«الفنونَ» اسم إنّ منصوب وعلامة نصبه الفتحة"},{"id":"b","text":"«الفنونَ» خبر إنّ مرفوع بالضمّة"},{"id":"c","text":"«غذاءُ» اسم إنّ مرفوع بالضمّة"},{"id":"d","text":"«الفنونَ» فاعل مرفوع بالضمّة"}]'::jsonb, 'a', '«إنّ» من الحروف الناسخة، تنصب الاسم وترفع الخبر. فـ«الفنونَ» اسمها منصوب بالفتحة، و«غذاءُ» خبرها مرفوع بالضمّة. فـ(b) و(c) عكسا الموقعين، و(d) أخطأ إذ لا فاعل بعد الحرف الناسخ بل اسمٌ منصوب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d5406c3-70a6-5ffc-867b-509ea0fd6604', '4804d03e-a906-5c55-b91c-f7e5ea6184a6', 'اقرأ النصّ:

«المهندسُ النبيهُ يرسم خرائطَ دقيقةً قبل أن يشيّد بنيانًا متينًا.»

ما نوع كلمة «النبيهُ» من حيث الاشتقاق؟', '[{"id":"a","text":"صفة مشبّهة باسم الفاعل تدلّ على ثبوت الصفة"},{"id":"b","text":"اسم مفعول يدلّ على من وقع عليه الفعل"},{"id":"c","text":"اسم تفضيل يدلّ على المفاضلة"},{"id":"d","text":"اسم مكان يدلّ على موضع الحدث"}]'::jsonb, 'a', '«النبيه» على وزن «فعيل» من فعلٍ لازم (نَبُهَ)، يدلّ على صفةٍ ثابتةٍ لازمة في صاحبها، فهو صفة مشبّهة باسم الفاعل. وليس اسم مفعول (b) إذ لم يقع عليه الحدث، ولا اسم تفضيل (c) إذ لا مفاضلة بين شيئين، ولا اسم مكان (d).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6d4da5fa-aeaf-5c4c-aa04-44894bac7c45', '4804d03e-a906-5c55-b91c-f7e5ea6184a6', 'اقرأ النصّ:

«تتسارع التحوّلاتُ التكنولوجيّة، غير أنّ كثيرًا من الناس لا يُجارونها.»

ما العلاقة التي يُحدثها الرابط «غير أنّ»؟', '[{"id":"a","text":"استدراكٌ يُعارض ما قد يُتوقّع من الجملة الأولى"},{"id":"b","text":"تعليلٌ يُبيّن سبب تسارع التحوّلات"},{"id":"c","text":"نتيجةٌ مترتّبة على التسارع"},{"id":"d","text":"إضافةٌ لمعلومةٍ في الاتّجاه نفسه"}]'::jsonb, 'a', '«غير أنّ» أداةُ استدراكٍ مرادفةٌ لـ«لكنْ»؛ فبعد إثبات تسارع التحوّلات تستدرك بعجز الناس عن مجاراتها، محدثةً تقابلًا. وليست تعليلًا كـ«لأنّ» (b)، ولا نتيجةً كـ«لذلك» (c)، ولا إضافةً كـ«كذلك» (d).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d188d592-d3bf-5f91-98bf-23decf5ef7e9', '4804d03e-a906-5c55-b91c-f7e5ea6184a6', 'اقرأ النصّ:

«التفاعلُ بين الثقافات إثراءٌ متبادل: تأخذ كلُّ ثقافةٍ من غيرها وتُعطيها، فتنمو الإنسانيّةُ جمعاء.»

طُلب منك تحرير فقرةٍ تدافع فيها عن هذه الأطروحة. أيّ الجمل التالية أصلحُ لتكون حجّةً (لا مثالًا)؟', '[{"id":"a","text":"الانفتاحُ على الآخر يُغني المعرفة الإنسانيّة لأنّ تلاقح الأفكار يولّد الإبداع"},{"id":"b","text":"فقد نقل العربُ علومَ اليونان وطوّروها ثمّ نقلتها أوروبا عنهم"},{"id":"c","text":"تأمّل كيف انتشرت المأكولاتُ الآسيويّة في مدن العالم كلّها"},{"id":"d","text":"ها هو متحفُ اللوفر يجمع تحفًا من كلّ الحضارات"}]'::jsonb, 'a', 'الحجّة فكرةٌ عقليّة عامّة تُبرّر الموقف، وهذا ما في (a): مبدأٌ عامّ معلَّلٌ بأنّ تلاقح الأفكار يولّد الإبداع. أمّا (b) و(c) و(d) فوقائعُ جزئيّة محسوسة (نقل العرب علوم اليونان، انتشار المأكولات، متحف اللوفر)، وهذه أمثلةٌ تخدم الحجّة لا حججٌ بذاتها.', 7)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7237357-2f5a-5693-bc6b-3bbf53849cea', '4804d03e-a906-5c55-b91c-f7e5ea6184a6', 'اقرأ النصّ:

«تُهدّد التغيّراتُ المناخيّةُ مستقبلَ الكوكب؛ فارتفاعُ الحرارة يُذيب الجليد ويرفع منسوبَ البحار.»

بعد أن دافعتَ عن خطورة هذه الظاهرة، أيّ الخواتم أنسبُ لإنتاجٍ متماسك؟', '[{"id":"a","text":"وهكذا يتبيّن أنّ حماية المناخ مسؤوليّةٌ جماعيّة، فهل نتحرّك قبل فوات الأوان؟"},{"id":"b","text":"وتجدر الإشارة إلى أنّ التلوّث الصناعيّ موضوعٌ آخر يستحقّ بحثًا مستقلًّا"},{"id":"c","text":"إنّ التغيّراتِ المناخيّةَ تُهدّد مستقبلَ الكوكب كما قلنا في البداية تمامًا"},{"id":"d","text":"وفي الختام أحبّ أن أشكر معلّمي الذي علّمني الكتابة"}]'::jsonb, 'a', 'الخاتمة المتماسكة تُلخّص الموقف ثمّ تفتح أفقًا أو تطرح سؤالًا، وهذا ما في (a): خلاصةٌ (المسؤوليّة الجماعيّة) + أفقٌ تحفيزيّ. أمّا (b) فيُقحم فكرةً جديدةً خارجة عن الموضوع، و(c) تكرارٌ حرفيّ للمقدّمة بلا إضافة، و(d) عبارةٌ شخصيّة لا صلة لها بالموضوع.', 8)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('4469d441-7ab5-56df-8609-421f6996bf16', '25883c0e-2e60-52b4-ad9e-de3ffce1e9d8', 'arabic', 'سبر تطبيقيّ: نصّ «العمل والكرامة»', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d70ada72-63e7-5a55-a227-26e432a9b817', '4469d441-7ab5-56df-8609-421f6996bf16', 'اقرأ النصّ:

«ما أجملَ أن يكدح المرءُ بيده فيأكل من كدّ يمينه! فالعملُ يصون الكرامةَ ويغرس في النفس عزّةً لا يعرفها العاطل. لقد رأيتُ حرفيًّا بسيطًا يرفض الإحسانَ ويقول: يدي تكفيني. غير أنّ بعض الناس يحتقرون المهنَ اليدويّة ظلمًا، وما دروا أنّ بها قِوامَ المجتمع.»

ما الفكرة العامة للنصّ؟', '[{"id":"a","text":"العملُ مصدرٌ للكرامة والعزّة، واحتقارُ المهن اليدويّة ظلمٌ لها"},{"id":"b","text":"الحرفيُّ البسيط رفض الإحسان مرّةً واحدة"},{"id":"c","text":"بعضُ الناس يحتقرون المهن اليدويّة"},{"id":"d","text":"المرءُ يأكل من كدّ يمينه كلّ يوم"}]'::jsonb, 'a', 'الفكرة العامة جملةٌ جامعة تضمّ موضوع النصّ وموقف الكاتب: تمجيدُ العمل بوصفه مصدر كرامةٍ وعزّة، وإدانةُ احتقار المهن اليدويّة، وهو ما يصوغه (a). أمّا (b) فمثالٌ جزئيّ، و(c) فكرةٌ جزئيّة وردت في الخاتمة، و(d) تفصيلٌ تمهيديّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9704c8f4-b1d3-576d-a53b-d7d089c653ff', '4469d441-7ab5-56df-8609-421f6996bf16', 'اقرأ النصّ:

«ما أجملَ أن يكدح المرءُ بيده فيأكل من كدّ يمينه! فالعملُ يصون الكرامةَ ويغرس في النفس عزّةً لا يعرفها العاطل. لقد رأيتُ حرفيًّا بسيطًا يرفض الإحسانَ ويقول: يدي تكفيني. غير أنّ بعض الناس يحتقرون المهنَ اليدويّة ظلمًا، وما دروا أنّ بها قِوامَ المجتمع.»

ما النبرة الغالبة على موقف الكاتب من العمل؟', '[{"id":"a","text":"إعجابٌ بالعمل وتثمينٌ له مع استنكارٍ لاحتقار المهن"},{"id":"b","text":"سخريةٌ من العمّال وأصحاب الحرف"},{"id":"c","text":"حيادٌ تامّ لا موقف فيه"},{"id":"d","text":"حزنٌ وأسًى على ضياع العمل"}]'::jsonb, 'a', 'قرائنُ النصّ تكشف النبرة: التعجّبُ الإعجابيّ «ما أجملَ»، وألفاظُ المدح «يصون الكرامة، يغرس عزّة»، ثمّ الاستنكارُ «يحتقرون ظلمًا». فالنبرة إعجابٌ بالعمل واستنكارٌ لاحتقاره (a). فلا سخرية من العمّال (b)، ولا حياد (c) إذ الموقف واضح، ولا حزن على ضياعٍ لم يُذكر (d).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7bcff282-d7f8-54b0-b0be-c872ab3c752a', '4469d441-7ab5-56df-8609-421f6996bf16', 'اقرأ النصّ:

«ما أجملَ أن يكدح المرءُ بيده فيأكل من كدّ يمينه! فالعملُ يصون الكرامةَ ويغرس في النفس عزّةً لا يعرفها العاطل. لقد رأيتُ حرفيًّا بسيطًا يرفض الإحسانَ ويقول: يدي تكفيني. غير أنّ بعض الناس يحتقرون المهنَ اليدويّة ظلمًا، وما دروا أنّ بها قِوامَ المجتمع.»

ما إعراب كلمة «الكرامةَ» في قوله: «يصون الكرامةَ»؟', '[{"id":"a","text":"مفعول به منصوب وعلامة نصبه الفتحة"},{"id":"b","text":"فاعل مرفوع وعلامة رفعه الضمّة"},{"id":"c","text":"مبتدأ مرفوع بالضمّة"},{"id":"d","text":"مضاف إليه مجرور بالكسرة"}]'::jsonb, 'a', '«الكرامةَ» وقع عليها فعلُ الصون، والفاعل هو «العمل»، فهي مفعول به منصوب وعلامة نصبه الفتحة الظاهرة. وليست فاعلًا (b) فالفاعل سبقها، ولا مبتدأ (c) فالجملة فعليّة، ولا مضافًا إليه (d) إذ لم يسبقها مضاف.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d98ffab6-c3af-520a-b0fe-45997e7aa17f', '4469d441-7ab5-56df-8609-421f6996bf16', 'اقرأ النصّ:

«ما أجملَ أن يكدح المرءُ بيده فيأكل من كدّ يمينه! فالعملُ يصون الكرامةَ ويغرس في النفس عزّةً لا يعرفها العاطل. لقد رأيتُ حرفيًّا بسيطًا يرفض الإحسانَ ويقول: يدي تكفيني. غير أنّ بعض الناس يحتقرون المهنَ اليدويّة ظلمًا، وما دروا أنّ بها قِوامَ المجتمع.»

ما نوع كلمة «العاطل» من حيث الاشتقاق؟', '[{"id":"a","text":"اسم فاعل من الفعل «عَطَلَ» على وزن فاعِل"},{"id":"b","text":"اسم مفعول على وزن مَفعول"},{"id":"c","text":"اسم تفضيل على وزن أَفعَل"},{"id":"d","text":"مصدر صريح"}]'::jsonb, 'a', '«العاطل» على وزن «فاعِل»، يدلّ على من قام بالحدث (اتّصف بالعَطالة/البطالة)، فهو اسم فاعل. وليس اسم مفعول (b) فلا يدلّ على من وقع عليه الفعل، ولا اسم تفضيل (c) إذ ليس على وزن «أفعل» ولا مفاضلة فيه، ولا مصدرًا (d) فهو وصفٌ لذاتٍ لا حدثٌ مجرّد.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c113425c-4057-5109-aec5-1f8b1d8a7267', '4469d441-7ab5-56df-8609-421f6996bf16', 'اقرأ النصّ:

«ما أجملَ أن يكدح المرءُ بيده فيأكل من كدّ يمينه! فالعملُ يصون الكرامةَ ويغرس في النفس عزّةً لا يعرفها العاطل. لقد رأيتُ حرفيًّا بسيطًا يرفض الإحسانَ ويقول: يدي تكفيني. غير أنّ بعض الناس يحتقرون المهنَ اليدويّة ظلمًا، وما دروا أنّ بها قِوامَ المجتمع.»

ما الغرض البلاغيّ من أسلوب التعجّب في «ما أجملَ أن يكدح المرءُ بيده!»؟', '[{"id":"a","text":"إظهارُ الإعجاب بقيمة العمل اليدويّ وتعظيمُها"},{"id":"b","text":"الاستفهامُ عن جمال الكدح والسؤال عنه"},{"id":"c","text":"النهيُ عن العمل اليدويّ والتحذيرُ منه"},{"id":"d","text":"التمنّي بحدوث أمرٍ مستحيل"}]'::jsonb, 'a', '«ما أجملَ…» صيغةُ تعجّبٍ قياسيّة (ما + أفعَل + المتعجَّب منه)، غرضُها البلاغيّ إظهارُ الإعجاب بقيمة العمل وتعظيمها. وليست استفهامًا (b) فلا أداة استفهام، ولا نهيًا (c) فهي تمدح لا تزجر، ولا تمنّيًا لمستحيل (d) فالكدح أمرٌ ممكنٌ واقع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de398e68-3464-5534-9fe5-a80a67ce51f0', '4469d441-7ab5-56df-8609-421f6996bf16', 'اقرأ النصّ:

«ما أجملَ أن يكدح المرءُ بيده فيأكل من كدّ يمينه! فالعملُ يصون الكرامةَ ويغرس في النفس عزّةً لا يعرفها العاطل. لقد رأيتُ حرفيًّا بسيطًا يرفض الإحسانَ ويقول: يدي تكفيني. غير أنّ بعض الناس يحتقرون المهنَ اليدويّة ظلمًا، وما دروا أنّ بها قِوامَ المجتمع.»

طُلب منك تحرير فقرةٍ تدافع فيها عن قيمة العمل. أيّ الجمل التالية أصلحُ لتكون أطروحةً واضحة؟', '[{"id":"a","text":"العملُ أساسُ كرامة الإنسان وعمادُ نهضة المجتمعات"},{"id":"b","text":"هل العملُ مفيدٌ للإنسان أم لا؟"},{"id":"c","text":"رأيتُ ذات يومٍ نجّارًا يصنع بابًا جميلًا"},{"id":"d","text":"العملُ شيءٌ موجودٌ في كلّ مكان من العالم"}]'::jsonb, 'a', 'الأطروحة موقفٌ خبريٌّ واضحٌ حاسمٌ قابلٌ للبرهنة، وهذا ما في (a): حُكمٌ صريح يقبل الدفاع بالحجج. أمّا (b) فسؤالٌ لا أطروحة، و(c) مثالٌ جزئيّ محسوس يصلح للبرهنة لا للطرح، و(d) عبارةٌ مبهمةٌ خاليةٌ من الموقف لا تقبل الدفاع عنها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

