  ('718b8183-470f-54a1-9091-3bcbbcb0951d', '25883c0e-2e60-52b4-ad9e-de3ffce1e9d8', 'arabic', '⚔️ زعيم الفصل: سبر نصّ «شواغل العصر»', 3, 120, 30, 'boss', 'admin', 2)
